  let chunkId = this.getChunkIdentifier(new Position(x, y, z));
  let chunk = this.__loadedMinimapChunks[chunkId];
  if (!chunk || !chunk.view) return null;

  let localX = ((x % 128) + 128) % 128;
  let localY = ((y % 128) + 128) % 128;
  let val = chunk.view[localX + localY * 128];

  return {
    r: val & 0xFF,
    g: (val >> 8) & 0xFF,
    b: (val >> 16) & 0xFF,
    a: (val >> 24) & 0xFF
  };

