  // Set some state
  this.__tickInterval = 0;
  this.serverVersion = null;

  // Load item definitions (keyed by SID) and build CID-keyed reverse lookup
  this.itemDefinitions = {};
  this.itemDefinitionsByCid = {};
  fetch("/play/definitions.json?v=" + Date.now()).then(response => {
    return response.json();
  }).then(data => {
    this.itemDefinitions = data;
    this.itemDefinitionsByCid = {};
    this.itemDefinitionsBySid = {};
    Object.keys(data).forEach(function(sid) {
      let cid = data[sid].id;
      if (cid) {
        this.itemDefinitionsByCid[cid] = data[sid];
      }
      this.itemDefinitionsBySid[sid] = data[sid];
    }.bind(this));
  });

  document.getElementById("client-version").innerHTML = this.CLIENT_VERSION;

