GameClient.prototype.__setTickInterval = function (tick) {

  /*
   * Function GameClient.__setTickInterval
   * Sets the gameserver tick interval which is used to synchronize server and client events
   */

  this.__tickInterval = tick;

}

GameClient.prototype.__startBackgroundTicker = function () {

  /*
   * Function GameClient.__startBackgroundTicker
   * Spawns a Web Worker that fires a 'tick' message every 200 ms.
   * Workers aren't throttled when the tab is in the background, so this
   * keeps the eventQueue draining at ~5 Hz even when rAF is throttled
   * to 1 Hz. The handler runs a minimal logic tick only when rAF has
   * clearly stalled (gap > 250 ms — foreground rAF is ~16 ms, throttled
   * is ≥1000 ms), so foreground rendering at 60 fps is unaffected.
   *
   * Cadence note: 200 ms is a tradeoff between background animation
   * smoothness and foreground postMessage overhead. At 50 ms the
   * worker dispatched 20×/sec — measurable on low-end mobile (~0.5%
   * CPU) for ~zero benefit in foreground (gap always <100 ms). 200 ms
   * cuts overhead 4× while still draining the eventQueue fast enough
   * to avoid burst-on-return artifacts when the tab regains focus.
   *
   * Skips renderer + input handlers in the fallback tick: there's no
   * point drawing while hidden, and no input is arriving from a
   * background tab. Only the eventQueue + soundManager get ticked,
   * which is what avoids the burst-on-return effect.
   *
   * Tracks `__lastLogicTick` separately from GameLoop's FPS-pacing
   * timestamp. GameLoop.__lastFrameTime is unset in VSync mode (FPS=0,
   * the default for VSync setting) — using it as the gap source would
   * make the worker fire spuriously in foreground vsync. Updating it
   * from both rAF (__loop) and worker keeps the gap measurement
   * accurate across all FPS modes.
   */

  if (this.__bgTickWorker) {
    this.__bgTickWorker.terminate();
  }

  let workerCode = "setInterval(function(){postMessage(0)},200);";
  let blob = new Blob([workerCode], { "type": "application/javascript" });
  this.__bgTickWorker = new Worker(URL.createObjectURL(blob));

  let self = this;
  this.__bgTickWorker.onmessage = function () {
    if (!self.gameLoop || !self.gameLoop.isRunning()) return;
    let now = performance.now();
    let lastTick = self.__lastLogicTick || 0;
    if (now - lastTick <= 250) return;
    self.__lastLogicTick = now;
    self.eventQueue.tick();
    self.interface.soundManager.tick();
  };

}

GameClient.prototype.__loop = function () {

  /*
   * Function GameClient.__loop
   * Main body of the internal game loop
   */

  // Stamp last logic tick so __startBackgroundTicker's worker can
  // detect rAF stalls (background throttling) and fall back to a
  // worker-driven tick. Updated here regardless of FPS mode.
  this.__lastLogicTick = performance.now();

  // Increment the frame counter and execute all scheduled events
  this.eventQueue.tick();

  // Increment sound as well
  this.interface.soundManager.tick();

  // Read the keyboard input
  this.keyboard.handleInput();

  // Read gamepad input
  if (this.gamepad && this.gamepad.isConnected()) {
    this.gamepad.handleInput();
  }

  // Read the touch joystick input (frame-synced for smooth movement)
  if (this.touch && this.touch.isMobileMode) {
    this.touch.handleInput();
  }

  // Request to render the frame
  this.renderer.render();

}


