"use strict";

const Spellbook = function (spells) {

  /*
   * Class Spellbook
   * Container for the player spells
   */

  // The list of spell identifiers (sid) that are available
  if (spells && Array.isArray(spells.availableSpells)) {
    this.spells = new Set(spells.availableSpells);
  } else if (Array.isArray(spells)) {
    this.spells = new Set(spells);
  } else {
    this.spells = new Set();
  }

  // List of all abilities on cooldown
  this.cooldowns = new Map();

  // Create the spellbook
  gameClient.interface.modalManager.get("hotbar-add-modal").createSpellList(this.spells);
  gameClient.interface.hotbarManager.__loadConfiguration();
  gameClient.interface.hotbarManager.updateAllKeyLabels();

}

// Bucket-scoped global cooldowns. Server sends each as a SpellCastPacket
// with id = bucket ID. Client just stores them in cooldowns Map under the
// id; rendering picks the appropriate one per slot's spell type.
Spellbook.prototype.GLOBAL_COOLDOWN = 0xFFFF;        // attack bucket
Spellbook.prototype.GLOBAL_COOLDOWN_HEAL = 0xFFFE;   // heal bucket
Spellbook.prototype.GLOBAL_COOLDOWN_DURATION = 20;

// Mirrors `aggressive: true` flags in data/760/spells/definitions.json so
// the client can pick the right cooldown bucket per spell. Direct-damage
// spells only — conjure spells (which create attack runes) are utility on
// the server and live in the heal bucket too. Keep in sync with server defs.
Spellbook.prototype.__ATTACK_SPELL_IDS = new Set([
  6,   // Force Strike       (exori mort)
  13,  // Energy Strike      (exori vis)
  14,  // Flame Strike       (exori flam)
  15,  // Fire Wave          (exevo flam hur)
  16,  // Energy Beam        (exevo vis lux)
  20,  // Great Energy Beam  (exevo gran vis lux)
  21,  // Energy Wave        (exevo mas vis)
  22,  // Ultimate Explosion (exevo gran mas vis)
  23,  // Berserk            (exori)
  29,  // Challenge          (exeta res)
  30,  // Poison Storm       (exevo gran mas pox)
]);

Spellbook.prototype.__bucketFor = function (sid) {
  return this.__ATTACK_SPELL_IDS.has(sid) ? this.GLOBAL_COOLDOWN : this.GLOBAL_COOLDOWN_HEAL;
}

Spellbook.prototype.addSpell = function (sid) {

  /*
   * Function Spellbook.addSpell
   * Adds a spell to the players spellbook
   */

  this.spells.add(sid);
  gameClient.interface.modalManager.get("hotbar-add-modal").createSpellList(this.spells);

}

Spellbook.prototype.removeSpell = function (sid) {

  /*
   * Function Spellbook.addSpell
   * Removes a spell from the players spellbook
   */

  // Delete the spell and update the spell list
  this.spells.delete(sid);
  gameClient.interface.modalManager.get("hotbar-add-modal").createSpellList(this.spells);

}

Spellbook.prototype.castSpell = function (sid) {

  /*
   * Function Spellbook.castSpell
   * Function to cast a spell from the spellbook
   */

  // The spell is still on cooldown — gate against the bucket this spell
  // belongs to (attack bucket for damage spells, heal bucket for everything
  // else) plus the per-spell cooldown.
  let bucket = this.__bucketFor(sid);
  if (this.cooldowns.has(bucket) || this.cooldowns.has(sid)) {
    return this.__cooldownCallback();
  }

  gameClient.send(new SpellCastPacket(sid));

}

Spellbook.prototype.serverCastSpell = function (packet) {

  /*
   * Function Spellbook.serverCastSpell
   * Handles messages from the server to lock a spell
   */

  this.__lockSpell(packet.id, packet.cooldown);

}

Spellbook.prototype.getCooldownSeconds = function (sid) {

  let bucket = this.__bucketFor(sid);
  let gcdf = this.cooldowns.has(bucket) ? this.cooldowns.get(bucket).remainingSeconds() : 0;

  if (!this.cooldowns.has(sid)) {
    return gcdf;
  }

  return Math.max(gcdf, this.cooldowns.get(sid).remainingSeconds());

}

Spellbook.prototype.getCooldownFraction = function (sid) {

  /*
   * Function Spellbook.getCooldownFraction
   * Returns the cooldown of a speed with a particular identifier
   */

  // Bucket-scoped global cooldown — heal spells dim only when the heal
  // bucket is locked, attack spells only when the attack bucket is locked.
  let bucket = this.__bucketFor(sid);
  let gcdf = this.cooldowns.has(bucket) ? (1 - this.cooldowns.get(bucket).remainingFraction()) : 1;

  // Spell is not on cooldown: show the global cooldown time
  if (!this.cooldowns.has(sid)) {
    return gcdf;
  }

  // Return the minimum
  return Math.min(gcdf, 1 - this.cooldowns.get(sid).remainingFraction());

}

Spellbook.prototype.__cooldownCallback = function () {

  /*
   * Function Spellbook.__cooldownCallback
   * Callback fired when a spell is cast that is still on cooldown
   * Provides reject haptic feedback (triple-buzz) on mobile
   */

  gameClient.player.blockHit();
  gameClient.interface.setCancelMessage("You cannot cast this spell yet.");

  // Reject haptic feedback for cooldown
  if (navigator.vibrate) navigator.vibrate([20, 20, 20, 20, 20]);

}

Spellbook.prototype.__lockSpell = function (id, time) {

  /*
   * Function Spellbook.__lockSpell
   * Handles messages from the server to lock a spell. Server now sends
   * separate packets for the per-spell sid AND the bucket cooldown
   * (0xFFFF = attack, 0xFFFE = heal), so we just lock whichever id
   * arrived. No auto-set of GLOBAL_COOLDOWN — would over-lock the
   * heal bucket on attack spell casts.
   */

  this.cooldowns.set(id, gameClient.eventQueue.addEvent(this.__unlockSpell.bind(this, id), time));

}

Spellbook.prototype.__unlockSpell = function (id) {

  /*
   * Function Spellbook.__unlockSpell
   * Unlocks a spell from the spellbook, allowing it to be cast again
   */

  this.cooldowns.delete(id);

}


