    this.__gamepadIndex = null;
    console.log("[GAMEPAD] Disconnected: " + event.gamepad.id);
    // === STREAMING-WALK BEGIN ===
    // If the player was streaming-walking via the gamepad and it pulls
    // out mid-stride, the server keeps walking them forever. Tell server
    // to stop. Idempotent — no-op if streaming wasn't active.
    if (typeof gameClient !== "undefined" && gameClient && gameClient.keyboard &&
        typeof gameClient.keyboard.__sendStreamingWalk === "function") {
      gameClient.keyboard.__sendStreamingWalk(null);
    }
    // === STREAMING-WALK END ===
