  9, 13, 16, 17, 27,       // Tab, Enter, Shift, Ctrl, Escape
  37, 38, 39, 40,           // Arrow keys
  33, 34, 35, 36,           // Numpad diagonals (PageUp/Down, End, Home)
  65, 68, 83, 87            // WASD
