// Standard CRC32 (IEEE 802.3 polynomial 0xEDB88320) — table-driven.
// Used by the frame-CRC probe so the client can cross-reference the
// plaintext CRC stamped server-side in frame-crc.log when an unknown
// opcode lands. Mismatch = compression layer corrupted the bytes.
const __CRC_TABLE = (function () {
  let t = new Uint32Array(256);
  for (let i = 0; i < 256; i++) {
    let c = i;
    for (let j = 0; j < 8; j++) c = (c & 1) ? (0xEDB88320 ^ (c >>> 1)) : (c >>> 1);
    t[i] = c;
  }
  return t;
})();
function __crc32Bytes(bytes) {
  let c = 0xFFFFFFFF;
  for (let i = 0; i < bytes.length; i++) c = __CRC_TABLE[(c ^ bytes[i]) & 0xFF] ^ (c >>> 8);
  return (c ^ 0xFFFFFFFF) >>> 0;
}

const NetworkManager = function () {

  /*
   * Class NetworkManager
   * Handles networking over the websocket
   */

  // Internal class state
  this.state = new State();
  this.state.add("bytesRecv", null);
  this.state.add("bytesSent", null);
  this.state.add("latency", null);
  this.state.add("nPackets", null);
  this.state.add("connected", null);

  // Frame-CRC probe state — captured at WS-message-receive time so the
  // unknown-opcode handler can include the frame-level CRC in its log
  // line for cross-reference against frame-crc.log on the server.
  this.__lastFrameCRC = 0;
  this.__lastFrameSize = 0;

  this.nPacketsSent = 0;

  // Reconnection state
  this.__wasConnected = false;
  this.__intentionalClose = false;

  // Character selection state for reconnect
  this.__lastCharacterName = null;
  this.__sessionToken = null;
  this.__lastHost = null;

  // Web Lock release function — held while connected to prevent mobile browsers from freezing the tab
  this.__releaseWakeLock = null;

  // Track when tab was hidden for zombie socket detection
  this.__hiddenAt = 0;

  // Guard against parallel reconnect attempts
  this.__reconnecting = false;

  // Long-disconnect hard-reload threshold. When a reconnect attempt
  // happens more than RELOAD_AFTER_MS after the original disconnect,
  // we force a full page reload before reconnecting — this catches
  // the server-save scenario where stale cached client JS would
  // otherwise miss new packet opcodes and desync. Brief network blips
  // (well under this threshold) keep the fast in-memory reconnect.
  this.__disconnectStartTime = 0;
  this.__RELOAD_AFTER_MS = 180000;  // 3 minutes — covers server saves comfortably

  // Silent auto-retry on unexpected disconnect: fire the reconnect
  // immediately and chain up to N background attempts before surfacing
  // the "Connection lost." modal. Most WiFi/server blips recover after
  // 1-2 attempts so the user never sees a modal; a small cancel-message
  // confirms the recovery instead. Counter resets on success and on any
  // intentional close.
  this.__silentRetryInFlight = false;
  this.__silentRetryCount = 0;
  this.__silentRetryMax = 3;   // total attempts (initial + 2 retries)
  this.__silentRetryTimer = null;
  // Legacy field kept for server-error / old paths that still clear it —
  // no longer used to gate the modal, counter-based now.
  this.__pendingModalTimer = null;

  // Periodic heartbeat via Web Worker (not throttled in background tabs)
  this.__heartbeatWorker = null;
  this.__heartbeatTimeout = null;
  this.__lastServerPacket = 0;
  // Half-open WebSocket detection — if the outbound pipe dies (NAT
  // mapping aged out, carrier drop) but the inbound still delivers
  // server-pushed packets, __lastServerPacket keeps refreshing and the
  // 20s incoming check never trips. We separately track unanswered
  // LATENCY pings so we notice when the server stops echoing them.
  this.__pendingPings = 0;

  // Auto-reconnect when page becomes visible again (mobile browsers kill WebSockets on minimize)
  document.addEventListener("visibilitychange", this.__handleVisibilityChange.bind(this));

  // iOS Safari fires `pagehide`/`pageshow` more reliably than visibilitychange
  // during aggressive app-switch suspend and bfcache freeze/restore. Listen
  // for them in parallel so we notice background transitions iOS hides from
  // visibilitychange. persisted=true on pageshow means the page was restored
  // from bfcache — WebSocket is almost certainly dead, reconnect immediately.
  window.addEventListener("pagehide", this.__handlePageHide.bind(this));
  window.addEventListener("pageshow", this.__handlePageShow.bind(this));

  // Network connectivity events — catches airplane mode, tunnel, WiFi drop
  // much faster than the 15s heartbeat timeout. On `online`, if the socket
  // isn't OPEN we reconnect immediately instead of waiting for the next tick.
  window.addEventListener("online", this.__handleOnline.bind(this));
  window.addEventListener("offline", this.__handleOffline.bind(this));

  // Queue for packets received while the tab is hidden (browser throttles game loop)
  this.__packetQueue = [];
  this.__tabHidden = false;

  // The handler for all incoming packets
  this.packetHandler = new PacketHandler();

}

NetworkManager.prototype.close = function () {

  /*
   * Function NetworkManager.close
   * Intentionally closes the socket to the gameserver (no auto-reconnect)
   */

  this.__intentionalClose = true;

  // Cancel any pending silent retry — the player is logging out on
  // purpose, they shouldn't see a reconnect UI a second later.
  if (this.__silentRetryTimer) {
    clearTimeout(this.__silentRetryTimer);
    this.__silentRetryTimer = null;
  }
  if (this.__pendingModalTimer) {
    clearTimeout(this.__pendingModalTimer);
    this.__pendingModalTimer = null;
  }
  this.__silentRetryInFlight = false;
  this.__silentRetryCount = 0;
  this.__clearReconnectingIndicator();

  return this.socket.close();

}

NetworkManager.prototype.isConnected = function () {

  /*
   * Class NetworkManager.isConnected
   * Returns true if the network manager is connected to the gameserver
   */

  return this.state.connected;

}

NetworkManager.prototype.readPacket = function (packet) {

  /*
   * Class NetworkManager.readPacket
   * Reads a packet received from the gameserver
   */

  this.state.nPackets++;
  // Phase 1 desync probe: per-connection inbound opcode count. Bumped
  // for every opcode INCLUDING SEQ_CHECK itself, so when the SEQ_CHECK
  // handler runs the count equals what the server sees right after
  // queuing the SEQ_CHECK packet.
  if (this.__inboundPacketCount === undefined) this.__inboundPacketCount = 0;
  this.__inboundPacketCount++;

  // Capture the opcode so the default case can report the ACTUAL unrecognized
  // byte (not buffer[0], which is always the first opcode of the message).
  let opcode = packet.readUInt8();
  let opcodeOffset = packet.index - 1;

  // What operation the server sends is the first byte
  switch (opcode) {

    case CONST.PROTOCOL.SERVER.SPELL_ADD: {
      let sid = packet.readUInt16();
      let mana = packet.readUInt16();
      let level = packet.readUInt8();
      return gameClient.interface.updateSpells(sid, mana, level);
    }

    case CONST.PROTOCOL.SERVER.PLAYER_STATISTICS: {
      return this.packetHandler.handlePlayerStatistics(packet.readCharacterStatistics());
    }

    // NPC trade offers are received
    case CONST.PROTOCOL.SERVER.TRADE_OFFER: {
      return this.packetHandler.handleTradeOffer(packet.readTradeOffer());
    }

    // NPC travel destinations are received
    case CONST.PROTOCOL.SERVER.TRAVEL_OFFER: {
      return this.packetHandler.handleTravelOffer(packet.readTravelOffer());
    }

    // Friend list operations
    case CONST.PROTOCOL.SERVER.FRIEND_ADD: {
      return this.packetHandler.handleAddFriend(packet.readFriend());
    }

    case CONST.PROTOCOL.SERVER.FRIEND_REMOVE: {
      return this.packetHandler.handleRemoveFriend(packet.readString());
    }

    case CONST.PROTOCOL.SERVER.FRIEND_STATUS: {
      return this.packetHandler.handleFriendStatus(packet.readFriend());
    }

    case CONST.PROTOCOL.SERVER.ITEM_TRANSFORM: {
      return this.packetHandler.handleTransformTile(packet.readTransformTile());
    }

    case CONST.PROTOCOL.SERVER.ITEM_REPLACE: {
      return this.packetHandler.handleItemReplace(packet.readItemReplace());
    }

    case CONST.PROTOCOL.SERVER.MESSAGE_CANCEL: {
      return this.packetHandler.handleCancelMessage(packet.readString());
    }

    case CONST.PROTOCOL.SERVER.ITEM_INFORMATION: {
      return this.packetHandler.handleItemInformation(packet.readItemInformation());
    }

    case CONST.PROTOCOL.SERVER.TARGET: {
      return this.packetHandler.handleSetTarget(packet.readUInt32());
    }

    case CONST.PROTOCOL.SERVER.FOLLOW_TARGET: {
      return this.packetHandler.handleSetFollowTarget(packet.readUInt32());
    }

    case CONST.PROTOCOL.SERVER.OUTFIT: {
      return this.packetHandler.handleChangeOutfit(packet.readChangeOutfit());
    }

    case CONST.PROTOCOL.SERVER.ITEM_TEXT: {
      return this.packetHandler.handleReadText(packet.readReadable());
    }

    case CONST.PROTOCOL.SERVER.STATE_SERVER: {
      return this.packetHandler.handleServerData(packet);
    }

    case CONST.PROTOCOL.SERVER.CHANNEL_JOIN: {
      return this.packetHandler.handleOpenChannel(packet.readOpenChannel());
    }

    case CONST.PROTOCOL.SERVER.COMBAT_LOCK: {
      return this.packetHandler.handleCombatLock(packet.readBoolean());
    }

    case CONST.PROTOCOL.SERVER.MAGIC_EFFECT: {
      return this.packetHandler.handleSendMagicEffect(packet.readMagicEffect());
    }

    case CONST.PROTOCOL.SERVER.DISTANCE_EFFECT: {
      return this.packetHandler.handleSendDistanceEffect(packet.readDistanceEffect());
    }

    case CONST.PROTOCOL.SERVER.CONTAINER_REMOVE: {
      return this.packetHandler.handleContainerItemRemove(packet.readContainerItemRemove());
    }

    case CONST.PROTOCOL.SERVER.CREATURE_STATE: {
      return this.packetHandler.handleEntityReference(packet.readCreatureInfo());
    }

    case CONST.PROTOCOL.SERVER.CREATURE_INFORMATION: {
      return this.packetHandler.handleCharacterInformation(packet.readCharacterInformation());
    }

    case CONST.PROTOCOL.SERVER.CONTAINER_CLOSE: {
      return this.packetHandler.handleContainerClose(packet.readUInt32());
    }

    case CONST.PROTOCOL.SERVER.LATENCY: {
      return this.packetHandler.handleLatency();
    }

    case CONST.PROTOCOL.SERVER.CREATURE_MOVE: {
      return this.packetHandler.handleCreatureServerMove(packet.readEntityMove());
    }

    case CONST.PROTOCOL.SERVER.CANCEL_WALK: {
      packet.readUInt8(); // reserved byte
      let cancelPosition = packet.readPosition();
      return this.packetHandler.handleCancelWalk(cancelPosition);
    }

    case CONST.PROTOCOL.SERVER.ITEM_ADD: {
      return this.packetHandler.handleItemAdd(packet.readTileItemAdd());
    }

    case CONST.PROTOCOL.SERVER.CONTAINER_OPEN: {
      return this.packetHandler.handleContainerOpen(packet.readOpenContainer());
    }

    case CONST.PROTOCOL.SERVER.CONTAINER_ADD: {
      return this.packetHandler.handleContainerAddItem(packet.readContainerItemAdd());
    }

    case CONST.PROTOCOL.SERVER.STATE_PLAYER: {
      return this.packetHandler.handleAcceptLogin(packet.readPlayerInfo());
    }

    case CONST.PROTOCOL.SERVER.ITEM_REMOVE: {
      return this.packetHandler.handleRemoveItem(packet.readRemoveItem());
    }

    case CONST.PROTOCOL.SERVER.SPELL_CAST: {
      // Always drain the packet first — even if the player isn't ready, the
      // bytes need to be consumed or the next opcode reads at the wrong
      // offset and triggers protocol desync.
      let cast = packet.readCastSpell();
      if (gameClient.player && gameClient.player.spellbook) {
        gameClient.player.spellbook.serverCastSpell(cast);
      }
      return;
    }

    case CONST.PROTOCOL.SERVER.USE_GLOBAL_COOLDOWN: {
      let p = packet.readUseGlobalCooldown();
      let hm = gameClient.interface && gameClient.interface.hotbarManager;
      if (hm && typeof hm.setRuneGlobalCooldown === "function") {
        hm.setRuneGlobalCooldown(p.durationMs, p.bucket);
      }
      return;
    }

    case CONST.PROTOCOL.SERVER.FLUID_GLOBAL_COOLDOWN: {
      let p = packet.readFluidGlobalCooldown();
      let hm = gameClient.interface && gameClient.interface.hotbarManager;
      if (hm && typeof hm.setFluidGlobalCooldown === "function") {
        hm.setFluidGlobalCooldown(p.durationMs);
      }
      return;
    }

    case CONST.PROTOCOL.SERVER.SEQ_CHECK: {
      // Server tells us how many packets it has shipped (counter is per-
      // socket, includes this SEQ_CHECK). Compare against our inbound
      // count and ship a [seq-gap] debug line on mismatch — server
      // routes those into sequence-gaps.log.
      let serverCount = packet.readUInt32();
      let clientCount = this.__inboundPacketCount || 0;
      let delta = serverCount - clientCount;
      // Only log when the gap GROWS — a steady state of N missing
      // packets shouldn't spam every probe interval. When delta increases,
      // that means new packets were missed since the last probe.
      if (this.__lastSeqDelta === undefined) this.__lastSeqDelta = 0;
      if (delta > this.__lastSeqDelta) {
        let newlyMissed = delta - this.__lastSeqDelta;
        this.__lastSeqDelta = delta;
        try {
          gameClient.sendDebug("[seq-gap] server=" + serverCount
            + " client=" + clientCount
            + " missing=" + delta
            + " new=" + newlyMissed);
        } catch (e) {}

        // Force a silent reconnect on big bursts. Small drips (1-6) are
        // routine packet loss and the existing self-heal absorbs them;
        // a 20+ burst means the wire ate something structural — a stair
        // teleport, a chunk transition, etc. — and the player will be
        // visibly stuck (Rastajelen 2026-05-03 stair-down freeze, 29
        // packets missing in one window). Reconnect re-serializes the
        // world cleanly. Mirrors the existing protocol-desync close at
        // line ~633. Per-socket throttle so we don't ping-pong if the
        // same gap keeps re-firing.
        if (delta >= 20 && !this.__seqForceReconnected) {
          this.__seqForceReconnected = true;
          try {
            gameClient.sendDebug("[seq-gap] force-reconnect missing=" + delta);
          } catch (e) {}
          if (this.socket && this.socket.readyState === WebSocket.OPEN) {
            this.socket.close(4001, "seq-gap-burst");
          }
        }
      }
      return;
    }

    case CONST.PROTOCOL.SERVER.CHUNK: {
      return this.packetHandler.handleChunk(packet.readChunkData());
    }

    case CONST.PROTOCOL.SERVER.MAP_AREA: {
      return this.packetHandler.handleMapArea(packet.readMapArea());
    }

    case CONST.PROTOCOL.SERVER.MAP_SLICE_NORTH: {
      return this.packetHandler.handleMapSlice(0, packet.readMapSlice());
    }

    case CONST.PROTOCOL.SERVER.MAP_SLICE_EAST: {
      return this.packetHandler.handleMapSlice(1, packet.readMapSlice());
    }

    case CONST.PROTOCOL.SERVER.MAP_SLICE_SOUTH: {
      return this.packetHandler.handleMapSlice(2, packet.readMapSlice());
    }

    case CONST.PROTOCOL.SERVER.MAP_SLICE_WEST: {
      return this.packetHandler.handleMapSlice(3, packet.readMapSlice());
    }

    case CONST.PROTOCOL.SERVER.SERVER_ERROR: {
      return this.packetHandler.handleServerError(packet.readString());
    }

    case CONST.PROTOCOL.SERVER.MESSAGE_SERVER: {
      let color = packet.readUInt8();
      let priority = packet.readUInt8();
      return this.packetHandler.handleServerMessage(packet.readString(), color, priority);
    }

    case CONST.PROTOCOL.SERVER.CREATURE_REMOVE: {
      return this.packetHandler.handleEntityRemove(packet.readUInt32());
    }

    case CONST.PROTOCOL.SERVER.CREATURE_TELEPORT: {
      return this.packetHandler.handleEntityTeleport(packet.readCreatureTeleport());
    }

    case CONST.PROTOCOL.SERVER.MESSAGE_PRIVATE: {
      return this.packetHandler.handleReceivePrivateMessage(packet.readPrivateMessage());
    }

    case CONST.PROTOCOL.SERVER.PLAYER_LOGIN: {
      return this.packetHandler.handlePlayerConnect(packet.readString());
    }

    case CONST.PROTOCOL.SERVER.PLAYER_LOGOUT: {
      return this.packetHandler.handlePlayerDisconnect(packet.readString());
    }

    case CONST.PROTOCOL.SERVER.WORLD_TIME: {
      return this.packetHandler.handleWorldTime(packet.readUInt32());
    }

    case CONST.PROTOCOL.SERVER.CREATURE_MESSAGE: {
      return this.packetHandler.handleChannelMessage(packet.readChannelMessage());
    }

    case CONST.PROTOCOL.SERVER.TOGGLE_CONDITION: {
      return this.packetHandler.handleCondition(packet.readToggleCondition());
    }

    case CONST.PROTOCOL.SERVER.EMOTE: {
      return this.packetHandler.handleEmote(packet.readDefaultMessage());
    }

    case CONST.PROTOCOL.SERVER.CREATURE_SAY: {
      return this.packetHandler.handleDefaultMessage(packet.readDefaultMessage());
    }

    case CONST.PROTOCOL.SERVER.CREATURE_PROPERTY: {
      return this.packetHandler.handlePropertyChange(packet.readProperty());
    }

    case CONST.PROTOCOL.SERVER.FOOD_TIMER: {
      // Read remaining seconds and update skill window
      let remainingSeconds = packet.readUInt32();
      gameClient.interface.windowManager.getWindow("skill-window").setFoodTimer(remainingSeconds);
      return;
    }

    case CONST.PROTOCOL.SERVER.TRADE_OFFER: {
      return this.packetHandler.handleTradeOffer(packet.readTradeOffer());
    }

    case CONST.PROTOCOL.SERVER.TRADE_GOLD_UPDATE: {
      return this.packetHandler.handleTradeGoldUpdate(packet.readUInt32());
    }

    case CONST.PROTOCOL.SERVER.TRADE_FEEDBACK: {
      return this.packetHandler.handleTradeFeedback(packet.readString());
    }

    case CONST.PROTOCOL.SERVER.QUEST_LOG: {
      return this.packetHandler.handleQuestLog(packet.readQuestLog());
    }

    case CONST.PROTOCOL.SERVER.QUEST_LINE: {
      return this.packetHandler.handleQuestLine(packet.readQuestLine());
    }

    case 40: {
      // Magic byte 0xDE confirms this is a real DeathPacket and not a
      // misaligned-read of byte 40 from upstream wire desync. Drop the
      // packet (and log) if the magic doesn't match — see protocol.js
      // DeathPacket comment.
      let deathMagic = packet.readUInt8();
      if (deathMagic !== 0xDE) {
        if (gameClient && gameClient.sendDebug) {
          gameClient.sendDebug("[death-magic-mismatch] got=" + deathMagic);
        }
        return;
      }
      return this.packetHandler.handleDeath();
    }

    case CONST.PROTOCOL.SERVER.WEATHER: {
      return this.packetHandler.handleWeather(packet.readWeather());
    }

    case CONST.PROTOCOL.SERVER.SKULL_UPDATE: {
      return this.packetHandler.handleSkullUpdate(packet.readSkullUpdate());
    }

    case CONST.PROTOCOL.SERVER.SHIELD_UPDATE: {
      return this.packetHandler.handleShieldUpdate(packet.readShieldUpdate());
    }

    case CONST.PROTOCOL.SERVER.PARTY_INVITE: {
      return this.packetHandler.handlePartyInvite(packet.readPartyInvite());
    }

    // Player-to-player safe trade
    case CONST.PROTOCOL.SERVER.PLAYER_TRADE_OPEN: {
      return this.packetHandler.handlePlayerTradeOpen(packet.readPlayerTradeOpen());
    }

    case CONST.PROTOCOL.SERVER.PLAYER_TRADE_ITEM: {
      return this.packetHandler.handlePlayerTradeItem(packet.readPlayerTradeItem());
    }

    case CONST.PROTOCOL.SERVER.PLAYER_TRADE_CLOSE: {
      return this.packetHandler.handlePlayerTradeClose();
    }

    case CONST.PROTOCOL.SERVER.HOTBAR_ITEM_COUNT: {
      let itemId = packet.readUInt16();
      let fluidType = packet.readUInt8();
      let count = packet.readUInt16();
      return gameClient.interface.hotbarManager.updateItemCount(itemId, fluidType, count);
    }

    case CONST.PROTOCOL.SERVER.TUTORIAL_MARKERS: {
      let count = packet.readUInt8();
      let markers = [];
      for (let i = 0; i < count; i++) {
        markers.push(packet.readPosition());
      }
      return this.packetHandler.handleTutorialMarkers(markers);
    }

    case CONST.PROTOCOL.SERVER.SHOP_OFFER: {
      return this.packetHandler.handleShopOffer(packet.readShopOffer());
    }

    case CONST.PROTOCOL.SERVER.SHOP_POINT_UPDATE: {
      return this.packetHandler.handleShopPointUpdate(packet.readUInt32());
    }

    case CONST.PROTOCOL.SERVER.PARTY_INFO: {
      let info = packet.readPartyInfo();
      if (info) {
        let mgr = gameClient.interface.modalManager;
        let existing = mgr.get("party-info-modal");
        // Refresh in place if the modal is already open (avoids flash on kick)
        if (mgr.isOpened() && mgr.__openedModal === existing) {
          existing.handleOpen(info);
        } else {
          mgr.open("party-info-modal", info);
        }
      }
      return;
    }

    case CONST.PROTOCOL.SERVER.TASK_INFO: {
      let info = packet.readTaskInfo();
      if (info) {
        let mgr = gameClient.interface.modalManager;
        let existing = mgr.get("task-info-modal");
        if (mgr.isOpened() && mgr.__openedModal === existing) {
          existing.handleOpen(info);
        } else {
          mgr.open("task-info-modal", info);
        }
      }
      return;
    }

    case CONST.PROTOCOL.SERVER.HUNT_INFO: {
      let info = packet.readHuntInfo();
      if (info) {
        let mgr = gameClient.interface.modalManager;
        let existing = mgr.get("hunt-info-modal");
        if (mgr.isOpened() && mgr.__openedModal === existing) {
          existing.handleOpen(info);
        } else {
          mgr.open("hunt-info-modal", info);
        }
      }
      return;
    }

    case CONST.PROTOCOL.SERVER.LOOT_LIST_INFO: {
      let info = packet.readLootListInfo();
      if (info) {
        let mgr = gameClient.interface.modalManager;
        let existing = mgr.get("lootlist-modal");
        if (mgr.isOpened() && mgr.__openedModal === existing) {
          existing.handleOpen(info);
        } else {
          mgr.open("lootlist-modal", info);
        }
      }
      return;
    }

    case CONST.PROTOCOL.SERVER.HOUSE_INFO: {
      let info = packet.readHouseInfo();
      if (info) {
        let mgr = gameClient.interface.modalManager;
        let existing = mgr.get("house-info-modal");
        // Refresh in place if the modal is already open (avoids the
        // close/re-open flash on every edit action).
        if (mgr.isOpened() && mgr.__openedModal === existing) {
          existing.handleOpen(info);
        } else {
          mgr.open("house-info-modal", info);
        }
      }
      return;
    }

    case CONST.PROTOCOL.SERVER.CONFIRM_DIALOG: {
      let data = packet.readConfirmDialog();
      let modal = gameClient.interface.modalManager.open("confirm-modal", function () {
        gameClient.send(new ConfirmActionPacket(data.actionId));
      });
      if (modal) {
        modal.setTitle(data.title);
        modal.element.querySelector(".modal-body > div").innerHTML = data.message;
      }
      return;
    }

    case CONST.PROTOCOL.SERVER.SERVER_DISCONNECT: {
      this.__intentionalClose = true;
      // Same as the manual close(): cancel any pending auto-retry —
      // the server is telling us to stay down.
      if (this.__silentRetryTimer) {
        clearTimeout(this.__silentRetryTimer);
        this.__silentRetryTimer = null;
      }
      if (this.__pendingModalTimer) {
        clearTimeout(this.__pendingModalTimer);
        this.__pendingModalTimer = null;
      }
      this.__silentRetryInFlight = false;
      this.__silentRetryCount = 0;
      return;
    }

    default:
      // Dump a window of bytes around the bad opcode so the server log shows
      // what preceded it — the packet before the misaligned byte is usually
      // the under-writer. buffer[0] used to be logged by mistake (always the
      // first opcode of the WebSocket message); keep it around as "msgStart"
      // so we still know which packet kicked off this message.
      let ctxStart = Math.max(0, opcodeOffset - 8);
      let ctxEnd = Math.min(packet.buffer.length, opcodeOffset + 8);
      let ctxBytes = [];
      for (let i = ctxStart; i < ctxEnd; i++) {
        ctxBytes.push(packet.buffer[i].toString(16).padStart(2, "0"));
      }
      console.warn("Unknown server packet opcode: 0x" + opcode.toString(16) + " at offset " + opcodeOffset);
      gameClient.sendDebug("[unknown opcode] 0x" + opcode.toString(16)
        + " at offset=" + opcodeOffset
        + " msgStart=0x" + packet.buffer[0].toString(16)
        + " frameSize=" + this.__lastFrameSize
        + " frameCRC=" + this.__lastFrameCRC.toString(16).padStart(8, "0")
        + " ctx=[" + ctxBytes.join(" ") + "]");
      // Stream is desynced for THIS WS frame — bail the parse loop so we
      // don't chew through misaligned bytes and fire bogus events (false
      // death modal, ghost containers, phantom self-heals — Magic Level
      // 16:42:35). __desyncDetected stops the outer __processPacketData
      // loop. The next WS frame is a fresh boundary with no alignment
      // baggage; we resume parsing it cleanly.
      //
      // Trade-off (deliberate, see commit notes): we no longer
      // socket.close(4000) on every desync. Force-reconnect was making
      // every misaligned frame a 1006 disconnect (33 unknown-opcode
      // events ≈ 33 of last night's 1006s). With DEDICATED_COMPRESSOR_3KB
      // catching most corruption upstream, the residual cases are rare
      // enough that "stay in-game with possibly stale state" beats
      // "force reconnect every time." Risk: if a corrupted packet was
      // carrying a death event or container update, the client missed
      // it silently — heartbeat / self-heal / next chunk-request usually
      // catches it within seconds. Worth it.
      this.__desyncDetected = true;
      return;

  }

}

NetworkManager.prototype.send = function (packet) {

  /*
   * Function NetworkManager.send
   * Writes a packet to the gameserver
   */

  // Not connected to the gameserver
  if (!this.isConnected()) {
    return;
  }

  buffer = packet.getBuffer();

  // Save some state
  this.state.bytesSent += buffer.length;
  this.nPacketsSent++;

  // Just write the buffer over the websocket
  this.socket.send(buffer);

}

NetworkManager.prototype.getLatency = function () {

  /*
   * Function NetworkManager.pingServer
   * Pings the game server with a stay-alive message
   */

  // Save the ping timing and write the packet. __pendingPings rises by
  // one per send and is zeroed by handleLatency on pong receipt — the
  // heartbeat tick uses it to detect a half-open outbound pipe.
  this.__latency = performance.now();
  this.__pendingPings++;

  this.send(new LatencyPacket());

}

NetworkManager.prototype.getConnectionString = function (response) {

  /*
   * Function NetworkManager.getConnectionString
   * Returns the connection string from the protocol, host, and port
   */

  return "%s?token=%s".format(response.host, response.token);

}

NetworkManager.prototype.getConnectionSettings = function () {

  /*
   * Function NetworkManager.getConnectionSettings
   * Returns the configured connection settings from the DOM
   */

  return document.getElementById("host").value;

}

NetworkManager.prototype.createAccount = function (options) {

  /*
   * Function NetworkManager.createAccount
   * Creates a new account and auto-logs in on success
   */

  let self = this;

  // Make a post request with JSON body
  fetch("/api/login/create", {
    "method": "POST",
    "headers": { "Content-Type": "application/json" },
    "body": JSON.stringify({ "account": options.account, "password": options.password, "name": options.name, "sex": options.sex, "referral": options.referral || "" })
  }).then(function (response) {

    switch (response.status) {
      case 201: break;
      case 400:
        return response.json().then(function (data) {
          throw (data.error || "Malformed account creation request.");
        }).catch(function (e) {
          if (typeof e === "string") throw e;
          throw ("Malformed account creation request.");
        });
      case 409: throw ("An account or character with this name already exists.");
      case 429: throw ("Too many requests. Please try again later.");
      case 500: throw ("The server experienced an internal error.");
    }

    // Fill in the login fields with the new credentials
    document.getElementById("user-username").value = options.account;
    document.getElementById("user-password").value = options.password;

    // Show "Logging in..." on the same modal, then auto-login
    gameClient.interface.modalManager.open("floater-connecting", "Account created! Logging in...");
    self.connect();

  }).catch(function (x) {
    // Reset the create account button and show error inline
    let confirmBtn = document.querySelector("#floater-create button[action='confirm']");
    if (confirmBtn) {
      confirmBtn.disabled = false;
      confirmBtn.textContent = "Create Account";
    }
    let errorEl = document.getElementById("create-error");
    if (errorEl) {
      errorEl.textContent = x;
      errorEl.style.display = "block";
    }
  });

}

NetworkManager.prototype.fetchCallback = function (response) {

  /*
   * Function NetworkManager.fetchCallback
   * Callback to fire for fetch requests: check HTTP Status Code
   */

  if (response.status !== 200) {
    return Promise.reject(response);
  }

  return Promise.resolve(response.arrayBuffer());

}

NetworkManager.prototype.loadGameFilesServer = function () {

  /*
   * Function NetworkManager.loadGameFilesServer
   * Downloads Tibia.spr and Tibia.dat from the server with progress tracking
   */

  let resources = ["Tibia.spr", "Tibia.dat"];
  let totalBytes = 0;
  let loadedBytes = [0, 0];
  let launcher = window.__launcherUI;

  function updateProgress() {
    if (!launcher || totalBytes === 0) return;
    let loaded = loadedBytes[0] + loadedBytes[1];
    let percent = Math.round((loaded / totalBytes) * 100);
    launcher.setProgress(percent);
    let mb = (loaded / 1024 / 1024).toFixed(1);
    let totalMb = (totalBytes / 1024 / 1024).toFixed(1);
    launcher.setStatus("Downloading: " + mb + " / " + totalMb + " MB");
  }

  function fetchWithProgress(url, index) {
    // cache: 'reload' forces a fresh fetch from the server, ignoring any
    // cached HTTP response. Without this, the browser may serve a stale
    // Tibia.dat / Tibia.spr from its HTTP cache even after we've wiped
    // the localStorage flags + IndexedDB on an asset-version change.
    return fetch("/data/%s/%s?v=%s".format(gameClient.SERVER_VERSION, url, ASSET_VERSION), { cache: "reload" }).then(function(response) {
      if (response.status !== 200) {
        throw new Error("Failed to load " + url);
      }

      // X-Uncompressed-Length (set by the server for gzip responses) is the
      // raw byte count we'll see at the reader level after the browser
      // auto-decompresses. Without it, Content-Length is the compressed
      // size and the progress total will be much smaller than what we
      // actually receive — UI shows "20.0 / 0.2 MB" mid-download.
      let uncompressed = response.headers.get("X-Uncompressed-Length");
      let contentLength = response.headers.get("Content-Length");
      if (uncompressed) {
        totalBytes += parseInt(uncompressed);
      } else if (contentLength) {
        totalBytes += parseInt(contentLength);
      }

      // If we can stream the response, track progress. Gate on either
      // header — uncompressed for gzipped responses, content-length for
      // raw — so disabling gzip in the future doesn't silently fall back
      // to the no-progress arrayBuffer() path.
      if (response.body && (uncompressed || contentLength)) {
        let reader = response.body.getReader();
        let chunks = [];

        return (function read() {
          return reader.read().then(function(result) {
            if (result.done) {
              let blob = new Blob(chunks);
              return blob.arrayBuffer();
            }
            chunks.push(result.value);
            loadedBytes[index] += result.value.length;
            updateProgress();
            return read();
          });
        })();
      }

      // Fallback: no streaming support
      return response.arrayBuffer();
    });
  }

  if (launcher) {
    launcher.setLabel("Downloading Assets...");
    launcher.setStatus("Starting download...");
    launcher.setProgress(0);
  }

  let promises = resources.map(function(url, index) {
    return fetchWithProgress(url, index);
  });

  Promise.all(promises).then(function ([dataSprites, dataObjects]) {

    if (launcher) {
      launcher.setStatus("Processing assets...");
      launcher.setProgress(100);
    }

    // Load the sprites and data objects
    gameClient.spriteBuffer.load("Tibia.spr", { "target": { "result": dataSprites } });
    gameClient.dataObjects.load("Tibia.dat", { "target": { "result": dataObjects } });

  }).catch(function (error) {
    if (launcher) {
      launcher.dismiss();
    }
    return gameClient.interface.modalManager.open("floater-connecting", "Failed loading client data from server. Please select them manually using the Load Assets button.");
  });

}

NetworkManager.prototype.connect = function () {

  /*
   * Function NetworkManager.connect
   * Connects to the login server to get a character list and session token
   */

  // Reset state from any previous session so login is not blocked
  this.__intentionalClose = false;
  this.__wasConnected = false;

  let { account, password } = gameClient.interface.getAccountDetails();

  // Contact the login server
  fetch("/api/login", {
    "method": "POST",
    "headers": { "Content-Type": "application/json" },
    "body": JSON.stringify({ "account": account, "password": password })
  }).then(function (response) {

    if (response.status === 200) {
      return response.json();
    }

    if (response.status === 401) {
      return response.json().catch(function() { return {}; }).then(function(data) {
        throw new AuthenticationError(data.error || "The account name or password is incorrect.");
      });
    }

    if (response.status === 403) {
      return response.json().catch(function() { return {}; }).then(function(data) {
        if (data && data.error) {
          // Real server-issued 403 — message is from our login server
          // (typically "Your account is banished[ until ...]").
          throw new AuthenticationError(data.error);
        }
        // 403 with no JSON error = not from our server. Almost always
        // Cloudflare / WAF / Bot Fight Mode returning a challenge or
        // block page (HTML body). Don't claim "banished" when the
        // server didn't actually say so — that's a misleading dead-end
        // for users who aren't actually banned.
        throw new AuthenticationError(
          "Login was blocked by the security layer (HTTP 403). " +
          "Your account is not banned. Try a different network, " +
          "clear your browser cache, or contact support."
        );
      });
    }

    if (response.status === 429) {
      throw new AuthenticationError("Too many login attempts. Please wait a minute and try again.");
    }

    if (response.status === 500) {
      throw new ServerError("The server experienced an internal error.");
    }

    if (response.status === 503) {
      throw new ServerError("Login server is temporarily unavailable. Please try again in a moment.");
    }

    throw new Error("Login failed: unexpected server response (HTTP " + response.status + ").");

  }).then(function (response) {

    // Two-phase login: store session token and open character selection
    this.__sessionToken = response.sessionToken;
    this.__lastHost = response.host;

    gameClient.interface.modalManager.open("character-select-modal", {
      "characters": response.characters,
      "premiumUntil": response.premiumUntil || null,
      "sessionToken": response.sessionToken,
      "host": response.host,
      "hasEmail": response.hasEmail
    });

  }.bind(this)).catch(x => gameClient.interface.modalManager.open("floater-connecting", x)).finally(function() {
    let loginBtn = document.getElementById("enter-game");
    if (loginBtn) { loginBtn.disabled = false; loginBtn.textContent = "Login"; }
  });

}

NetworkManager.prototype.connectWithToken = function (token, host) {

  /*
   * Function NetworkManager.connectWithToken
   * Opens a WebSocket connection using a pre-obtained HMAC token
   */

  // Detach callbacks from any previous socket to prevent stale close/error events
  // from corrupting the state of the new connection
  if (this.socket) {
    this.socket.onopen = null;
    this.socket.onmessage = null;
    this.socket.onclose = null;
    this.socket.onerror = null;
    try { this.socket.close(); } catch (e) {}
  }

  let connectionString = "%s?token=%s".format(host, token);

  // Pass mobile flag so the server can tailor tutorial hints
  let isMobile = gameClient.touch && gameClient.touch.isMobileMode;
  if (isMobile) {
    connectionString += "&mobile=1";
  }

  // Pass device type (desktop, mobile, tablet) for analytics
  let deviceType = "desktop";
  if (isMobile) {
    deviceType = document.body.classList.contains("force-tablet") ? "tablet" : "mobile";
  }
  connectionString += "&device=" + deviceType;

  // Wire format version. Bump this constant on both sides any time
  // writeOutfit / readOutfit / a fixed-size packet layout changes.
  // Server rejects the upgrade with a "please refresh" message if the
  // numbers don't match — prevents the parser-misalign cascade we saw
  // when a stale tab kept running pre-bump JS after a wire format
  // change deploy. Sent as ?w= so it parses cheaply without bumping
  // any opcode.
  let wireVersion = (typeof CONST !== "undefined" && CONST.WIRE_FORMAT_VERSION) || 0;
  connectionString += "&w=" + wireVersion;

  // Open the websocket connection: binary transfer of data
  this.socket = new WebSocket(connectionString);
  this.socket.binaryType = "arraybuffer";

  // Attach callbacks
  this.socket.onopen = this.__handleConnection.bind(this);
  this.socket.onmessage = this.__handlePacket.bind(this);
  this.socket.onclose = this.__handleClose.bind(this);
  this.socket.onerror = this.__handleError.bind(this);

}

NetworkManager.prototype.selectCharacter = function (sessionToken, characterName, host) {

  /*
   * Function NetworkManager.selectCharacter
   * Sends the selected character to the login server to get an HMAC token
   */

  fetch("/api/login/select-character", {
    "method": "POST",
    "headers": { "Content-Type": "application/json" },
    "body": JSON.stringify({ "sessionToken": sessionToken, "characterName": characterName })
  }).then(function (response) {

    // 451 NAMELOCK — character needs a rename (GM namelock or a used
    // name-change scroll set the pending flag). Fires the auto-redirect
    // to /rename.html?oldName=X&reason=Y, then throws a modal message
    // containing a live <a> tag as a fallback. TextModal uses innerHTML
    // for x.message, so the link renders; if the browser blocks the
    // auto-nav (extension, popup policy, etc.) the user can still click
    // through manually. The Back button in the modal footer also stays
    // available via isError path.
    if (response.status === 451) {
      // rename.html lives on the website process (port 3000 by default),
      // NOT on this Python client-server (port 8000), so a bare
      // "/rename.html" stays on the wrong origin and 404s. Precedence for
      // the base URL:
      //   1. body.renameBaseUrl   — supplied by login-server when the
      //      operator sets WEBSITE.EXTERNAL_URL in config (works for
      //      reverse-proxied / subpathed deployments too)
      //   2. same host + :3000    — default assumption for the two-port
      //      dev setup (also works for most straight IP:port deployments)
      //   3. same-origin fallback — last resort; will 404 if the website
      //      isn't actually on this origin, but the fallback link in the
      //      thrown error message lets the user correct the URL manually
      let buildBase = function (renameBaseUrl) {
        if (renameBaseUrl) return String(renameBaseUrl).replace(/\/+$/, "");
        try {
          let loc = window.location;
          if (loc && loc.protocol && loc.hostname) {
            return loc.protocol + "//" + loc.hostname + ":3000";
          }
        } catch (e) { /* fall through */ }
        return "";
      };
      let doRedirect = function (oldName, reason, renameBaseUrl) {
        let base = buildBase(renameBaseUrl);
        let url = base + "/rename.html?oldName=" + encodeURIComponent(oldName || characterName) +
                  "&reason=" + encodeURIComponent(reason || "scroll");
        try { window.location.href = url; } catch (e) { /* blocked — link below is the fallback */ }
        throw new Error(
          "This character must be renamed. " +
          "<a href=\"" + url + "\" style=\"color:#ffcc66;text-decoration:underline\">" +
          "Click here</a>."
        );
      };
      return response.json().then(function (body) {
        doRedirect(body && body.oldName, body && body.reason, body && body.renameBaseUrl);
      }, function () {
        doRedirect(null, null, null);
      });
    }

    if (response.status === 200) {
      return response.json();
    }

    // For 403 the server may have a real reason (account banned with
    // expiry timestamp). Read it instead of substituting a generic
    // message that hides the actual cause.
    if (response.status === 403) {
      return response.json().catch(function() { return {}; }).then(function(data) {
        if (data && data.error) throw new AuthenticationError(data.error);
        // 403 with no JSON body — same CDN/WAF case as /api/login.
        throw new AuthenticationError(
          "Login was blocked by the security layer (HTTP 403). " +
          "Try a different network, clear your browser cache, or contact support."
        );
      });
    }

    switch (response.status) {
      case 400: throw new AuthenticationError("Invalid request. Please try again.");
      case 401: throw new AuthenticationError("Session expired. Please log in again.");
      case 404: throw new AuthenticationError("Character not found on this account.");
      case 429: throw new AuthenticationError("Too many requests. Please wait a minute and try again.");
      case 500: throw new ServerError("The server experienced an internal error.");
      case 503: throw new ServerError("Login server is temporarily unavailable. Please try again.");
      default: throw new Error("Unexpected server response (HTTP " + response.status + ").");
    }

  }).then(function (response) {

    // Store the character name for reconnect
    this.__lastCharacterName = characterName;

    // Show connecting feedback while WebSocket handshake completes
    gameClient.interface.modalManager.open("floater-connecting", "Connecting to Gameworld...");
    this.connectWithToken(response.token, response.host);

  }.bind(this)).catch(x => gameClient.interface.modalManager.open("floater-connecting", x));

}

NetworkManager.prototype.createCharacterOnAccount = function (sessionToken, name, sex, callback) {

  /*
   * Function NetworkManager.createCharacterOnAccount
   * Creates a new character on the account via the login server
   */

  fetch("/api/login/create-character", {
    "method": "POST",
    "headers": { "Content-Type": "application/json" },
    "body": JSON.stringify({ "sessionToken": sessionToken, "name": name, "sex": sex })
  }).then(function (response) {

    if (response.status === 201) {
      return response.json();
    }

    // Try to read the JSON error message from the server
    return response.json().then(function (data) {
      throw (data.error || "An error occurred.");
    }).catch(function (parseError) {
      // If JSON parsing fails, use a generic message based on status
      if (typeof parseError === "string") throw parseError;
      switch (response.status) {
        case 400: throw "Invalid character name.";
        case 401: throw "Session expired. Please log in again.";
        case 409: throw "A character with this name already exists.";
        default: throw "The server experienced an internal error.";
      }
    });

  }).then(function (data) {

    callback(null, data.characters, data.premiumUntil || null);

  }).catch(function (error) {

    callback(error, null);

  });

}

NetworkManager.prototype.initOAuth = function () {

  /*
   * Function NetworkManager.initOAuth
   * Fetches OAuth config to check enabled providers and sets up buttons
   */

  fetch("/api/oauth/config").then(function (response) {
    if (!response.ok) return;
    return response.json();
  }).then(function (config) {
    if (!config) return;

    let anyEnabled = false;

    if (config.google) {
      let btn = document.getElementById("oauth-google");
      btn.style.display = "";
      btn.addEventListener("click", this.connectWithOAuth.bind(this, "google"));
      anyEnabled = true;
    }

    if (config.discord) {
      let btn = document.getElementById("oauth-discord");
      btn.style.display = "";
      btn.addEventListener("click", this.connectWithOAuth.bind(this, "discord"));
      anyEnabled = true;
    }

    // Show the OAuth section if any provider is enabled
    if (anyEnabled) {
      document.getElementById("oauth-section").style.display = "";
    }

    // Listen for postMessage from OAuth popup windows
    window.addEventListener("message", this.__handleOAuthMessage.bind(this));

  }.bind(this)).catch(function () {
    // OAuth not available — buttons remain hidden
  });

}

NetworkManager.prototype.connectWithOAuth = function (provider) {

  /*
   * Function NetworkManager.connectWithOAuth
   * Fetches the authorization URL and opens a popup window
   */

  fetch("/api/oauth/" + provider + "/url").then(function (response) {
    if (!response.ok) throw new Error("Failed to get authorization URL.");
    return response.json();
  }).then(function (data) {

    // Open the OAuth consent screen in a popup
    let width = 500;
    let height = 600;
    let left = (screen.width - width) / 2;
    let top = (screen.height - height) / 2;

    window.open(
      data.url,
      "oauth_popup",
      "width=" + width + ",height=" + height + ",left=" + left + ",top=" + top
    );

  }).catch(function (error) {
    gameClient.interface.modalManager.open("floater-connecting", "Failed to start OAuth sign-in.");
  });

}

NetworkManager.prototype.__handleOAuthMessage = function (event) {

  /*
   * Function NetworkManager.__handleOAuthMessage
   * Handles postMessage events from OAuth popup windows
   */

  // Validate origin matches our host
  if (event.origin !== window.location.origin) {
    return;
  }

  let data = event.data;

  if (!data || !data.type) {
    return;
  }

  if (data.type === "oauth_character_select") {
    // Existing user — show character selection
    this.__sessionToken = data.sessionToken;
    this.__lastHost = data.host;
    gameClient.interface.modalManager.open("character-select-modal", {
      "characters": data.characters,
      "premiumUntil": data.premiumUntil || null,
      "sessionToken": data.sessionToken,
      "host": data.host
    });
  } else if (data.type === "oauth_success") {
    // Legacy fallback — connect with the token directly
    this.connectWithToken(data.token, data.host);
  } else if (data.type === "oauth_new_user") {
    // New user — open character creation modal
    gameClient.interface.modalManager.open("floater-oauth-create", {
      "sessionToken": data.sessionToken,
      "provider": data.provider
    });
  } else if (data.type === "oauth_error") {
    gameClient.interface.modalManager.open("floater-connecting", data.error || "OAuth authentication failed.");
  }

}

NetworkManager.prototype.__handlePacket = function (event) {

  /*
   * Function NetworkManager.__handlePacket
   * Handles an incoming binary message
   * When the tab is hidden, packets are queued and processed when the tab becomes visible
   */

  // Track last received time for heartbeat detection
  this.__lastServerPacket = Date.now();

  // Save the number of received bytes
  let frameSize = event.data.byteLength || event.data.length || 0;
  this.state.bytesRecv += frameSize;

  // Frame-CRC probe — only compute for frames over the compression
  // threshold (smaller frames bypass deflate entirely on the server side).
  // The default opcode handler reads __lastFrameCRC when logging an
  // unknown opcode so we can cross-reference against frame-crc.log.
  if (frameSize > 1024) {
    this.__lastFrameCRC = __crc32Bytes(new Uint8Array(event.data));
    this.__lastFrameSize = frameSize;
  } else {
    this.__lastFrameCRC = 0;
    this.__lastFrameSize = frameSize;
  }

  // Queue packets while the tab is hidden to avoid state desync from burst processing
  if (this.__tabHidden) {
    this.__packetQueue.push(event.data);
    return;
  }

  this.__processPacketData(event.data);

}

NetworkManager.prototype.__processPacketData = function (data) {

  /*
   * Function NetworkManager.__processPacketData
   * Processes raw packet data through the packet reader
   */

  let packet = new PacketReader(data);

  while (packet.readable()) {
    try {
      this.readPacket(packet);
    } catch(error) {
      console.error("Error processing server packet:", error);
      gameClient.sendDebug("[packet error] " + error.message);
      break;
    }
    // readPacket's default case sets __desyncDetected after closing the
    // socket on an unknown opcode. Stop parsing the rest of the buffer —
    // every byte after this is misaligned, and continuing produces a
    // cascade of bogus self-heals / chunk requests / move events as
    // garbage bytes get interpreted as valid opcodes.
    if (this.__desyncDetected) {
      this.__desyncDetected = false;
      break;
    }
  }

  // After processing all packets in this batch, retry any creatures that
  // arrived before their chunk — the chunk may have been in the same batch
  if (gameClient.world && gameClient.world.__pendingCreatures.length > 0) {
    let pending = gameClient.world.__pendingCreatures;
    gameClient.world.__pendingCreatures = [];
    for (let i = 0; i < pending.length; i++) {
      let creature = pending[i];
      let tile = gameClient.world.getTileFromWorldPosition(creature.getPosition());
      if (tile !== null) {
        tile.addCreature(creature);
      } else {
        gameClient.world.__pendingCreatures.push(creature);
      }
    }
  }

}

NetworkManager.prototype.__flushPacketQueue = function () {

  /*
   * Function NetworkManager.__flushPacketQueue
   * Processes all queued packets that arrived while the tab was hidden
   */

  let queue = this.__packetQueue;
  this.__packetQueue = [];

  for (let i = 0; i < queue.length; i++) {
    this.__processPacketData(queue[i]);
  }

}

NetworkManager.prototype.__handleError = function (event) {

  /*
   * Function NetworkManager.__handleError
   * Gracefully handle websocket errors
   */

  // If we are in reconnect mode, suppress the error modal (onclose will handle retry)
  if (this.__wasConnected) {
    return;
  }

  gameClient.interface.modalManager.open("floater-connecting", new ConnectionError("Could not connect to the Gameworld. <br> Please try again later."));

}

NetworkManager.prototype.__handleClose = function (event) {

  /*
   * Function NetworkManager.__handleClose
   * Callback function for when the websocket connection is closed
   */

  let wasInGame = this.state.connected && gameClient.renderer;

  console.log("Disconnected");

  // Flush any packets queued while the tab was hidden BEFORE deciding
  // whether to silent-retry. Without this, a ServerErrorPacket sent by
  // the server right before closing the socket sits in __packetQueue —
  // __serverError stays null, the silent-retry path fires, and the
  // background tab kicks the foreground tab back. Most common when the
  // user takes over their character on a different device while the
  // first device is backgrounded (phone-to-desktop session swap).
  if (this.__packetQueue && this.__packetQueue.length > 0) {
    this.__flushPacketQueue();
  }

  // Stop the heartbeat check
  this.__stopHeartbeat();

  // Release the Web Lock so the browser can freeze the tab normally
  this.__releaseExistingWakeLock();

  // Set connected to false
  this.state.connected = false;

  // If intentionally closed (logout, death respawn), do the normal full reset
  if (this.__intentionalClose) {
    this.__intentionalClose = false;
    this.__wasConnected = false;
    if (wasInGame) {
      gameClient.reset();
    }
    return;
  }

  // Unexpected disconnect while in-game
  if (wasInGame) {

    // If the player is dead (idle timeout), skip reconnect and reset normally
    if (gameClient.player && gameClient.player.isDead) {
      this.__wasConnected = false;
      gameClient.reset();
      return;
    }

    // Stop the game loop immediately to prevent stale state from sending packets
    // or rendering with invalid references during the reconnect window
    gameClient.gameLoop.abort();

    // Server sent an error before closing — show it without reconnect option
    if (this.__serverError) {
      let errorMsg = this.__serverError;
      this.__serverError = null;
      this.__wasConnected = false;
      // If a silent retry was in flight from an earlier drop, kill it
      // so the chained retry can't fire after our error message shows.
      if (this.__silentRetryTimer) {
        clearTimeout(this.__silentRetryTimer);
        this.__silentRetryTimer = null;
      }
      if (this.__pendingModalTimer) {
        clearTimeout(this.__pendingModalTimer);
        this.__pendingModalTimer = null;
      }
      this.__silentRetryInFlight = false;
      this.__silentRetryCount = 0;
      this.__clearReconnectingIndicator();
      this.__showReconnectMessage(errorMsg);
      let btn = document.getElementById("reconnect-now-btn");
      // "Logged in from another location" is the only server error that's
      // user-recoverable — clicking the button reconnects this client and
      // kicks the other session. Other errors (banned, kicked, etc.) hide
      // the button because clicking would just bounce off the same error.
      // Auto-retry stays disabled either way; the manual click is safe
      // because it's user-initiated and can't ping-pong without intent.
      let isReclaimable = errorMsg && errorMsg.indexOf("another location") !== -1;
      if (btn) {
        btn.textContent = "Reconnect";
        if (isReclaimable) {
          btn.title = "Reconnect this client and kick the other session.";
          btn.style.display = "";
        } else {
          btn.title = "";
          btn.style.display = "none";
        }
      }
      return;
    }

    // Silent auto-retry: kick off the same fast-path reconnect that the
    // modal's Reconnect button would trigger. No modal yet. If this
    // attempt fails and we haven't exhausted the retry budget, the
    // close-handler falls into the chained-retry branch below and tries
    // again. Only after __silentRetryMax attempts is the modal surfaced.
    this.__wasConnected = true;
    this.__silentRetryInFlight = true;
    this.__silentRetryCount = 1;
    this.__reconnecting = true;
    if (!this.__disconnectStartTime) {
      this.__disconnectStartTime = Date.now();
    }

    this.__showReconnectingIndicator();
    this.__reconnectWithCharacter();
    return;
  }

  // A silent retry attempt just failed its close — chain another attempt
  // if we still have budget, otherwise surface the modal.
  if (this.__silentRetryInFlight) {
    if (this.__silentRetryCount < this.__silentRetryMax) {
      this.__silentRetryCount++;
      // Small gap between attempts so a briefly-unreachable server has
      // time to respond on the next handshake (also reduces load on a
      // genuinely-busy server). Re-surface the indicator so the cancel
      // message re-arms its 3 s auto-clear.
      this.__showReconnectingIndicator();
      let self = this;
      if (this.__silentRetryTimer) clearTimeout(this.__silentRetryTimer);
      this.__silentRetryTimer = setTimeout(function () {
        self.__silentRetryTimer = null;
        if (!self.__silentRetryInFlight) return;
        self.__reconnectWithCharacter();
      }, 1000);
      return;
    }
    // Budget exhausted — fall through to the "Reconnect failed" modal.
    this.__silentRetryInFlight = false;
    this.__clearReconnectingIndicator();
  }

  // Failed reconnect attempt — update the overlay message so the user can try again
  if (this.__wasConnected) {
    this.__reconnecting = false;
    this.__showReconnectMessage("Reconnect failed. Try again.");
    return;
  }

  // Disconnect while not in-game — normal reset
  if (this.state.connected && gameClient.renderer) {
    gameClient.reset();
  }

}

NetworkManager.prototype.__handleConnection = function (event) {

  /*
   * Function NetworkManager.__handleConnection
   * Callback fired when connected to the gameserver
   */

  this.state.connected = true;

  // Phase 1 desync probe: per-connection inbound opcode counter. Server's
  // matching counter resets on each new socket; ours has to too so the
  // SEQ_CHECK comparison stays meaningful across reconnects. Don't reuse
  // state.nPackets — it's a session-lifetime counter the debugger renders.
  this.__inboundPacketCount = 0;
  this.__seqGapNotedThisConnection = false;

  // Successful connect — clear the disconnect-duration stamp so the next
  // close starts a fresh window. Without this, a long offline session
  // followed by a successful connect, then ANOTHER quick blip, would
  // wrongly trip the hard-reload threshold.
  this.__disconnectStartTime = 0;

  // Acquire a Web Lock to prevent mobile browsers from freezing the tab
  this.__acquireWakeLock();

  // Activate the anti-connection-loss oscillator now that we have a user gesture
  gameClient.interface.soundManager.activateAntiConnectionLoss();

  // Start periodic heartbeat to detect dead connections
  this.__startHeartbeat();

  // Always hide the reconnect modal + indicator on a successful connect.
  // The full reset branch below only runs when __wasConnected is true, but
  // the modal must be dismissed in BOTH cases — including manual Reconnect
  // from the "logged in from another location" error, which clears
  // __wasConnected in __handleClose. Without this, the modal + drop-shadow
  // overlay stayed stuck on top of the in-game view after taking back the
  // session (visible bug user reported).
  this.__hideReconnectMessage();
  this.__clearReconnectingIndicator();
  this.__reconnecting = false;

  // Reset reconnection state on successful connection.
  //
  // Don't gate cleanup on __wasConnected — that flag is reset by the
  // server-error handler (line ~1287) so auto-reconnect doesn't fire,
  // but the DOM still needs scrubbing. Concrete case: "this character
  // was logged in from another location" → __wasConnected=false →
  // user clicks Reconnect → without the cleanup, the previous
  // session's creature nameplates / health bars stay layered over the
  // new world, producing the "DemcFireElemental" overlap reports.
  //
  // Detect stale state directly: if gameClient.world has any tracked
  // creatures or loaded chunks, the previous session left residue and
  // we need the same scrub the auto-reconnect path runs.
  let hasStaleWorldState = gameClient.world && (
       Object.keys(gameClient.world.activeCreatures).length > 0
    || (gameClient.world.chunks && gameClient.world.chunks.length > 0)
  );

  if (this.__wasConnected || hasStaleWorldState) {
    console.log("Reconnected to the gameserver.");

    // Ensure game loop is stopped (defensive — should already be aborted in __handleClose)
    gameClient.gameLoop.abort();

    // Remove all creature characterElements (health bars, nameplates) from the DOM
    if (gameClient.world) {
      gameClient.renderer.screen.clear();
      Object.keys(gameClient.world.activeCreatures).forEach(function (id) {
        let creature = gameClient.world.activeCreatures[id];
        if (creature && creature.characterElement) {
          creature.characterElement.remove();
        }
      });
      gameClient.world.activeCreatures = new Object();

      // Wipe all loaded chunks so stale creature references on tiles are cleared.
      // The server sends fresh chunk + creature data on reconnect via writeWorldState,
      // so these will be fully rebuilt before the game loop restarts.
      gameClient.world.chunks = new Array();
      gameClient.world.__chunksByIdVersion++;
    }

    // Nuke all dynamically-added screen elements (character names, health bars,
    // floating text) from the wrapper, preserving only static children
    if (gameClient.interface && gameClient.interface.screenElementManager) {
      let wrapper = gameClient.interface.screenElementManager.screenWrapper;
      let child = wrapper.firstChild;
      while (child) {
        let next = child.nextSibling;
        // Only preserve the static elements that are part of the HTML template
        if (child.id !== "server-message" && child.id !== "zone-message") {
          wrapper.removeChild(child);
        }
        child = next;
      }
      gameClient.interface.screenElementManager.activeTextElements.clear();

      // Hide static text elements that may have been visible at disconnect
      let serverMsg = document.getElementById("server-message");
      let zoneMsg = document.getElementById("zone-message");
      if (serverMsg) serverMsg.style.display = "none";
      if (zoneMsg) zoneMsg.style.display = "none";
    }

    // Clear notification text
    let notification = document.getElementById("notification");
    if (notification) notification.innerHTML = "";

    // Close all open containers and clear player reference
    // (will be recreated when STATE_PLAYER arrives via handleAcceptLogin)
    if (gameClient.player) {
      gameClient.player.closeAllContainers();
      gameClient.player = null;
    }

    // Clear battle window entries
    let battleWindow = gameClient.interface.windowManager.getWindow("battle-window");
    if (battleWindow) {
      battleWindow.getBody().innerHTML = "";
    }

    // Clear pending events to prevent stale callbacks
    if (gameClient.eventQueue) {
      gameClient.eventQueue.heap.content = [];
    }

    // Clear the silent-retry state — we beat the budget.
    // Remember whether this was the silent path so we can surface a
    // gentle "You have been reconnected." cancel message AFTER the
    // world state comes back in (interface needs to be alive to show
    // the message, and the new gameClient.player hasn't arrived yet).
    let wasSilent = this.__silentRetryInFlight;
    if (this.__silentRetryTimer) {
      clearTimeout(this.__silentRetryTimer);
      this.__silentRetryTimer = null;
    }
    if (this.__pendingModalTimer) {
      clearTimeout(this.__pendingModalTimer);
      this.__pendingModalTimer = null;
    }
    this.__silentRetryInFlight = false;
    this.__silentRetryCount = 0;
    this.__clearReconnectingIndicator();

    this.__wasConnected = false;
    this.__reconnecting = false;
    this.__hideReconnectMessage();

    // Defer the cancel-message until the player is actually back in-world
    // with the interface ready. 500 ms is enough for STATE_PLAYER +
    // writeWorldState to land and the modal-level UI to redraw. If the
    // interface still isn't ready (edge case), fall through quietly.
    if (wasSilent) {
      setTimeout(function () {
        if (gameClient.interface && typeof gameClient.interface.setCancelMessage === "function") {
          gameClient.interface.setCancelMessage("You have been reconnected.");
        }
        // Mirror to the in-game Console channel for persistent visibility
        if (gameClient.interface && gameClient.interface.channelManager
            && typeof gameClient.interface.channelManager.addConsoleMessage === "function") {
          gameClient.interface.channelManager.addConsoleMessage(
            "You have been reconnected.",
            Interface.prototype.COLORS.YELLOW
          );
        }
      }, 500);
    }
  } else {
    console.log("You are connected to the gameserver.");
  }

}

NetworkManager.prototype.reconnectNow = function () {

  /*
   * Function NetworkManager.reconnectNow
   * Attempts to reconnect when the user clicks the Reconnect button
   */

  let btn = document.getElementById("reconnect-now-btn");

  if (btn && btn.disabled) {
    return;
  }

  // Don't reconnect if already connected, intentionally closed, or reconnect in progress
  if (this.isConnected() || this.__intentionalClose || this.__reconnecting) {
    return;
  }

  // Disable button for 3 seconds to prevent spam-clicking
  if (btn) {
    btn.disabled = true;
    btn.style.opacity = "0.5";
    setTimeout(function () {
      btn.disabled = false;
      btn.style.opacity = "";
    }, 3000);
  }

  this.__reconnecting = true;
  this.__showReconnectMessage("Reconnecting...");

  // Activate keep-alive audio now (user gesture context)
  gameClient.interface.soundManager.activateAntiConnectionLoss();

  this.__reconnectWithCharacter();

}

NetworkManager.prototype.__reconnectWithCharacter = function () {

  /*
   * Function NetworkManager.__reconnectWithCharacter
   * Reconnects by logging in and auto-selecting the last played character.
   * If a session token exists (OAuth or regular), reuses it directly.
   * Otherwise falls back to password-based re-authentication.
   */

  // Long-disconnect hard-reload guard. If we've been disconnected longer
  // than RELOAD_AFTER_MS (typically the case after a server save, which
  // takes ~30s+), force a full page reload before reconnecting. The
  // browser then re-fetches all client JS via the launcher's
  // ?v=Date.now() cache-bust, picking up any new packet opcodes the
  // current in-memory client doesn't know how to read. Brief network
  // blips finish well under the threshold and keep the fast path.
  if (this.__disconnectStartTime && (Date.now() - this.__disconnectStartTime) > this.__RELOAD_AFTER_MS) {
    window.location.reload();
    return;
  }

  let self = this;

  // If we have a valid session token, skip login and go straight to character select
  if (this.__sessionToken && this.__lastCharacterName) {
    return this.__reconnectWithSessionToken(this.__sessionToken);
  }

  // Fall back to password-based login (regular accounts only)
  let { account, password } = gameClient.interface.getAccountDetails();

  fetch("/api/login", {
    "method": "POST",
    "headers": { "Content-Type": "application/json" },
    "body": JSON.stringify({ "account": account, "password": password })
  }).then(function (response) {

    if (response.status !== 200) {
      throw new Error("Login failed during reconnect.");
    }

    return response.json();

  }).then(function (response) {

    // Store the new session token
    self.__sessionToken = response.sessionToken;

    if (self.__lastCharacterName) {
      return self.__reconnectWithSessionToken(response.sessionToken);
    }

    // No last character — fall back to showing character select
    gameClient.interface.modalManager.open("character-select-modal", {
      "characters": response.characters,
      "premiumUntil": response.premiumUntil || null,
      "sessionToken": response.sessionToken,
      "host": response.host
    });

    self.__reconnecting = false;

  }).catch(function () {

    self.__reconnecting = false;
    self.__showReconnectMessage("Reconnect failed. Try again.");

  });

}

NetworkManager.prototype.__reconnectWithSessionToken = function (sessionToken) {

  /*
   * Function NetworkManager.__reconnectWithSessionToken
   * Reconnects using an existing session token by selecting the last character
   */

  let self = this;

  let characterName = this.__lastCharacterName;

  fetch("/api/login/select-character", {
    "method": "POST",
    "headers": { "Content-Type": "application/json" },
    "body": JSON.stringify({ "sessionToken": sessionToken, "characterName": characterName })
  }).then(function (response) {

    if (response.status === 401) {
      // Session genuinely expired — clear token so next attempt uses password login
      self.__sessionToken = null;
      throw new Error("Session expired. Please log in again.");
    }

    // 451 NAMELOCK — reconnect path was falling through to the generic
    // "Reconnect failed (server error)" message because the handler only
    // existed in the fresh-login selectCharacter path. Mirror the same
    // redirect-to-rename flow here so a /namelock-kicked player is taken
    // straight to the rename page on reconnect instead of seeing an
    // opaque error.
    if (response.status === 451) {
      let buildBase = function (renameBaseUrl) {
        if (renameBaseUrl) return String(renameBaseUrl).replace(/\/+$/, "");
        try {
          let loc = window.location;
          if (loc && loc.protocol && loc.hostname) {
            return loc.protocol + "//" + loc.hostname + ":3000";
          }
        } catch (e) { /* fall through */ }
        return "";
      };
      let doRedirect = function (oldName, reason, renameBaseUrl) {
        let base = buildBase(renameBaseUrl);
        let url = base + "/rename.html?oldName=" + encodeURIComponent(oldName || characterName) +
                  "&reason=" + encodeURIComponent(reason || "namelock");
        try { window.location.href = url; } catch (e) { /* blocked — link below is the fallback */ }
        throw new Error(
          "This character must be renamed. Click here: " + url
        );
      };
      return response.json().then(function (body) {
        doRedirect(body && body.oldName, body && body.reason, body && body.renameBaseUrl);
      }, function () {
        doRedirect(null, null, null);
      });
    }

    if (response.status !== 200) {
      throw new Error("Reconnect failed (server error). Try again.");
    }

    return response.json();

  }).then(function (data) {

    if (!data) return;                    // 451 branch already navigated away
    self.connectWithToken(data.token, data.host);

  }).catch(function (err) {

    self.__reconnecting = false;
    self.__showReconnectMessage(err.message || "Reconnect failed. Try again.");

  });

}

NetworkManager.prototype.__showReconnectingIndicator = function () {

  /*
   * Function NetworkManager.__showReconnectingIndicator
   * Shows the "Reconnecting..." cancel message + pulses the player's
   * character element while a silent retry is in flight. Called on
   * every retry attempt so the cancel-message auto-clear timer (3 s)
   * doesn't make the message disappear mid-retry. Safe to call with
   * no player / no character element (bail quietly).
   */

  try {
    if (gameClient && gameClient.interface && typeof gameClient.interface.setCancelMessage === "function") {
      gameClient.interface.setCancelMessage("Reconnecting...");
    }
    // Mirror to the in-game Console channel so the message persists
    // (cancel text auto-clears in 3s; the console scrollback is forever)
    if (gameClient && gameClient.interface && gameClient.interface.channelManager
        && typeof gameClient.interface.channelManager.addConsoleMessage === "function") {
      gameClient.interface.channelManager.addConsoleMessage(
        "Reconnecting...",
        Interface.prototype.COLORS.YELLOW
      );
    }
  } catch (e) { /* notification manager may not be initialised yet */ }

  if (gameClient && gameClient.player && gameClient.player.characterElement) {
    let el = gameClient.player.characterElement.element;
    if (el && el.classList && !el.classList.contains("reconnecting-player-pulse")) {
      el.classList.add("reconnecting-player-pulse");
    }
  }

}

NetworkManager.prototype.__clearReconnectingIndicator = function () {

  /*
   * Function NetworkManager.__clearReconnectingIndicator
   * Removes the pulse class. Cancel message auto-clears on its own.
   * Called on successful reconnect and on modal surface (retry budget
   * exhausted).
   */

  if (gameClient && gameClient.player && gameClient.player.characterElement) {
    let el = gameClient.player.characterElement.element;
    if (el && el.classList) {
      el.classList.remove("reconnecting-player-pulse");
    }
  }

}

NetworkManager.prototype.__showReconnectMessage = function (message) {

  /*
   * Function NetworkManager.__showReconnectMessage
   * Shows an overlay message on the game screen during reconnection
   */

  let overlay = document.getElementById("reconnect-overlay");

  if (!overlay) {
    overlay = document.createElement("div");
    overlay.id = "reconnect-overlay";
    overlay.style.cssText = "position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.6);display:flex;align-items:center;justify-content:center;z-index:9999;";
    let inner = document.createElement("div");
    // Responsive: cap width to viewport minus a 16px gutter so long
    // messages (e.g. the scroll / namelock kick copy) don't overflow on
    // narrow phones. Word-wrap + box-sizing keeps the rounded box tidy.
    inner.style.cssText = "text-align:center;background:rgba(0,0,0,0.8);padding:16px 20px;border:1px solid #555;border-radius:4px;max-width:calc(100% - 32px);box-sizing:border-box;";
    let msg = document.createElement("div");
    msg.id = "reconnect-message";
    msg.style.cssText = "color:#fff;font-size:clamp(14px, 3.8vw, 18px);font-family:Martel,serif;white-space:pre-line;word-break:break-word;line-height:1.35;";
    let btn = document.createElement("button");
    btn.id = "reconnect-now-btn";
    btn.textContent = "Reconnect";
    btn.style.cssText = "margin-top:12px;padding:8px 20px;font-size:14px;font-family:Martel,serif;cursor:pointer;background:#444;color:#fff;border:1px solid #888;border-radius:3px;";
    btn.addEventListener("click", this.reconnectNow.bind(this));
    inner.appendChild(msg);
    inner.appendChild(btn);
    overlay.appendChild(inner);
    document.body.appendChild(overlay);
  }

  overlay.style.display = "flex";
  document.getElementById("reconnect-message").textContent = message;

  // Reset the button to its default state every show so a previous
  // "Force Reconnect" label or hidden state doesn't persist into a
  // subsequent unrelated reconnect attempt. Callers that need the
  // alternate label / visibility (e.g. the "logged in elsewhere" path)
  // override these properties immediately after calling this function.
  let btn = document.getElementById("reconnect-now-btn");
  if (btn) {
    btn.textContent = "Reconnect";
    btn.title = "";
    btn.style.display = "";
  }

}

NetworkManager.prototype.__hideReconnectMessage = function () {

  /*
   * Function NetworkManager.__hideReconnectMessage
   * Hides the reconnection overlay
   */

  let overlay = document.getElementById("reconnect-overlay");

  if (overlay) {
    overlay.style.display = "none";
  }

}

NetworkManager.prototype.__acquireWakeLock = function () {

  /*
   * Function NetworkManager.__acquireWakeLock
   * Acquires a Web Lock to prevent mobile browsers from freezing the tab and killing the WebSocket.
   * Chrome/Android freezes background tabs to save battery, but pages holding a Web Lock are exempt.
   */

  // Release any existing lock first
  this.__releaseExistingWakeLock();

  if (typeof navigator.locks === "undefined") {
    return;
  }

  navigator.locks.request("minibia_ws_keepalive", function (lock) {
    return new Promise(function (resolve) {
      this.__releaseWakeLock = resolve;
    }.bind(this));
  }.bind(this));

}

NetworkManager.prototype.__releaseExistingWakeLock = function () {

  /*
   * Function NetworkManager.__releaseExistingWakeLock
   * Releases the Web Lock so the browser can freeze the tab normally after disconnect
   */

  if (this.__releaseWakeLock !== null) {
    this.__releaseWakeLock();
    this.__releaseWakeLock = null;
  }

}

NetworkManager.prototype.__startHeartbeat = function () {

  /*
   * Function NetworkManager.__startHeartbeat
   * Starts a periodic heartbeat that pings the server every 15 seconds.
   * Uses a Web Worker so the timer is NOT throttled when the tab is in the background.
   * Main-thread setInterval gets throttled to 1/minute in background tabs, which is
   * too slow to detect dead connections before the server kicks the player.
   */

  this.__stopHeartbeat();
  this.__lastServerPacket = Date.now();
  this.__pendingPings = 0;

  let self = this;

  // 3s heartbeat cadence — paired with the server's 6s app-liveness
  // threshold for ~6s end-to-end detection of half-open WebSockets
  // mid-combat. 1 byte/ping × 20 pings/min/player is negligible cost.
  let workerCode = "setInterval(function(){postMessage('tick')},3000);";
  let blob = new Blob([workerCode], { "type": "application/javascript" });
  this.__heartbeatWorker = new Worker(URL.createObjectURL(blob));

  this.__heartbeatWorker.onmessage = function () {

    // Only check while connected
    if (!self.state.connected || !self.socket || self.socket.readyState !== WebSocket.OPEN) {
      return;
    }

    // Skip liveness check when tab is hidden — main thread is frozen so
    // __lastServerPacket stops updating, but the connection is still alive
    // Still send pings to keep the server idle timer alive
    if (self.__tabHidden) {
      self.getLatency();
      return;
    }

    // If we haven't received any packet in 20 seconds, connection is dead
    if (Date.now() - self.__lastServerPacket > 20000) {
      console.log("Heartbeat — no server packets for 20s, forcing reconnect...");
      self.__stopHeartbeat();
      self.socket.close();
      return;
    }

    // Half-open detection: the prior check only fires when the inbound
    // pipe goes silent. If outbound is dead but server-pushed packets
    // (combat damage etc.) keep arriving, __lastServerPacket stays
    // fresh and the player sits there unable to walk/heal/cast (Mimes
    // case, 2026-04-29 — see MEMORY/half_open_websocket_heartbeat). At
    // 3s cadence, ≥2 unanswered pings = 6-9s without a pong, well past
    // any plausible RTT spike. Reconnect promptly so server-side
    // monster protection has time to save the player.
    if (self.__pendingPings >= 2) {
      console.log("Heartbeat — " + self.__pendingPings + " pings unanswered, outbound dead, forcing reconnect...");
      self.__stopHeartbeat();
      self.socket.close();
      return;
    }

    // Send a ping to keep the connection alive and provoke a response
    self.getLatency();

  };

}

NetworkManager.prototype.__stopHeartbeat = function () {

  /*
   * Function NetworkManager.__stopHeartbeat
   * Terminates the heartbeat Web Worker
   */

  if (this.__heartbeatWorker !== null) {
    this.__heartbeatWorker.terminate();
    this.__heartbeatWorker = null;
  }

}

NetworkManager.prototype.__handleVisibilityChange = function () {

  /*
   * Function NetworkManager.__handleVisibilityChange
   * Routes visibility transitions to the shared background-enter / foreground-
   * return handlers so pagehide / pageshow / visibilitychange all use the
   * same logic (mobile browsers don't all fire the same events reliably).
   */

  if (document.visibilityState !== "visible") {
    this.__onBackgroundEnter();
  } else {
    this.__onForegroundReturn(false);
  }

}

NetworkManager.prototype.__handlePageHide = function () {

  /*
   * Function NetworkManager.__handlePageHide
   * iOS Safari fires pagehide when suspending the tab (app switch, screen
   * lock), often without a matching visibilitychange. Treat as a background
   * transition so we start queueing packets and tracking hiddenAt.
   */

  this.__onBackgroundEnter();

}

NetworkManager.prototype.__handlePageShow = function (event) {

  /*
   * Function NetworkManager.__handlePageShow
   * Fired when the page is displayed — including bfcache restore, where
   * `event.persisted` is true. A bfcache-restored page has had its
   * WebSocket silently killed by the browser; reconnect without waiting
   * for any probe.
   */

  if (event && event.persisted) {
    // bfcache restore — socket is definitely gone
    this.__tabHidden = false;
    this.__packetQueue = [];
    this.__lastServerPacket = Date.now();
    if (this.__wasConnected && !this.__intentionalClose) {
      console.log("Page restored from bfcache — forcing reconnect.");
      this.reconnectNow();
    }
    return;
  }

  this.__onForegroundReturn(false);

}

NetworkManager.prototype.__handleOnline = function () {

  /*
   * Function NetworkManager.__handleOnline
   * Fires when the OS reports the device has regained network connectivity
   * (WiFi reconnect, airplane mode off, tunnel exit). If our socket isn't
   * OPEN, reconnect immediately — don't wait 15s for the heartbeat to
   * figure out what the OS already knows.
   */

  if (this.__intentionalClose) return;
  if (!this.__wasConnected) return;
  if (this.socket && this.socket.readyState === WebSocket.OPEN) {
    // Socket claims to be open but may be a zombie after connectivity loss.
    // Force a probe — heartbeat picks it up if no pong arrives.
    this.getLatency();
    return;
  }
  console.log("Network online — forcing reconnect.");
  this.__packetQueue = [];
  this.reconnectNow();

}

NetworkManager.prototype.__handleOffline = function () {

  /*
   * Function NetworkManager.__handleOffline
   * Fires when the OS reports loss of network. Nothing to do proactively —
   * the socket will drop on its own and the heartbeat / pageshow / online
   * handlers will reconnect when connectivity returns. Logged so we can
   * trace the sequence during debugging.
   */

  console.log("Network offline — waiting for reconnect.");

}

NetworkManager.prototype.__onBackgroundEnter = function () {

  /*
   * Function NetworkManager.__onBackgroundEnter
   * Shared path for entering background state. Idempotent — safe to call
   * repeatedly as both pagehide and visibilitychange may fire for the
   * same transition.
   */

  if (this.__tabHidden) return;
  this.__hiddenAt = Date.now();
  this.__tabHidden = true;

}

NetworkManager.prototype.__onForegroundReturn = function (forceReconnect) {

  /*
   * Function NetworkManager.__onForegroundReturn
   * Shared path for returning to foreground. Always probes the socket
   * (removed the old awayMs > 15000 gate — short backgrounds still leave
   * zombie sockets on mobile, and one ping is cheap). If the socket is
   * already closed or forceReconnect is true, kicks off reconnect.
   */

  if (!this.__tabHidden && !forceReconnect) {
    // Nothing to recover from — but still flush queue defensively.
    this.__flushPacketQueue();
    return;
  }

  this.__tabHidden = false;
  this.__lastServerPacket = Date.now();

  if (this.__intentionalClose) {
    this.__packetQueue = [];
    return;
  }

  // Case 1: onclose already fired while we were hidden.
  if (this.__wasConnected && (!this.socket || this.socket.readyState !== WebSocket.OPEN)) {
    console.log("Foreground return — socket already closed, reconnecting.");
    this.__packetQueue = [];
    this.reconnectNow();
    return;
  }

  // Case 2: socket still claims to be OPEN. Always probe with a ping —
  // zombies can appear after even brief backgrounds on iOS. If no pong
  // arrives the heartbeat's 20s dead-connection check reconnects for us.
  if (this.state.connected && this.socket && this.socket.readyState === WebSocket.OPEN) {
    this.__flushPacketQueue();
    this.getLatency();
    return;
  }

  // Fallback: drain any queued packets.
  this.__flushPacketQueue();

}



/* ===== FILE: https://minibia.com/src/network/packet-handler.js?v=1778114718536 ===== */

const PacketHandler = function () {

  /*
   * Class PacketHandler
   * Containers handler functions for all incoming network packets from the gameserver
   * This usually delegates to the gameClient but is a central place for collections
   */

}

// Per-creature cooldown Map for the unknown-creature self-heal below.
// Shared across the single PacketHandler instance.
PacketHandler.prototype.__unknownCreatureCooldown = new Map();

PacketHandler.prototype.__selfHealForUnknownCreature = function (creatureId, position, source) {

  /*
   * Function PacketHandler.__selfHealForUnknownCreature
   *
   * CLIENT-SIDE SELF-HEAL for missed CreatureStatePacket delivery.
   *
   * Symptom we're patching:
   *   The server sends a packet for a creature whose CreatureStatePacket
   *   we never received (damage emote, property change, move, say,
   *   condition toggle, teleport). The client silently drops the packet
   *   because the creature isn't in world.__creatures. Result: invisible
   *   attackers, players taking damage from "nothing", ghost-like sprites.
   *   Only a relog fixes it because relog forces a full serializeWorld.
   *
   * Fix strategy:
   *   When we detect the unknown-creature situation, send ONE CHUNK_REQUEST
   *   asking the server to re-serialize the chunk containing that creature.
   *   The chunk re-send includes every CreatureStatePacket in that chunk
   *   (see server Chunk.serialize). Our client's existing
   *   __pendingCreatures buffer then drains the arriving creatures into
   *   their tiles.
   *
   * Why this is safe (and not the failed __knownBy approach):
   *   - Zero server-side tracking: no Sets on creatures, no O(N²) scans,
   *     no periodic reconciliation. __knownBy was reverted in commit
   *     1addc511 because it caused ~50% abnormal-disconnect rates with
   *     80 players; this reactive approach touches none of that.
   *   - Purely reactive: only fires when the specific symptom hits.
   *     A well-synced client never triggers this code.
   *   - Server-side CHUNK_REQUEST is already rate-limited to 1/2s per
   *     socket AND validates that the requested chunk is a neighbour of
   *     the player's current chunk (see src/network/network-manager.js).
   *     A hostile client cannot weaponize this to pull arbitrary world
   *     state.
   *   - We also rate-limit per-creature-id on the client at 2s so a
   *     server repeatedly referencing a creature that's genuinely not in
   *     our visible area (odd edge case) won't fire bursts of requests.
   *
   * Limits:
   *   - If we have the creature's position (move/teleport packets), we
   *     pass it directly so the server re-sends that specific chunk.
   *   - If we don't (emote/say/property/condition), we fall back to the
   *     local player's position and request our own visible neighbourhood.
   *     The unknown creature must be in one of those chunks or the server
   *     wouldn't have referenced it at all.
   */

  if (!gameClient.world) return;

  let now = performance.now();
  let lastAsk = PacketHandler.prototype.__unknownCreatureCooldown.get(creatureId);
  if (lastAsk && now - lastAsk < 2000) return;
  PacketHandler.prototype.__unknownCreatureCooldown.set(creatureId, now);

  let requestPos = position;
  if (!requestPos && gameClient.player) {
    requestPos = gameClient.player.getPosition();
  }
  if (!requestPos) return;

  gameClient.world.requestChunk(requestPos);

  // Diagnostic — emit a [self-heal] line for every firing so server logs
  // can correlate [CHUNK_REQUEST] bursts to the exact packet type and
  // creature id that triggered the recovery. Sent directly via send() to
  // bypass the gameClient.sendDebug 5s rate limit (the enclosing 2s per-
  // creatureId cooldown above already throttles us plenty).
  // Suppressed within the post-/goto window — the burst of move/state
  // packets that race ahead of the new-area chunks always triggers a
  // flurry of these and they all self-heal correctly. Heal still ran;
  // we just skip the log for the noise window.
  let suppressUntil = gameClient.player && gameClient.player.__postTeleportLogSuppressUntil;
  if (suppressUntil && now < suppressUntil) return;
  try {
    let p = gameClient.player && gameClient.player.getPosition ? gameClient.player.getPosition() : { x: 0, y: 0, z: 0 };
    let msg = "[self-heal] source=" + (source || "unknown")
      + " cid=" + creatureId
      + " at=" + requestPos.x + "," + requestPos.y + "," + requestPos.z
      + " player=" + p.x + "," + p.y + "," + p.z
      + " posKnown=" + (position ? 1 : 0);
    gameClient.send(new ClientDebugPacket(msg));
  } catch (e) { /* diagnostics must never break the handler */ }

  // Keep the Map bounded — evict entries older than 10s if we accumulate many
  if (PacketHandler.prototype.__unknownCreatureCooldown.size > 256) {
    PacketHandler.prototype.__unknownCreatureCooldown.forEach(function (t, id) {
      if (now - t > 10000) PacketHandler.prototype.__unknownCreatureCooldown.delete(id);
    });
  }

};

PacketHandler.prototype.handlePropertyChange = function (packet) {

  let creature = gameClient.world.getCreature(packet.guid);

  if (creature === null) {
    // Death-window race suppression: the killing-blow setProperty(HEALTH, 0)
    // is broadcast moments before the server's removeCreature() deletes the
    // entity from creatureHandler. If we receive that HEALTH=0 packet for a
    // creature we don't have (e.g. we just walked into the chunk and the
    // intro packet hasn't arrived yet), firing a self-heal probe is wasted
    // — by the time the probe reaches the server the creature is gone, the
    // server returns MISSING, and the forget packet is already on its way
    // anyway. Silently drop these packets to keep the log clean and save
    // the round-trip. Pixi + Wuwuzela had ~150 such events in a 4-hour
    // window today, all srvCreature=MISSING — this should erase them.
    if (packet.property === CONST.PROPERTIES.HEALTH && packet.value === 0) {
      return;
    }

    // Self-heal: server referenced a creature we don't know about. See
    // __selfHealForUnknownCreature for the full rationale.
    PacketHandler.prototype.__selfHealForUnknownCreature(packet.guid, null, "property");
    return;
  }

  // Track last server update for ghost creature detection
  creature.__lastServerUpdate = performance.now();

  switch (packet.property) {
    case CONST.PROPERTIES.HEALTH:
      // Death explosion: trigger when creature health drops to 0
      // Stored on renderer (not creature) so it persists after creature is removed from world
      if (packet.value === 0 && creature !== gameClient.player && creature.state.health > 0) {
        // Death fade: creature shrinks and fades over 300ms
        creature.__deathFade = { start: performance.now() };
        let color = PacketHandler.prototype.__getCreatureBloodColor(creature);
        // Scale particle count and size by creature sprite size
        let spriteSize = 32;
        let charObj = creature.outfit.getDataObject();
        if (charObj) {
          let fg = charObj.getFrameGroup(0);
          if (fg && (fg.width > 1 || fg.height > 1)) spriteSize = 64;
        }
        let isSmall = PacketHandler.prototype.__BODY_SMALL.test(creature.name);
        let count = spriteSize > 32 ? 40 : isSmall ? 12 : 22;
        let maxSpeed = spriteSize > 32 ? 4.0 : isSmall ? 1.8 : 2.8;
        let maxSize = spriteSize > 32 ? 2.5 : isSmall ? 1.0 : 1.5;
        let particles = [];
        for (let i = 0; i < count; i++) {
          let angle = Math.random() * 2 * Math.PI;
          let speed = 0.8 + Math.random() * maxSpeed;
          particles.push({
            vx: Math.cos(angle) * speed,
            vy: Math.sin(angle) * speed,
            size: 0.6 + Math.random() * maxSize
          });
        }
        gameClient.renderer.__activeDeathExplosions.push({
          start: performance.now(),
          worldPos: creature.getPosition(),
          particles: particles,
          color: color
        });
      }
      // Tutorial highlight: show health/mana bars on first damage
      if (creature === gameClient.player) {
        gameClient.interface.tutorialHighlight.onHealthChange(creature.state.health, packet.value);
      }
      // Update damage tint based on HP percentage (0 = full HP, 1 = near death)
      PacketHandler.prototype.__updateDamageTint(creature, packet.value);
      return creature.state.health = packet.value;
    case CONST.PROPERTIES.HEALTH_MAX:
      creature.maxHealth = packet.value;
      creature.state.maxHealth = packet.value;
      creature.setHealthStatus();
      return;
    case CONST.PROPERTIES.MANA:
      return creature.state.mana = packet.value;
    case CONST.PROPERTIES.MANA_MAX:
      creature.state.maxMana = packet.value;
      creature.setManaStatus();
      return;
    case CONST.PROPERTIES.CAPACITY:
      if (creature === gameClient.player) {
        creature.state.capacity = packet.value;
      }
      return;
    case CONST.PROPERTIES.CAPACITY_MAX:
      if (creature === gameClient.player) {
        creature.state.maxCapacity = packet.value;
      }
      return;
    case CONST.PROPERTIES.SPEED:
      // Update speed in real-time (for haste, boots of haste, etc.)
      if (creature === gameClient.player) {
        creature.state.speed = packet.value;
        // Update the UI - skill window shows speed
        let skillWindow = gameClient.interface.windowManager.getWindow("skill-window");
        if (skillWindow) {
          skillWindow.setSkillValue("speed", packet.value, 0);
        }
      }
      // Also update the creature's speed for movement calculations
      creature.speed = packet.value;
      return;
    case CONST.PROPERTIES.DIRECTION:
      return creature.setTurnBuffer(packet.value);
    case CONST.PROPERTIES.VOCATION:
      if (creature === gameClient.player) {
        creature.vocation = packet.value;
        if (creature.skills) {
          creature.skills.vocation = packet.value;
        }
      }
      return;
    case CONST.PROPERTIES.LEVEL: // 31 — kept distinct from SMITHING (30)
      if (creature === gameClient.player) {
        let oldLevel = creature.skills ? creature.skills.level : 0;

        // Store the level for experience percentage calculation
        if (!creature.skills) creature.skills = {};
        creature.skills.level = packet.value;

        // Update the level in skills display
        gameClient.interface.windowManager.getWindow("skill-window").setSkillValue("level", packet.value, 0);
        // Update health and mana bars after level up
        creature.setHealthStatus();
        creature.setManaStatus();

        // Level-up glow effect (gold burst)
        if (packet.value > oldLevel && oldLevel > 0) {
          creature.__spellGlow = { start: performance.now(), color: [255, 215, 0] };
        }
      }
      return;
    case CONST.PROPERTIES.EXPERIENCE:
      if (creature === gameClient.player) {
        // Calculate experience percentage to next level
        let currentExp = packet.value;
        let currentLevel = creature.skills ? creature.skills.level : 1;

        // Experience table formula: 50/3 * (x³ - 6x² + 17x - 12)
        let getExpForLevel = function (level) {
          return Math.round((50 / 3) * (Math.pow(level, 3) - 6 * Math.pow(level, 2) + 17 * level - 12));
        };

        let currentLevelExp = getExpForLevel(currentLevel);
        let nextLevelExp = getExpForLevel(currentLevel + 1);
        let expDiff = nextLevelExp - currentLevelExp;
        let expProgress = currentExp - currentLevelExp;
        let percentage = expDiff > 0 ? (expProgress / expDiff) * 100 : 0;

        // Update the experience in skills display with calculated percentage
        let skillWindow = gameClient.interface.windowManager.getWindow("skill-window");
        skillWindow.setSkillValue("experience", currentExp, percentage);
        skillWindow.updateExperiencePerHour(currentExp);
      }
      return;
    // Combat skills - real-time updates
    case CONST.PROPERTIES.MAGIC:
    case CONST.PROPERTIES.FIST:
    case CONST.PROPERTIES.CLUB:
    case CONST.PROPERTIES.SWORD:
    case CONST.PROPERTIES.AXE:
    case CONST.PROPERTIES.DISTANCE:
    case CONST.PROPERTIES.SHIELDING:
    case CONST.PROPERTIES.FISHING:
    case CONST.PROPERTIES.MINING:
    case CONST.PROPERTIES.WOODCUTTING:
    case CONST.PROPERTIES.COOKING:
    case CONST.PROPERTIES.SMITHING:
      if (creature === gameClient.player) {
        this.__handleSkillUpdate(packet.property, packet.value);
      }
      return;
  }

}

PacketHandler.prototype.__handleSkillUpdate = function (skillType, skillPoints) {
  /*
   * Function PacketHandler.__handleSkillUpdate
   * Handles real-time skill point updates and calculates level/percentage
   */

  // Get skill name for the window
  let skillName = this.__getSkillNameFromType(skillType);
  if (skillName === null) return;

  // Get vocation for calculation (default to NONE if not available)
  let vocation = gameClient.player.vocation || 0;

  // Calculate skill level and percentage from points
  let { level, percentage } = this.__calculateSkillLevelAndPercentage(skillType, skillPoints, vocation);

  // Update the skill window
  gameClient.interface.windowManager.getWindow("skill-window").setSkillValue(skillName, level, percentage);
}

PacketHandler.prototype.__getSkillNameFromType = function (type) {
  /*
   * Returns the skill name used in the skill-window for a given skill type
   */
  switch (type) {
    case CONST.PROPERTIES.MAGIC: return "magic";
    case CONST.PROPERTIES.FIST: return "fist";
    case CONST.PROPERTIES.CLUB: return "club";
    case CONST.PROPERTIES.SWORD: return "sword";
    case CONST.PROPERTIES.AXE: return "axe";
    case CONST.PROPERTIES.DISTANCE: return "distance";
    case CONST.PROPERTIES.SHIELDING: return "shielding";
    case CONST.PROPERTIES.FISHING: return "fishing";
    case CONST.PROPERTIES.MINING: return "mining";
    case CONST.PROPERTIES.WOODCUTTING: return "woodcutting";
    case CONST.PROPERTIES.COOKING: return "cooking";
    case CONST.PROPERTIES.SMITHING: return "smithing";
    default: return null;
  }
}

PacketHandler.prototype.__calculateSkillLevelAndPercentage = function (skillType, points, vocation) {
  /*
   * Calculates skill level and percentage from skill points
   * Uses the Tibia formula: A * ((B^(level - offset) - 1) / (B - 1))
   * See https://tibia.fandom.com/wiki/Formulae#Skills
   */

  // Skill constants based on type
  let A, B, skillOffset;

  // Get A (skill constant) - same for all vocations
  switch (skillType) {
    case CONST.PROPERTIES.MAGIC: A = 1600; break;
    case CONST.PROPERTIES.FIST:
    case CONST.PROPERTIES.CLUB:
    case CONST.PROPERTIES.SWORD:
    case CONST.PROPERTIES.AXE: A = 50; break;
    case CONST.PROPERTIES.DISTANCE: A = 25; break;
    case CONST.PROPERTIES.SHIELDING: A = 100; break;
    case CONST.PROPERTIES.FISHING: A = 20; break;
    case CONST.PROPERTIES.MINING:
    case CONST.PROPERTIES.WOODCUTTING:
    case CONST.PROPERTIES.COOKING:
    case CONST.PROPERTIES.SMITHING: A = 30; break;
    default: A = 50;
  }

  // Get B (vocation constant) - matches server skill.js exactly
  B = this.__getVocationSkillConstant(skillType, vocation);

  // Skill offset (magic starts at 0, others at 10)
  skillOffset = skillType === CONST.PROPERTIES.MAGIC ? 0 : 10;

  // Calculate level from points: level = offset + log(points * (B-1) / A + 1) / log(B)
  let level = Math.floor(skillOffset + (Math.log(points * ((B - 1) / A) + 1) / Math.log(B)));

  // Calculate points required for current level and next level (rounded to match server)
  let getPointsForLevel = function (lvl) {
    return Math.round(A * ((Math.pow(B, lvl - skillOffset) - 1) / (B - 1)));
  };

  let currentLevelPoints = getPointsForLevel(level);
  let nextLevelPoints = getPointsForLevel(level + 1);
  let pointsDiff = nextLevelPoints - currentLevelPoints;
  let pointsProgress = points - currentLevelPoints;
  let percentage = pointsDiff > 0 ? (pointsProgress / pointsDiff) * 100 : 0;

  // Clamp percentage
  percentage = Math.max(0, Math.min(percentage, 100));

  return { level, percentage };
}

PacketHandler.prototype.__getVocationSkillConstant = function (skillType, vocation) {
  /*
   * Returns the vocation skill constant (B) for each skill
   * Matches server skill.js __getVocationConstant exactly
   */

  // Map promoted vocations to their base vocation (same skill rates)
  switch (vocation) {
    case 5: vocation = 1; break; // Elite Knight → Knight
    case 6: vocation = 2; break; // Royal Paladin → Paladin
    case 7: vocation = 3; break; // Master Sorcerer → Sorcerer
    case 8: vocation = 4; break; // Elder Druid → Druid
  }

  if (vocation === 0) { // NONE
    switch (skillType) {
      case CONST.PROPERTIES.MAGIC: return 3.0;
      case CONST.PROPERTIES.CLUB:
      case CONST.PROPERTIES.SWORD:
      case CONST.PROPERTIES.AXE:
      case CONST.PROPERTIES.DISTANCE: return 2.0;
      case CONST.PROPERTIES.FIST:
      case CONST.PROPERTIES.SHIELDING: return 1.5;
      case CONST.PROPERTIES.FISHING:
      case CONST.PROPERTIES.MINING:
      case CONST.PROPERTIES.WOODCUTTING:
      case CONST.PROPERTIES.COOKING:
      case CONST.PROPERTIES.SMITHING: return 1.1;
    }
  } else if (vocation === 1) { // KNIGHT
    switch (skillType) {
      case CONST.PROPERTIES.MAGIC: return 3.0;
      case CONST.PROPERTIES.CLUB:
      case CONST.PROPERTIES.SWORD:
      case CONST.PROPERTIES.AXE:
      case CONST.PROPERTIES.FIST:
      case CONST.PROPERTIES.SHIELDING:
      case CONST.PROPERTIES.FISHING:
      case CONST.PROPERTIES.MINING:
      case CONST.PROPERTIES.WOODCUTTING:
      case CONST.PROPERTIES.COOKING:
      case CONST.PROPERTIES.SMITHING: return 1.1;
      case CONST.PROPERTIES.DISTANCE: return 1.4;
    }
  } else if (vocation === 2) { // PALADIN
    switch (skillType) {
      case CONST.PROPERTIES.MAGIC: return 1.4;
      case CONST.PROPERTIES.CLUB:
      case CONST.PROPERTIES.SWORD:
      case CONST.PROPERTIES.AXE:
      case CONST.PROPERTIES.FIST: return 1.2;
      case CONST.PROPERTIES.DISTANCE:
      case CONST.PROPERTIES.SHIELDING:
      case CONST.PROPERTIES.FISHING:
      case CONST.PROPERTIES.MINING:
      case CONST.PROPERTIES.WOODCUTTING:
      case CONST.PROPERTIES.COOKING:
      case CONST.PROPERTIES.SMITHING: return 1.1;
    }
  } else if (vocation === 3) { // SORCERER
    switch (skillType) {
      case CONST.PROPERTIES.MAGIC: return 1.1;
      case CONST.PROPERTIES.CLUB:
      case CONST.PROPERTIES.SWORD:
      case CONST.PROPERTIES.AXE:
      case CONST.PROPERTIES.DISTANCE: return 2.0;
      case CONST.PROPERTIES.FIST:
      case CONST.PROPERTIES.SHIELDING: return 1.5;
      case CONST.PROPERTIES.FISHING:
      case CONST.PROPERTIES.MINING:
      case CONST.PROPERTIES.WOODCUTTING:
      case CONST.PROPERTIES.COOKING:
      case CONST.PROPERTIES.SMITHING: return 1.1;
    }
  } else if (vocation === 4) { // DRUID
    switch (skillType) {
      case CONST.PROPERTIES.MAGIC: return 1.1;
      case CONST.PROPERTIES.CLUB:
      case CONST.PROPERTIES.SWORD:
      case CONST.PROPERTIES.AXE:
      case CONST.PROPERTIES.DISTANCE: return 1.8;
      case CONST.PROPERTIES.FIST:
      case CONST.PROPERTIES.SHIELDING: return 1.5;
      case CONST.PROPERTIES.FISHING:
      case CONST.PROPERTIES.MINING:
      case CONST.PROPERTIES.WOODCUTTING:
      case CONST.PROPERTIES.COOKING:
      case CONST.PROPERTIES.SMITHING: return 1.1;
    }
  }

  // Default fallback
  return 2.0;
}

PacketHandler.prototype.handleWorldTime = function (time) {

  /*
   * Function PacketHandler.handleWorldTime
   * Handles an incoming packet with the world time by setting the phase offset between client / phase
   */

  gameClient.world.clock.setPhase(time);

}

PacketHandler.prototype.handleSetTarget = function (id) {

  /*
   * Function PacketHandler.handleSetTarget
   * Handles server-side event that sets the target of the player
   */

  // An identifier of zero means null
  if (id === 0) {
    return gameClient.player.setTarget(null);
  }

  // Set the target creature if it exists
  let creature = gameClient.world.getCreature(id);

  if (creature === null) {
    return;
  }

  gameClient.player.setTarget(creature);

}

PacketHandler.prototype.handleSetFollowTarget = function (id) {

  /*
   * Function PacketHandler.handleSetFollowTarget
   * Handles server-side event that sets the follow target of the player
   */

  if (id === 0) {
    return gameClient.player.setFollowTarget(null);
  }

  let creature = gameClient.world.getCreature(id);

  if (creature === null) {
    return;
  }

  gameClient.player.setFollowTarget(creature);

}

PacketHandler.prototype.handleCombatLock = function (bool) {

  /*
   * Function PacketHandler.handleCombatLock
   * Handles state of the combat lock from true to false on the DOM
   */

  let condition = new Object({
    "toggle": bool,
    "guid": gameClient.player.id,
    "cid": ConditionManager.prototype.COMBAT_LOCK
  });

  this.handleCondition(condition);

}

PacketHandler.prototype.handleCondition = function (packet) {

  /*
   * Function PacketHandler.handleCondition
   * Handles an incoming change to a condition
   */

  let creature = gameClient.world.getCreature(packet.guid);

  if (creature === null) {
    // Self-heal for missed CreatureStatePacket (see __selfHealForUnknownCreature).
    PacketHandler.prototype.__selfHealForUnknownCreature(packet.guid, null, "condition");
    return;
  }

  // Determine what to do
  if (packet.toggle) {
    // Track whether LIGHT condition is from equipment (permanent) or spell
    if (packet.cid === ConditionManager.prototype.LIGHT) {
      creature.__lightLevel = packet.properties || 0;
      creature.__lightPermanent = !!packet.permanent;
    }
    creature.addCondition(packet.cid);
  } else {
    creature.removeCondition(packet.cid);
    // Clear light level when LIGHT condition expires
    if (packet.cid === ConditionManager.prototype.LIGHT) {
      creature.__lightLevel = 0;
      creature.__lightPermanent = false;
    }
  }

}

PacketHandler.prototype.handleTradeOffer = function (packet) {

  /*
   * Function PacketHandler.handleTradeOffer
   * Handles incoming packet to open the NPC trade offer modal.
   * An empty offer list signals the NPC ended the conversation — close the modal.
   */

  if (packet.offers.length === 0) {
    // Server ended the conversation — clear NPC dialog state before closing
    // so handleClose does not restore an outdated dialog
    gameClient.interface.npcDialog.clearState();
    gameClient.interface.npcDialog.hide();
    gameClient.interface.modalManager.close();
    return;
  }

  // Hide NPC dialog while trade modal is open — it will be restored on close
  gameClient.interface.npcDialog.hide();
  gameClient.interface.modalManager.open("offer-modal", packet)

}

PacketHandler.prototype.handleTradeGoldUpdate = function (gold) {

  /*
   * Function PacketHandler.handleTradeGoldUpdate
   * Updates the gold display in the NPC trade modal after a transaction
   */

  let modal = gameClient.interface.modalManager.get("offer-modal");

  if (modal) {
    modal.updateGold(gold);
  }

}

PacketHandler.prototype.handleTradeFeedback = function (message) {

  /*
   * Function PacketHandler.handleTradeFeedback
   * Displays an error message in the NPC trade modal
   */

  let modal = gameClient.interface.modalManager.get("offer-modal");

  if (modal) {
    modal.showFeedback(message);
  }

  let shopModal = gameClient.interface.modalManager.get("shop-modal");

  if (shopModal) {
    shopModal.showFeedback(message);
  }

}

PacketHandler.prototype.handleShopOffer = function (packet) {

  /*
   * Function PacketHandler.handleShopOffer
   * Handles incoming cosmetic shop offer packet — opens the shop modal
   */

  if (packet.offers.length === 0) {
    gameClient.interface.npcDialog.clearState();
    gameClient.interface.npcDialog.hide();
    gameClient.interface.modalManager.close();
    return;
  }

  gameClient.interface.npcDialog.hide();
  gameClient.interface.modalManager.open("shop-modal", packet);

}

PacketHandler.prototype.handleShopPointUpdate = function (points) {

  /*
   * Function PacketHandler.handleShopPointUpdate
   * Updates the point display in the shop modal after a purchase
   */

  let modal = gameClient.interface.modalManager.get("shop-modal");

  if (modal) {
    modal.updatePoints(points);
  }

}

PacketHandler.prototype.handleTravelOffer = function (packet) {

  /*
   * Function PacketHandler.handleTravelOffer
   * Handles incoming packet to open the NPC travel destination modal.
   * An empty route list signals the NPC ended the conversation — close the modal.
   */

  if (packet.routes.length === 0) {
    gameClient.interface.npcDialog.clearState();
    gameClient.interface.npcDialog.hide();
    gameClient.interface.modalManager.close();
    return;
  }

  // Hide NPC dialog while travel modal is open
  gameClient.interface.npcDialog.hide();
  gameClient.interface.modalManager.open("travel-modal", packet)

}

PacketHandler.prototype.handlePlayerStatistics = function (packet) {

  /*
   * Function PacketHandler.handlePlayerStatistics
   * Handles a change capacity packet
   */

  // Ignore these packets
  if (gameClient.player === null) {
    return;
  }

  // Update the character state
  gameClient.player.state.capacity = packet.capacity;
  gameClient.player.state.attack = packet.attack;
  gameClient.player.state.armor = packet.armor;
  gameClient.player.state.speed = packet.speed;

}

