PacketHandler.prototype.handleAddAchievement = function (packet) {

  /*
   * Function PacketHandler.handleAddAchievement
   * Handles incoming packet to send a distance effect from a position to a position
   */

  setTimeout(function () {
    document.getElementById("achievement").innerHTML = packet.title + "<hr>" + packet.description;
    document.getElementById("achievement").className = "canvas-notification visible";
  }, 1000);

  setTimeout(function () {
    document.getElementById("achievement").className = "canvas-notification hidden";
  }, 2000);

}

PacketHandler.prototype.handleSendDistanceEffect = function (packet) {

  /*
   * Function PacketHandler.handleSendDistanceEffect
   * Handles incoming packet to send a distance effect from a position to a position
   */

  // Skip distance effects where neither endpoint is visible
  if (gameClient.player) {
    let canSeeFrom = gameClient.player.canSee({ getPosition: () => packet.from });
    let canSeeTo = gameClient.player.canSee({ getPosition: () => packet.to });
    if (!canSeeFrom && !canSeeTo) {
      return;
    }
  }

  gameClient.renderer.addDistanceAnimation(packet);

  // Bow draw animation: player leans back then snaps forward when firing a physical projectile
  // Use distance <= 1 to handle mid-walk position mismatch
  let sp = gameClient.player.getPosition();
  if (Math.abs(sp.x - packet.from.x) <= 1 && Math.abs(sp.y - packet.from.y) <= 1 && sp.z === packet.from.z) {
    let t = packet.type;
    let isPhysical = t === CONST.EFFECT.PROJECTILE.SPEAR || t === CONST.EFFECT.PROJECTILE.BOLT ||
      t === CONST.EFFECT.PROJECTILE.ARROW || t === CONST.EFFECT.PROJECTILE.POISONARROW ||
      t === CONST.EFFECT.PROJECTILE.BURSTARROW || t === CONST.EFFECT.PROJECTILE.THROWINGSTAR ||
      t === CONST.EFFECT.PROJECTILE.THROWINGKNIFE || t === CONST.EFFECT.PROJECTILE.SMALLSTONE ||
      t === CONST.EFFECT.PROJECTILE.LARGEROCK || t === CONST.EFFECT.PROJECTILE.POWERBOLT ||
      // 8.0 physical projectiles
      t === CONST.EFFECT.PROJECTILE.INFERNALBOLT || t === CONST.EFFECT.PROJECTILE.HUNTINGSPEAR ||
      t === CONST.EFFECT.PROJECTILE.ENCHANTEDSPEAR || t === CONST.EFFECT.PROJECTILE.REDSTAR ||
      t === CONST.EFFECT.PROJECTILE.GREENSTAR || t === CONST.EFFECT.PROJECTILE.ROYALSPEAR ||
      t === CONST.EFFECT.PROJECTILE.SNIPERARROW || t === CONST.EFFECT.PROJECTILE.ONYXARROW ||
      t === CONST.EFFECT.PROJECTILE.PIERCINGBOLT;
    if (isPhysical) {
      let dx = packet.to.x - sp.x;
      let dy = packet.to.y - sp.y;
      let len = Math.sqrt(dx * dx + dy * dy) || 1;
      let ndx = dx / len;
      let ndy = dy / len;
      gameClient.player.__bowDraw = { start: performance.now(), ndx: ndx, ndy: ndy };
    }
  }

}

PacketHandler.prototype.handleSendMagicEffect = function (packet) {

  /*
   * Function PacketHandler.handleSendMagicEffect
   * Handles incoming packet to send a magic effect to a position
   */

  // Skip effects outside the visible screen
  if (gameClient.player && !gameClient.player.canSee({ getPosition: () => packet.position })) {
    return;
  }

  gameClient.renderer.addPositionAnimation(packet);

  // Block/parry spark: trigger on POFF or BLOCKHIT effects
  if (packet.type === CONST.EFFECT.MAGIC.POFF || packet.type === CONST.EFFECT.MAGIC.BLOCKHIT) {
    let sparkPos = packet.position;
    let sparkTile = gameClient.world.getTileFromWorldPosition(sparkPos);
    let sparkCreature = null;
    if (sparkTile && sparkTile.monsters.size > 0) {
      sparkTile.monsters.forEach(function(c) {
        if (!sparkCreature && c !== gameClient.player) sparkCreature = c;
      });
    }
    if (sparkCreature) {
      sparkCreature.__blockSpark = { start: performance.now() };
    } else {
      gameClient.renderer.__activeBlockSparks.push({ start: performance.now(), worldPos: sparkPos });
    }
  }

  // Ranged flinch: when a damage effect appears on a creature from ranged distance
  let dmgEffect = packet.type === CONST.EFFECT.MAGIC.DRAWBLOOD ||
    packet.type === CONST.EFFECT.MAGIC.HITBYFIRE ||
    packet.type === CONST.EFFECT.MAGIC.HITBYPOISON ||
    packet.type === CONST.EFFECT.MAGIC.ENERGYHIT ||
    packet.type === CONST.EFFECT.MAGIC.LOSEENERGY ||
    packet.type === CONST.EFFECT.MAGIC.MORTAREA;
  if (dmgEffect) {
    let sp = gameClient.player.getPosition();
    let px = packet.position.x;
    let py = packet.position.y;
    // Only for non-adjacent positions (ranged attacks)
    if (Math.abs(px - sp.x) > 1 || Math.abs(py - sp.y) > 1) {
      let dx = px - sp.x;
      let dy = py - sp.y;
      let len = Math.sqrt(dx * dx + dy * dy) || 1;
      let ndx = dx / len;
      let ndy = dy / len;
      // Check effect tile + adjacent tiles (creature may have moved mid-walk)
      let offsets = [[0,0],[-1,0],[1,0],[0,-1],[0,1]];
      let hit = false;
      for (let oi = 0; oi < offsets.length; oi++) {
        let checkPos = new Position(px + offsets[oi][0], py + offsets[oi][1], packet.position.z);
        let tile = gameClient.world.getTileFromWorldPosition(checkPos);
        if (!tile || tile.monsters.size === 0) continue;
        tile.monsters.forEach(function(c) {
          if (c !== gameClient.player && !hit) {
            hit = true;
            c.__flinch = { start: performance.now() };
            let color = PacketHandler.prototype.__getCreatureBloodColor(c);
            let particles = [];
            for (let i = 0; i < 16; i++) {
              let spread = (Math.random() - 0.5) * 1.2;
              particles.push({
                vx: ndx * (2 + Math.random() * 3) + spread,
                vy: ndy * (2 + Math.random() * 3) + spread,
                size: 1 + Math.random() * 1.5
              });
            }
            c.__weaponTrail = { start: performance.now(), particles: particles, ndx: ndx, ndy: ndy, color: color };
          }
        });
        if (hit) break;
      }
    }
  }

}

