PacketHandler.prototype.handleEmote = function (packet) {

  let sourceCreature = gameClient.world.getCreature(packet.id);

  if (sourceCreature === null) {
    // Self-heal for missed CreatureStatePacket (see __selfHealForUnknownCreature).
    // This is the "damage number from nothing" case — emote fires for a
    // hidden attacker so we ask the server to re-send our visible chunks.
    PacketHandler.prototype.__selfHealForUnknownCreature(packet.id, null, "emote");
    return;
  }

  gameClient.interface.screenElementManager.createFloatingTextElement(
    "<i>%s</i>".format(packet.message),
    sourceCreature.getPosition(),
    packet.color
  );

  // Melee hit effect: blood splatter + stagger + attacker lunge (adjacent only)
  if (gameClient.player.isCreatureTarget(sourceCreature) && sourceCreature !== gameClient.player) {
    let sp = gameClient.player.getPosition();
    let tp = sourceCreature.getPosition();
    let dx = tp.x - sp.x;
    let dy = tp.y - sp.y;

    // Only trigger for melee range (Chebyshev distance <= 1)
    if (Math.abs(dx) <= 1 && Math.abs(dy) <= 1) {
      let len = Math.sqrt(dx * dx + dy * dy) || 1;
      let ndx = dx / len;
      let ndy = dy / len;

      // Determine particle color based on creature type
      let color = PacketHandler.prototype.__getCreatureBloodColor(sourceCreature);

      // Generate blood particles flying in the attack direction
      let particles = [];
      for (let i = 0; i < 24; i++) {
        let spread = (Math.random() - 0.5) * 1.2;
        particles.push({
          vx: ndx * (2 + Math.random() * 3) + spread,
          vy: ndy * (2 + Math.random() * 3) + spread,
          size: 1 + Math.random() * 1.5
        });
      }
      sourceCreature.__weaponTrail = { start: performance.now(), particles: particles, ndx: ndx, ndy: ndy, color: color };

      // Attacker lunge: player briefly lunges toward the target
      gameClient.player.__attackLunge = { start: performance.now(), ndx: ndx, ndy: ndy };

      // Slash arc between player and target
      gameClient.renderer.__activeSlashArcs.push({
        start: performance.now(),
        worldPos: sp,
        ndx: ndx,
        ndy: ndy
      });
    }
  }

}


PacketHandler.prototype.handleIncreaseHealth = function (packet) {

  /*
   * Function PacketHandler.handleIncreaseHealth
   * Handles an increase health packet from the server
   */

  // Get the creature this applies to
  let sourceCreature = gameClient.world.getCreature(packet.id);

  if (sourceCreature === null) {
    return;
  }

  // Limit the health addition to the maximum player health
  let health = Math.min(packet.amount, sourceCreature.maxHealth - sourceCreature.state.health);

  if (health === 0) {
    return;
  }

  // Increase the creature health
  sourceCreature.increaseHealth(health);

  // Add a floating text element
  gameClient.interface.screenElementManager.createFloatingTextElement(
    health,
    sourceCreature.getPosition(),
    Interface.prototype.COLORS.LIGHTGREEN
  );

  // If self: add a message to the console
  if (gameClient.player === sourceCreature) {

    gameClient.interface.channelManager.addConsoleMessage(
      "You heal for %s health.".format(health),
      gameClient.interface.COLORS.WHITE
    );

  }

}

