PacketHandler.prototype.handleSkullUpdate = function (packet) {

  /*
   * Function PacketHandler.handleSkullUpdate
   * Handles an incoming skull update packet for a creature
   */

  let creature = gameClient.world.getCreature(packet.id);

  if (creature === null) {
    return;
  }

  creature.skull = packet.skull;

  // Update the skull icon on the character element
  if (creature.characterElement) {
    creature.characterElement.setSkull(packet.skull);
  }

}

PacketHandler.prototype.handleShieldUpdate = function (packet) {

  /*
   * Function PacketHandler.handleShieldUpdate
   * Handles an incoming shield update packet for a creature (party shields)
   */

  let creature = gameClient.world.getCreature(packet.id);

  if (creature === null) {
    return;
  }

  creature.shield = packet.shield;

  // Update the shield icon on the character element
  if (creature.characterElement) {
    creature.characterElement.setShield(packet.shield);
  }

  // If the player themselves just lost their party shield (kicked,
  // disbanded, last member left), refresh any open Party modal so the
  // stale "Leave Party" button doesn't sit there pointing at a party
  // that no longer exists. Server will respond to the resend with a
  // fresh not-in-party payload and the modal will re-render empty.
  if (creature === gameClient.player && packet.shield === CONST.SHIELD.NONE) {
    let modal = gameClient.interface.modalManager.get("party-info-modal");
    if (modal && modal.element && modal.element.style.display !== "none") {
      // Re-request the current party state so the modal updates in place.
      gameClient.send(new ChannelMessagePacket(0x00, 0, "/party"));
    }
  }

}

PacketHandler.prototype.handlePartyInvite = function (packet) {

  /*
   * Function PacketHandler.handlePartyInvite
   * Handles an incoming party invite notification
   */

  // Store the inviter's creature ID so the context menu can show "Join Party"
  gameClient.player.__pendingPartyInvite = packet.inviterId;

}


