const ItemMovePacket = function (fromThing, toThing, count) {

  /*
   * Class ItemMovePacket
   * Wrapper for an item move packet. Includes the source item's CID
   * so the server can verify the correct item is being moved (prevents
   * desync when rapidly dragging items between containers).
   */

  PacketWriter.call(this, CONST.PROTOCOL.CLIENT.THING_MOVE, 19);

  this.__writeGenericMove(fromThing);
  this.__writeGenericMove(toThing);
  this.writeUInt8(count);

  // Append the CID of the source item for server-side slot verification
  let item = fromThing.which.peekItem ? fromThing.which.peekItem(fromThing.index) : null;
  this.writeUInt16(item ? item.id : 0);

}

