/*
 * Per-Instance Tint ID Map
 * Maps tintId (per-item byte) to RGB tint multipliers.
 * Used for cosmetic weapon tinting (Mining crafting).
 */
var TINT_ID_MAP = {
  1: { r: 1.3, g: 0.9, b: 0.6 },   // Copper cosmetic
  2: { r: 1.1, g: 0.9, b: 0.7 },   // Bronze cosmetic
  3: { r: 1.4, g: 1.4, b: 1.5 },   // Silver cosmetic
  4: { r: 1.5, g: 1.3, b: 0.4 },   // Golden cosmetic
  5: { r: 1.3, g: 1.1, b: 0.7 },   // Oak wood — warm light brown
  6: { r: 0.8, g: 0.5, b: 0.4 },   // Mahogany wood — rich dark red-brown
  7: { r: 0.5, g: 0.4, b: 0.4 },   // Ebony wood — near black
  8: { r: 1.5, g: 0.5, b: 0.5 },   // Red
  9: { r: 0.5, g: 0.6, b: 1.5 },   // Blue
  10: { r: 0.5, g: 1.4, b: 0.5 },  // Green
  11: { r: 1.3, g: 0.5, b: 1.4 },  // Purple
  12: { r: 0.6, g: 1.3, b: 1.5 },  // Ice / Cyan
  13: { r: 1.5, g: 0.5, b: 0.8 },  // Pink
  14: { r: 1.5, g: 1.5, b: 1.5 },  // White / Bright
  15: { r: 0.4, g: 0.4, b: 0.4 }   // Black / Dark
};

/*
 * Glow Outline Color Map
 * Maps glow ID (0-15) to CSS-ready RGB strings for the outline effect.
 * Glow ID is encoded in the high nibble of the tintId byte (bits 4-7).
 */
var GLOW_COLOR_MAP = {
  1: "rgb(200,140,60)",     // Copper
  2: "rgb(170,140,100)",    // Bronze
  3: "rgb(200,200,220)",    // Silver
  4: "rgb(220,190,50)",     // Golden
  5: "rgb(200,170,100)",    // Oak
  6: "rgb(140,80,60)",      // Mahogany
  7: "rgb(80,60,60)",       // Ebony
  8: "rgb(220,60,60)",      // Red
  9: "rgb(60,80,220)",      // Blue
  10: "rgb(60,200,60)",     // Green
  11: "rgb(180,60,200)",    // Purple
  12: "rgb(80,200,220)",    // Ice / Cyan
  13: "rgb(220,80,140)",    // Pink
  14: "rgb(230,230,230)",   // White
  15: "rgb(60,60,60)"       // Black / Dark
};

function getItemTint(sid, tintId) {

  /*
   * Function getItemTint
   * Returns the tint object { r, g, b } for a given SID/tintId, or null if no tint.
   * Per-instance tintId takes priority over SID-based tints.
   * tintId byte: low nibble (bits 0-3) = tint color, high nibble (bits 4-7) = glow color.
   */

  let tintColor = tintId & 0x0F;

  if (tintColor && TINT_ID_MAP.hasOwnProperty(tintColor)) {
    return TINT_ID_MAP[tintColor];
  }

  if (!sid || !ITEM_TINT_MAP.hasOwnProperty(sid)) {
    return null;
  }

  return ITEM_TINT_MAP[sid];

}

function getItemGlow(tintId) {

  /*
   * Function getItemGlow
   * Returns the CSS RGB string for the glow outline, or null if no glow.
   * Glow ID is encoded in the high nibble of the tintId byte.
   */

  let glowColor = (tintId >> 4) & 0x0F;

  if (glowColor && GLOW_COLOR_MAP.hasOwnProperty(glowColor)) {
    return GLOW_COLOR_MAP[glowColor];
  }

  return null;

}


