"use strict";

const LightCanvas = function(id, width, height) {

  /*
   * Class LightCanvas
   * Container for a canvas that handles lighting
   */

  // Inherits from canvas
  Canvas.call(this, id, width, height);

  // Current state of the light canvas and start, target for interpolation
  this.__ambientColor = new RGBA(0, 0, 0, 0);
  this.__ambientColorTarget = new RGBA(0, 0, 0, 0);
  this.__ambientColorStart = new RGBA(0, 0, 0, 0);

  this.__counter = 0;
  this.__steps = 0;

  // Per-frame cached values for 2D lighting performance
  this.__cachedDarkFrac = 0;
  this.__cachedIntensity = 0;
  this.__prevIntensity = -1;

  // Pre-rendered light bubble textures keyed by colorByte
  this.__lightTextureCache = new Map();

}

LightCanvas.prototype = Object.create(Canvas.prototype);
LightCanvas.prototype.constructor = LightCanvas;

// Darkness is black
LightCanvas.prototype.DARKNESS = new RGBA(0, 0, 0, 255);

// Resolution of pre-rendered light bubble textures
LightCanvas.prototype.LIGHT_TEXTURE_SIZE = 128;

LightCanvas.prototype.setAmbientColor = function(r, g, b, a) {

  /*
   * Function LightCanvas.setAmbientColor
   * Sets a new ambient color for the lightscreen: we interpolate from the old color over some frames
   */

  // Store the start and target of the transition
  this.__ambientColorTarget = new RGBA(r, g, b, a);
  this.__ambientColorStart = this.__ambientColor.copy();

  // Determine the length of transition (number of ticks to go from color one to another)
  let f1 = Math.abs(this.__ambientColorStart.r - this.__ambientColorTarget.r);
  let f2 = Math.abs(this.__ambientColorStart.g - this.__ambientColorTarget.g);
  let f3 = Math.abs(this.__ambientColorStart.b - this.__ambientColorTarget.b);
  let f4 = Math.abs(this.__ambientColorStart.a - this.__ambientColorTarget.a);

  // Reset the state
  this.__steps = 2 * Math.max(f1, f2, f3, f4);
  this.__counter = this.__steps;

}

LightCanvas.prototype.getNightSine = function() {

  /*
   * Function LightCanvas.getNightSine
   * Returns the fraction of the night proportion. Nights are simulated using a sine-wave from -1 to 1 over a particular period
   */

  // Read the world time from the clock
  let unix = gameClient.world.clock.getUnix();

  // Offset by PI/2 so darkest=midnight, brightest=noon
  return Math.sin(0.5 * Math.PI + (2 * Math.PI * unix / (24 * 60 * 60 * 1000)));

}

LightCanvas.prototype.getDarknessFraction = function() {

  /*
   * Function LightCanvas.getDarknessFraction
   * Returns the night fraction
   */

  // Simulate the day & night cycle
  let fraction = Math.min(0.6, 0.5 * (this.getNightSine() + 1));

  // Underground is darker but not pitch black
  if(gameClient.player.isUnderground()) {
    fraction = 0.8;
  }

  return fraction;

}

LightCanvas.prototype.getInterpolationFraction = function() {

  /*
   * Function LightCanvas.getInterpolationFraction
   * Returns the fraction we are currently interpolating
   */

  return (this.__counter - 1) / this.__steps;

}

LightCanvas.prototype.setup = function() {

  /*
   * Function LightCanvas.setup
   * Sets up the light canvas for drawing (2D canvas mode)
   */

  // Clear lightscreen and create ambient color
  this.context.clearRect(0, 0, this.canvas.width, this.canvas.height);
  this.context.globalCompositeOperation = "source-over";

  // We are busy interpolating still
  if(this.__counter > 0) {
    this.__ambientColor = this.__ambientColorTarget.interpolate(this.__ambientColorStart, this.getInterpolationFraction());
    this.__counter--;
  }

  // Interpolate with complete darkness to simulate night (uses per-frame cached value)
  let color = this.__ambientColor.interpolate(this.DARKNESS, this.__cachedDarkFrac);

  this.context.fillStyle = color.toString();
  this.context.fillRect(0, 0, this.canvas.width, this.canvas.height);

  // Punch light holes through the darkness — overlapping lights clamp naturally
  this.context.globalCompositeOperation = "destination-out";

}

LightCanvas.prototype.setupInterpolation = function() {

  /*
   * Function LightCanvas.setupInterpolation
   * Updates only the ambient color interpolation state (no canvas rendering)
   * Used by WebGL FBO lighting path where 2D canvas is not needed
   */

  if(this.__counter > 0) {
    this.__ambientColor = this.__ambientColorTarget.interpolate(this.__ambientColorStart, this.getInterpolationFraction());
    this.__counter--;
  }

}

LightCanvas.prototype.invalidateTextureCache = function() {

  /*
   * Function LightCanvas.invalidateTextureCache
   * Clears light textures when intensity changes (day/night transition)
   */

  // Quantize intensity to avoid thrashing during slow transitions
  let key = Math.round(this.__cachedIntensity * 100);

  if(key !== this.__prevIntensity) {
    this.__lightTextureCache.clear();
    this.__prevIntensity = key;
  }

}

LightCanvas.prototype.__getLightTexture = function(colorByte, intensity) {

  /*
   * Function LightCanvas.__getLightTexture
   * Returns a pre-rendered light bubble texture for a given color byte and intensity.
   * Creates the texture once and caches it — avoids per-light gradient creation.
   */

  // Composite cache key: colorByte + quantized intensity
  let cacheKey = colorByte * 1000 + Math.round(intensity * 100);
  let cached = this.__lightTextureCache.get(cacheKey);

  if(cached !== undefined) {
    return cached;
  }

  let size = this.LIGHT_TEXTURE_SIZE;
  let half = size / 2;

  // Create offscreen canvas for this light color
  let offscreen = document.createElement("canvas");
  offscreen.width = size;
  offscreen.height = size;
  let ctx = offscreen.getContext("2d");

  // Desaturate light color 75% toward white — keeps subtle warmth without heavy yellow tint
  let r0 = 51 * (parseInt(colorByte / 36) % 6);
  let g0 = 51 * (parseInt(colorByte / 6) % 6);
  let b0 = 51 * (parseInt(colorByte % 6));
  let lum = Math.max(r0, g0, b0);
  let r = Math.round(r0 * 0.66 + lum * 0.34);
  let g = Math.round(g0 * 0.66 + lum * 0.34);
  let b = Math.round(b0 * 0.66 + lum * 0.34);

  let a1 = Math.floor(lum * intensity);
  let a2 = Math.floor(a1 * 0.75);
  let a3 = Math.floor(a1 * 0.45);
  let a4 = Math.floor(a1 * 0.15);

  // Create radial gradient — mostly white with a hint of the original light color
  let grad = ctx.createRadialGradient(half, half, 0, half, half, half);
  grad.addColorStop(0.00, "rgba(" + r + "," + g + "," + b + "," + (a1 / 255) + ")");
  grad.addColorStop(0.30, "rgba(" + r + "," + g + "," + b + "," + (a2 / 255) + ")");
  grad.addColorStop(0.55, "rgba(" + r + "," + g + "," + b + "," + (a3 / 255) + ")");
  grad.addColorStop(0.80, "rgba(" + r + "," + g + "," + b + "," + (a4 / 255) + ")");
  grad.addColorStop(1.00, "rgba(0,0,0,0)");

  ctx.fillStyle = grad;
  ctx.fillRect(0, 0, size, size);

  this.__lightTextureCache.set(cacheKey, offscreen);

  return offscreen;

}

LightCanvas.prototype.renderLightBubble = function(x, y, size, colorByte, intensityOverride) {

  /*
   * Function LightCanvas.renderLightBubble
   * Renders a particular light bubble using a pre-rendered texture
   * intensityOverride: optional absolute intensity (replaces __cachedIntensity when provided)
   */

  // Invalid input
  if(colorByte < 0 || colorByte >= 216) {
    return;
  }

  // Scale to the gamescreen
  x = 32 * x + 32;
  y = 32 * y + 32;
  size *= 32;

  // Use override intensity when provided, otherwise default cached value
  let intensity = (intensityOverride !== undefined && intensityOverride !== null) ? intensityOverride : this.__cachedIntensity;

  // Get or create the pre-rendered texture for this color and intensity
  let tex = this.__getLightTexture(colorByte, intensity);

  // Stamp the pre-rendered bubble scaled to the correct size
  let diameter = size * 2;
  this.context.drawImage(tex, x - size, y - size, diameter, diameter);

}


/* ===== FILE: https://minibia.com/src/rendering/minimap.js?v=1778114723415 ===== */

const Minimap = function () {

  /*
   * Class Minimap
   * Creates an off-screen canvas that holds the full minimap
   */

  this.minimap = new Canvas("minimap", 160, 160);

  // There are 16 minimap layers (8 above and 8 below ground)
  this.nLayers = 16;

  // Minimap state of the current zoom level and what layer is being renderer
  // Default to 1 zoom step on mobile for better visibility
  this.__zoomLevel = window.matchMedia("(max-width: 768px)").matches ? 1 : 0;
  this.__renderLayer = 7; // Default to surface level (Z=7)

  this.__imageBuffers = new Array();
  this.__currentIndex = null;

  // Current center of the minimap relative to the player character
  this.center = new Position(0, 0, 0);

  // Target position for visual marker (when autowalking)
  this.__targetPosition = null;

  this.addEventListeners();

}

Minimap.prototype.openLargeMap = function () {

  gameClient.interface.modalManager.open("map-modal");

}

Minimap.prototype.cache = function () {

  /*
   * Function Minimap.cache
   * Caches the required minimap chunks
   */

  let position = gameClient.player.getPosition();

  // Bounding rectangle for the minimap
  let upperWest = new Position(position.x - 80, position.y - 80, this.__renderLayer);
  let upper = new Position(position.x, position.y - 80, this.__renderLayer);
  let upperEast = new Position(position.x + 80, position.y - 80, this.__renderLayer);
  let east = new Position(position.x + 80, position.y, this.__renderLayer);
  let lowerEast = new Position(position.x + 80, position.y + 80, this.__renderLayer);
  let lower = new Position(position.x, position.y + 80, this.__renderLayer);
  let lowerWest = new Position(position.x - 80, position.y + 80, this.__renderLayer);
  let west = new Position(position.x - 80, position.y, this.__renderLayer);

  // Preemptively load the chunks
  gameClient.database.preloadCallback([position, upperWest, upper, upperEast, east, lowerEast, lower, lowerWest, west], this.chunkUpdate.bind(this));

}

Minimap.prototype.chunkUpdate = function (chunks) {

  /*
   * Function Minimap.chunkUpdate
   * Callback fired when a chunk needs to be updated
   */

  this.update(chunks);
  this.render(chunks);

}

Minimap.prototype.addEventListeners = function () {

  /*
   * Function Minimap.addEventListeners
   * Adds event listeners to the minimap
   */

  // Floor number button opens large map
  let layerBtn = document.getElementById("minimap-current-layer");
  layerBtn.innerHTML = "M";
  layerBtn.addEventListener("click", this.openLargeMap.bind(this));

  // Buttons to change the minimap zoom level state
  document.getElementById("minimap-zoom-up").addEventListener("click", this.changeZoomLevel.bind(this, 1));
  document.getElementById("minimap-zoom-down").addEventListener("click", this.changeZoomLevel.bind(this, -1));
  document.getElementById("minimap-zoom-el").addEventListener("click", this.changeLevel.bind(this, -1));
  document.getElementById("minimap-zoom-dl").addEventListener("click", this.changeLevel.bind(this, 1));

  // Listeners to the full canvas
  this.minimap.canvas.addEventListener("wheel", this.scroll.bind(this));

  // Left-click walks to location, right-click pans the minimap
  this.minimap.canvas.addEventListener("click", this.walkTo.bind(this));
  this.minimap.canvas.addEventListener("contextmenu", this.move.bind(this));

}

Minimap.prototype.setCenter = function () {

  /*
   * Function Minimap.setCenter
   * Resets the center of the minimap
   */

  this.center = new Position(0, 0, 0);

  this.setRenderLayer(gameClient.player.getPosition().z);

}

Minimap.prototype.__getCanvasCoordinates = function (event) {

  /*
   * Function Minimap.__getCanvasCoordinates
   * Converts CSS pixel coordinates to canvas internal coordinates
   * Needed because the canvas may be displayed at a different size than its internal resolution
   */

  let rect = this.minimap.canvas.getBoundingClientRect();
  let scaleX = this.minimap.canvas.width / rect.width;
  let scaleY = this.minimap.canvas.height / rect.height;

  return {
    x: (event.clientX - rect.left) * scaleX,
    y: (event.clientY - rect.top) * scaleY
  };

}

Minimap.prototype.move = function (event) {

  /*
   * Function Minimap.move
   * Sets the center of the minimap to a location
   */

  event.preventDefault();

  let coords = this.__getCanvasCoordinates(event);

  // The render loop upscales the minimap geometrically (×2 per zoom tick
  // via `drawImage(... -80,-80, 320,320)`), so canvas-pixels-per-world-tile
  // is 2^__zoomLevel, not the old arithmetic `(2*zoomLevel)+1`. The old
  // formula only matched at zoom 0; at every other level the pan/click
  // landed on the wrong world tile.
  let zoomScale = 1 << this.__zoomLevel;
  this.center.x += (coords.x - 80) / zoomScale;
  this.center.y += (coords.y - 80) / zoomScale;

  this.cache();

}

Minimap.prototype.walkTo = function (event) {

  /*
   * Function Minimap.walkTo
   * Initiates autowalk to the clicked position on the minimap
   */

  // Prevent context menu from appearing
  event.preventDefault();

  // Get player's current position
  let playerPos = gameClient.player.getPosition();

  // Convert CSS coordinates to canvas internal coordinates
  let coords = this.__getCanvasCoordinates(event);

  // Calculate the world position from minimap click
  // Account for zoom level and center offset. Scale is geometric
  // (2^zoomLevel) to match the render loop's drawImage upscaling.
  let zoomScale = 1 << this.__zoomLevel;
  let clickOffsetX = (coords.x - 80) / zoomScale;
  let clickOffsetY = (coords.y - 80) / zoomScale;

  // Calculate destination world position
  let destX = Math.floor(playerPos.x + this.center.x + clickOffsetX);
  let destY = Math.floor(playerPos.y + this.center.y + clickOffsetY);
  let destZ = this.__renderLayer;

  let destination = new Position(destX, destY, destZ);

  // Store target position for visual marker
  this.__targetPosition = destination;

  // Initiate pathfinding to the destination
  gameClient.world.pathfinder.findPath(playerPos, destination);

  // Redraw to show marker
  this.cache();

}

Minimap.prototype.scroll = function (event) {

  /*
   * Function Minimap.scroll
   * Scrolls the minimap with the scroll wheel
   */

  // Check the direction of the scrollwheel
  if (event.deltaY < 0) {
    this.changeZoomLevel(1);
  } else {
    this.changeZoomLevel(-1);
  }

}

Minimap.prototype.setRenderLayer = function (layer) {

  /*
   * Function Renderer.setRenderLayer
   * Sets the render layer
   */

  // Clamp the layer
  this.__renderLayer = Math.min(Math.max(0, layer), this.nLayers - 1);

  // Button always shows "M" now

  this.cache();

}

Minimap.prototype.changeLevel = function (level) {

  /*
   * Function Renderer.changeLevel
   * Changes the level
   */

  this.__renderLayer += level;
  this.setRenderLayer(this.__renderLayer);

}

Minimap.prototype.getMinimapBuffer = function (position) {

  return gameClient.database.getChunk(gameClient.database.getChunkIdentifier(position));

}


Minimap.prototype.update = function (chunks) {

  /*
   * Function Renderer.updateMinimap
   * Updates the minimap canvas
   */


  // Get the image data from the minimap buffer
  gameClient.world.chunks.forEach(function (chunk) {

    // Get the currently occupied layer
    let tiles = chunk.getFloorTiles(gameClient.player.getPosition().z);

    tiles.forEach(function (tile) {

      // Missing tile
      if (tile === null) {
        return;
      }

      // Cannot be viewed
      if (!gameClient.player.canSee(tile)) {
        return;
      }

      let color = this.__getTileColor(tile);

      if (color === null) {
        return;
      }

      // Calculate the buffer & index
      let buffer = chunks[gameClient.database.getChunkIdentifier(tile.getPosition())];
      let index = (tile.getPosition().x % 128) + ((tile.getPosition().y % 128) * 128);

      if (buffer) {
        buffer.view[index] = this.colors[color];
      }

    }, this);

  }, this);

}

Minimap.prototype.__getTileColor = function (tile) {

  /*
   * Function Minimap.__getTileColor
   * Returns the minimap color of a particular tile
   */

  // Perhaps check items
  let itemColors = tile.items.map(item => item.getMinimapColor()).filter(x => x !== null);

  // Return the color of the last item
  if (itemColors.length > 0) {
    return itemColors.last();
  }

  // Color of the tile then
  return tile.getMinimapColor();

}

Minimap.prototype.changeZoomLevel = function (value) {

  /*
   * Function Minimap.changeZoomLevel
   * Changes the state of the zoom level (clamped between 0 & 4) and renders the minimap
   */

  this.__zoomLevel += value;
  this.__zoomLevel = Math.min(Math.max(0, this.__zoomLevel), 4);

  this.cache();

}

Minimap.prototype.save = function () {

  gameClient.database.saveChunks();

}

Minimap.prototype.render = function (chunks) {

  /*
   * Function GameClient.renderMinimap
   * Renders the minimap to the screen
   */

  this.minimap.clear();

  // Go the active minimap chunks
  Object.keys(chunks).forEach(function (id) {

    let chunk = chunks[id];

    if (chunk === null) {
      return;
    }

    let [x, y, z] = id.split(".").map(Number);

    if (z !== this.__renderLayer) {
      return;
    }

    // And paste it at the right position on the minimap canvas
    this.minimap.context.putImageData(chunk.imageData, x * 128 - gameClient.player.getPosition().x + 80, y * 128 - gameClient.player.getPosition().y + 80);

  }, this);

  // Only save the new shape
  this.minimap.context.globalCompositeOperation = "copy";

  // Recursively scale the canvas to the appropriate zoom level
  for (let i = 0; i < this.__zoomLevel; i++) {
    this.minimap.context.drawImage(this.minimap.canvas, 0, 0, 160, 160, -80, -80, 320, 320);
  }

  // Draw target marker if there's an active destination
  this.__drawTargetMarker();

}

Minimap.prototype.__drawTargetMarker = function () {

  /*
   * Function Minimap.__drawTargetMarker
   * Draws a marker at the target position showing where player is walking to
   * Uses A* pathfinding on minimap colors to draw actual path
   */

  // Check if there's an active target (from pathfinder or local)
  let targetPos = this.__targetPosition || gameClient.world.pathfinder.__finalDestination;

  if (targetPos === null) {
    return;
  }

  // Clear target if player reached destination
  let playerPos = gameClient.player.getPosition();
  if (playerPos.x === targetPos.x && playerPos.y === targetPos.y && playerPos.z === targetPos.z) {
    this.__targetPosition = null;
    return;
  }

  // Only draw if on same floor
  if (targetPos.z !== this.__renderLayer) {
    return;
  }

  // Scale matches walkTo/move/render (geometric 2^zoomLevel).
  let zoomScale = 1 << this.__zoomLevel;

  // Calculate canvas positions (80 is center of 160px canvas)
  let targetCanvasX = 80 + (targetPos.x - playerPos.x - this.center.x) * zoomScale;
  let targetCanvasY = 80 + (targetPos.y - playerPos.y - this.center.y) * zoomScale;
  let playerCanvasX = 80 - this.center.x * zoomScale;
  let playerCanvasY = 80 - this.center.y * zoomScale;

  let ctx = this.minimap.context;

  // Reset composite operation for drawing on top
  ctx.globalCompositeOperation = "source-over";

  ctx.save();

  // Draw target marker (red X) only — the path-hint line was visually noisy
  // (orange dotted when minimap A* couldn't find a route) and not useful,
  // since the server-side pathfinder decides the actual walk route anyway.
  ctx.strokeStyle = "#FF0000";
  ctx.lineWidth = 2;
  ctx.setLineDash([]);
  ctx.beginPath();
  ctx.moveTo(targetCanvasX - 4, targetCanvasY - 4);
  ctx.lineTo(targetCanvasX + 4, targetCanvasY + 4);
  ctx.moveTo(targetCanvasX + 4, targetCanvasY - 4);
  ctx.lineTo(targetCanvasX - 4, targetCanvasY + 4);
  ctx.stroke();

  ctx.restore();

}

Minimap.prototype.__calculateMinimapPath = function (startX, startY, endX, endY, imageData, zoomScale) {

  /*
   * Function Minimap.__calculateMinimapPath
   * Calculates an A* path on the minimap using color data to determine walkability
   */

  // Step size based on zoom (larger steps for zoomed view)
  let step = Math.max(2, Math.floor(zoomScale));

  // Canvas dimensions
  let canvasWidth = 160;
  let canvasHeight = 160;

  // Convert to grid coordinates
  let gridStartX = Math.floor(startX / step);
  let gridStartY = Math.floor(startY / step);
  let gridEndX = Math.floor(endX / step);
  let gridEndY = Math.floor(endY / step);

  // Grid dimensions
  let gridWidth = Math.ceil(canvasWidth / step);
  let gridHeight = Math.ceil(canvasHeight / step);

  // Check if point is within bounds
  let isInBounds = function (x, y) {
    return x >= 0 && x < gridWidth && y >= 0 && y < gridHeight;
  };

  // Check if a grid cell is walkable based on minimap color
  let self = this;
  let isWalkable = function (gx, gy) {
    let canvasX = gx * step;
    let canvasY = gy * step;

    if (canvasX < 0 || canvasX >= canvasWidth || canvasY < 0 || canvasY >= canvasHeight) {
      return false;
    }

    let index = (canvasY * canvasWidth + canvasX) * 4;
    let r = imageData.data[index];
    let g = imageData.data[index + 1];
    let b = imageData.data[index + 2];
    let a = imageData.data[index + 3];

    return self.__isWalkableColor(r, g, b, a);
  };

  // Clamp to bounds
  gridStartX = Math.max(0, Math.min(gridWidth - 1, gridStartX));
  gridStartY = Math.max(0, Math.min(gridHeight - 1, gridStartY));
  gridEndX = Math.max(0, Math.min(gridWidth - 1, gridEndX));
  gridEndY = Math.max(0, Math.min(gridHeight - 1, gridEndY));

  // A* implementation
  let openSet = [];
  let closedSet = new Set();
  let cameFrom = new Map();
  let gScore = new Map();
  let fScore = new Map();

  let key = function (x, y) { return x + "," + y; };

  let heuristic = function (x1, y1, x2, y2) {
    return Math.abs(x1 - x2) + Math.abs(y1 - y2);
  };

  let startKey = key(gridStartX, gridStartY);
  gScore.set(startKey, 0);
  fScore.set(startKey, heuristic(gridStartX, gridStartY, gridEndX, gridEndY));
  openSet.push({ x: gridStartX, y: gridStartY, f: fScore.get(startKey) });

  // Direction vectors (8 directions)
  let directions = [
    { dx: 0, dy: -1 },  // N
    { dx: 1, dy: 0 },   // E
    { dx: 0, dy: 1 },   // S
    { dx: -1, dy: 0 },  // W
    { dx: 1, dy: -1 },  // NE
    { dx: 1, dy: 1 },   // SE
    { dx: -1, dy: 1 },  // SW
    { dx: -1, dy: -1 }  // NW
  ];

  let iterations = 0;
  let maxIterations = 2000; // Smaller for minimap

  while (openSet.length > 0 && iterations < maxIterations) {
    iterations++;

    // Get node with lowest fScore
    openSet.sort(function (a, b) { return a.f - b.f; });
    let current = openSet.shift();
    let currentKey = key(current.x, current.y);

    // Reached goal
    if (current.x === gridEndX && current.y === gridEndY) {
      // Reconstruct path
      let path = [];
      let pathKey = currentKey;

      while (pathKey) {
        let [px, py] = pathKey.split(",").map(Number);
        path.unshift({ x: px * step + step / 2, y: py * step + step / 2 });
        pathKey = cameFrom.get(pathKey);
      }

      return path;
    }

    closedSet.add(currentKey);

    // Check neighbors
    for (let i = 0; i < directions.length; i++) {
      let nx = current.x + directions[i].dx;
      let ny = current.y + directions[i].dy;
      let neighborKey = key(nx, ny);

      if (!isInBounds(nx, ny) || closedSet.has(neighborKey)) {
        continue;
      }

      if (!isWalkable(nx, ny)) {
        continue;
      }

      // Diagonal movement costs more
      let moveCost = (directions[i].dx !== 0 && directions[i].dy !== 0) ? 1.414 : 1;
      let tentativeG = gScore.get(currentKey) + moveCost;

      if (!gScore.has(neighborKey) || tentativeG < gScore.get(neighborKey)) {
        cameFrom.set(neighborKey, currentKey);
        gScore.set(neighborKey, tentativeG);
        let f = tentativeG + heuristic(nx, ny, gridEndX, gridEndY);
        fScore.set(neighborKey, f);

        // Check if already in openSet
        let inOpen = openSet.some(function (n) { return n.x === nx && n.y === ny; });
        if (!inOpen) {
          openSet.push({ x: nx, y: ny, f: f });
        }
      }
    }
  }

  // No path found - return empty array
  return [];

}

Minimap.prototype.__isWalkableColor = function (r, g, b, a) {

  /*
   * Function Minimap.__isWalkableColor
   * Determines if a minimap color represents a walkable tile
   */

  // Transparent or unexplored (black)
  if (a < 128 || (r === 0 && g === 0 && b === 0)) {
    return false;
  }

  let max = Math.max(r, g, b);
  let min = Math.min(r, g, b);
  let delta = max - min;

  // Very dark colors are usually obstacles
  if (max < 50) {
    return false;
  }

  // Check for red/orange hues (obstacles like walls)
  if (r > 150 && g < 100 && b < 100) {
    return false;
  }

  // Orange has high R, medium G, low B
  if (r > 180 && g > 50 && g < 150 && b < 80) {
    return false;
  }

  // Pure red (saturated)
  if (delta > 100 && r === max && r > 200 && g < 100) {
    return false;
  }

  // Gray colors (low saturation) are usually floors - walkable
  if (delta < 50 && max > 80) {
    return true;
  }

  // Bright green (#00FF00) is swamp/marsh - NOT walkable
  if (r === 0 && g === 255 && b === 0) {
    return false;
  }

  // Green colors (grass, nature) - walkable
  if (g > r && g > b && g > 100) {
    return true;
  }

  // Brown/tan colors (sand, dirt) - usually walkable
  if (r > b && g > b && max > 100) {
    return true;
  }

  // Blue colors could be water - not walkable
  if (b > r && b > g && b > 150) {
    return false;
  }

  // Default: if bright enough, consider walkable
  return max > 100;

}


