  gl.useProgram(this.__lightProgram);
  this.__lightUniforms = {
    "projection": gl.getUniformLocation(this.__lightProgram, "u_projection"),
    "gradient": gl.getUniformLocation(this.__lightProgram, "u_gradient")
  };

