  this.__lightVertexData = new Float32Array(256 * 6 * 7);

  this.__lightVao = gl.createVertexArray();
  gl.bindVertexArray(this.__lightVao);
  this.__lightVbo = gl.createBuffer();
  gl.bindBuffer(gl.ARRAY_BUFFER, this.__lightVbo);
  gl.bufferData(gl.ARRAY_BUFFER, this.__lightVertexData.byteLength, gl.DYNAMIC_DRAW);
  // position (2f)
  gl.enableVertexAttribArray(0);
  gl.vertexAttribPointer(0, 2, gl.FLOAT, false, 28, 0);
  // texcoord (2f)
  gl.enableVertexAttribArray(1);
  gl.vertexAttribPointer(1, 2, gl.FLOAT, false, 28, 8);
  // color (3f)
  gl.enableVertexAttribArray(2);
  gl.vertexAttribPointer(2, 3, gl.FLOAT, false, 28, 16);
  gl.bindVertexArray(null);

