  this.__overlayTexture = this.createTexture(canvas.width, canvas.height);
  this.__overlayTexWidth = canvas.width;
  this.__overlayTexHeight = canvas.height;

  // 2.5D post-processing (bloom + AO)
  this.__postFX = false;
  this.__bloomFBO = null;
  this.__bloomTexture = null;
  this.__bloomBlurFBO = null;
  this.__bloomBlurTexture = null;
  this.__bloomExtractProgram = null;
  this.__bloomBlurProgram = null;
  this.__bloomCompositeProgram = null;
