  gl.uniformMatrix3fv(this.__rectUniforms.projection, false, this.__projection);
  gl.uniform4f(this.__rectUniforms.color, r, g, b, a);

  gl.bindVertexArray(this.__rectVao);

  let rv = this.__rectVerts;
  rv[0] = x; rv[1] = y; rv[2] = x + w; rv[3] = y;
  rv[4] = x + w; rv[5] = y + h; rv[6] = x; rv[7] = y + h;
  gl.bindBuffer(gl.ARRAY_BUFFER, this.__rectVbo);
  gl.bufferSubData(gl.ARRAY_BUFFER, 0, rv);
