  "  vec4 E  = texture(u_source, tc);",
  "  vec4 F  = texture(u_source, tc + vec2( texel.x,  0.0));",
  "  vec4 H  = texture(u_source, tc + vec2( 0.0,  texel.y));",
  "",
  "  vec4 A  = texture(u_source, tc + vec2(-texel.x, -texel.y));",
  "  vec4 C  = texture(u_source, tc + vec2( texel.x, -texel.y));",
  "  vec4 G  = texture(u_source, tc + vec2(-texel.x,  texel.y));",
  "  vec4 I  = texture(u_source, tc + vec2( texel.x,  texel.y));",
