  "  vec4 B1 = texture(u_source, tc + vec2( 0.0,     -2.0*texel.y));",
  "  vec4 C1 = texture(u_source, tc + vec2( texel.x, -2.0*texel.y));",
  "",
  "  vec4 D0 = texture(u_source, tc + vec2(-2.0*texel.x, 0.0));",
  "  vec4 F4 = texture(u_source, tc + vec2( 2.0*texel.x, 0.0));",
  "",
  "  vec4 G5 = texture(u_source, tc + vec2(-texel.x,  2.0*texel.y));",
  "  vec4 H5 = texture(u_source, tc + vec2( 0.0,      2.0*texel.y));",
  "  vec4 I5 = texture(u_source, tc + vec2( texel.x,  2.0*texel.y));",
  "",
  "  // Edge detection weights",
  "  float edr  = weighted_distance(E,C,G,I,H5,F4,D0,B1) - weighted_distance(H,F,D,B,I5,C1,A,G5);",
  "  float edr2 = weighted_distance(E,C,G,I,H5,F4,D0,B1);",
  "  float edl  = weighted_distance(H,F,D,B,I5,C1,A,G5);",
