  "      }",
  "    }",
  "  }",
  "  // Top-right quadrant",
  "  else if (fp.x > 0.5 && fp.y < 0.5) {",
  "    float edrT = weighted_distance(E,C,G,I,B1,F4,D0,H5) - weighted_distance(B,F,D,H,C1,I5,G5,A);",
  "    if (edrT > 0.0 && !eq(B,F)) {",
