  "      if (diff(F,H) < diff(F,B)) {",
  "        color = mix(E, F, (fp.x - 0.5) * 1.4);",
  "      } else {",
  "        vec4 blend = mix(B, F, smoothstep(0.3, 0.7, dist_bf));",
