Interface.prototype.getSpell = function (id) {
  /*
   * Interface.getSpell
   * Returns client-side spell definitions for a spell with identifier id
   */

  if (!this.SPELLS.has(id)) {
    return new Object({
      name: "Unknown",
      description: "Unknown",
      icon: { x: 7, y: 10 },
    });
  }

  return this.SPELLS.get(id);
};

Interface.prototype.updateSpells = function (sid, mana, level) {
  /*
   * Interface.updateSpells
   * Updates information on spells that was returned from server
   * Overrides client-side mana and level with authoritative server values
   */

  let spell = this.SPELLS.get(sid);
  if (spell) {
    spell.mana = mana;
    spell.level = level;
  }

  gameClient.player.spellbook.addSpell(sid);
};

Interface.prototype.__openKeyRing = function (version) {
  gameClient.send(new KeyringOpenPacket());
};

Interface.prototype.enableVersionFeatures = function (version) {
  /*
   * Interface.enableVersionFeatures
   * Enables or disables version-specific features
   */

  // Disable addons when version is below 1000
  if (version <= 1000) {
    this.modalManager.get("outfit-modal").disableAddons();
  }
};

Interface.prototype.getHexColor = function (index) {
  /*
   * Function Interface.getHexColor
   * Returns the color from an identifier
   */

  // If invalid return white
  if (index < 0 || index >= this.WEBCOLORS.length) {
    return "#FFFFFF";
  }

  // Otherwise return the index
  return this.WEBCOLORS[index];
};

Interface.prototype.getAccountDetails = function () {
  /*
   * Function Interface.getACCountDetails
   * Returns the aCCount details from the DOM
   */

  return new Object({
    account: document.getElementById("user-username").value.trim(),
    password: document.getElementById("user-password").value.trim(),
  });
};

Interface.prototype.enterGame = function () {
  /*
   * Function Interface.enterGame
   * Callback fired when the enter game button is clicked
   */

  // Block if the assets are not yet loaded
  if (!this.areAssetsLoaded()) {
    return alert("The Tibia.spr and Tibia.dat must be loaded first.");
  }

  // Save or clear credentials based on "Remember me" checkbox
  let rememberMe = document.getElementById("remember-me").checked;
  if (rememberMe) {
    localStorage.setItem("remember-me", "true");
    localStorage.setItem("saved-account", document.getElementById("user-username").value.trim());
    localStorage.setItem("saved-password", document.getElementById("user-password").value.trim());
  } else {
    localStorage.removeItem("remember-me");
    localStorage.removeItem("saved-account");
    localStorage.removeItem("saved-password");
  }

  // Auto-fullscreen when launched from home screen (PWA bookmark)
  if (new URLSearchParams(window.location.search).has("pwa")) {
    var el = document.documentElement;
    var req = el.requestFullscreen || el.webkitRequestFullscreen || el.mozRequestFullScreen || el.msRequestFullscreen;
    if (req) req.call(el).catch(function(){});

    // Android Chrome PWA exits fullscreen on rotation — re-enter on the
    // user's next tap. requestFullscreen() needs a transient activation,
    // and pointerdown qualifies. Once-flag is per-attempt so we keep
    // re-arming after every rotation-driven exit.
    var __reentryArmed = false;
    var __armFullscreenReentry = function () {
      if (__reentryArmed) return;
      __reentryArmed = true;
      var onTap = function () {
        document.removeEventListener("pointerdown", onTap, true);
        __reentryArmed = false;
        var fsEl = document.fullscreenElement || document.webkitFullscreenElement;
        if (fsEl) return;   // already back in fullscreen somehow
        var r = el.requestFullscreen || el.webkitRequestFullscreen;
        if (r) r.call(el).catch(function(){});
      };
      document.addEventListener("pointerdown", onTap, true);
    };
    document.addEventListener("fullscreenchange", function () {
      if (!document.fullscreenElement) __armFullscreenReentry();
    });
    document.addEventListener("webkitfullscreenchange", function () {
      if (!document.webkitFullscreenElement) __armFullscreenReentry();
    });
  }

  // Disable login button to prevent double-clicks
  let loginBtn = document.getElementById("enter-game");
  loginBtn.disabled = true;
  loginBtn.textContent = "Logging in...";

  // Show the connecting message
  this.modalManager.open("floater-connecting", "Loading Account...");

  // Connect with the connection details
  gameClient.connect();
};

Interface.prototype.reset = function () {
  /*
   * Function Interface.reset
   * Resets the entire game interface to a clean state
   */

  // Hide any inventory/slot tooltip that was visible at logout.
  // Slot tooltips show on mouseover and hide on mouseout — but if the
  // player logs out while still hovering a slot, the slot DOM is torn
  // down before mouseout fires, leaving the tooltip stuck on screen
  // through the login flow. Force-hide here closes that gap.
  if (this.tooltip) {
    this.tooltip.hide();
  }

  // Clean up the interface
  this.screenElementManager.clear();

  this.windowManager.closeAll();

  // Close any modal that was left open when the connection ended so
  // it doesn't linger visually with stale state after re-login (e.g.
  // /house window sticking around and refusing to close).
  if (this.modalManager && this.modalManager.isOpened && this.modalManager.isOpened()) {
    this.modalManager.close();
  }

  // Remove all channels except Default (id 0) and Console (local) to prevent
  // guild/trade/world channels from leaking across character sessions
  for (let i = this.channelManager.channels.length - 1; i >= 0; i--) {
    let channel = this.channelManager.channels[i];
    if (channel.id === 0 || channel.constructor === LocalChannel) {
      channel.clear();
      continue;
    }
    // Remove DOM element
    if (channel.element && channel.element.parentNode) {
      channel.element.parentNode.remove();
    }
    this.channelManager.channels.splice(i, 1);
  }
  this.channelManager.setActiveChannel(0);

  // Show the game interface instead of the login box
  this.hideGameInterface();
};

Interface.prototype.enableEnterGame = function () {
  /*
   * Function Interface.enableEnterGame
   * Enables the enter game button if the sprites and data files are loaded
   */

  // Both are loaded: allow the character to enter the game
  if (this.areAssetsLoaded()) {
    let btn = document.getElementById("enter-game");
    btn.removeAttribute("disabled");
    btn.textContent = "Login";

    // Dismiss the launcher loading screen if it's still visible
    if (window.__launcherUI) {
      window.__launcherUI.dismiss();
      window.__launcherUI = null;
    }
  }
};

