Interface.prototype.hideGameInterface = function () {
  /*
   * Function Interface.hideGameInterface
   * Hides the game interface and shows the login interface
   */

  // Sets the login screen to hidden and opens the game interface
  document.getElementById("login-wrapper").style.display = "flex";
  document.getElementById("game-wrapper").style.display = "none";

  // Reset login button state
  let loginBtn = document.getElementById("enter-game");
  if (loginBtn) {
    loginBtn.disabled = false;
    loginBtn.textContent = "Login";
  }

  window.onresize();
};

Interface.prototype.showGameInterface = function () {
  /*
   * Function Interface.showGameInterface
   * Shows the game interface and hides the login interface with a smooth fade
   */

  let loginWrapper = document.getElementById("login-wrapper");
  let gameWrapper = document.getElementById("game-wrapper");

  // Start fade-out on the login screen
  loginWrapper.classList.add("fade-out");

  // After the fade completes, swap visibility
  setTimeout(function() {
    loginWrapper.style.display = "none";
    loginWrapper.classList.remove("fade-out");
    gameWrapper.style.display = "flex";

    // Defer resize until after the browser has laid out the newly-visible game wrapper.
    // Without this, getBoundingClientRect() can return stale/zero values on mobile,
    // causing the canvas to render uncentered until the next user interaction.
    requestAnimationFrame(function() {
      window.onresize();

      // Re-stack mobile panels now that the game wrapper is visible
      if (gameClient.touch && gameClient.touch.isMobileMode && gameClient.touch.__visiblePanels) {
        gameClient.touch.__stackPanels();
      }
    });
  }, 400);
};

Interface.prototype.loadGameFiles = function (event) {
  /*
   * Function Interface.loadGameFiles
   * Wrapper to load the Tibia .dat and .spr assets files from disk
   */

  // Go over the list of files
  Array.from(event.target.files).forEach(function (file) {
    console.debug("Loading asset %s from disk.".format(file.name));

    // Open a new filereader
    let reader = new FileReader();

    if (file.name === "Tibia.dat") {
      reader.addEventListener(
        "load",
        gameClient.dataObjects.load.bind(gameClient.dataObjects, file.name)
      );
    } else if (file.name === "Tibia.spr") {
      reader.addEventListener(
        "load",
        gameClient.spriteBuffer.load.bind(gameClient.spriteBuffer, file.name)
      );
    } else {
      return console.error(
        "Unknown asset file %s was selected.".format(file.name)
      );
    }

    // Read as a buffer for easy parsing
    return reader.readAsArrayBuffer(file);
  });
};

Interface.prototype.loadAssetCallback = function (which, filename) {
  /*
   * Function Interface.loadAssetCallback
   * Callback fired when .dat or .spr files are loaded
   */

  if (which === "sprite") {
    this.state.spritesLoaded = true;
    document.getElementById("sprites-loaded").style.color = "green";
    document.getElementById("sprites-loaded").innerHTML =
      filename + " (" + gameClient.spriteBuffer.__version + ")";
  } else if (which === "data") {
    this.state.dataLoaded = true;
    document.getElementById("data-loaded").style.color = "green";
    document.getElementById("data-loaded").innerHTML =
      filename + " (" + gameClient.dataObjects.__version + ")";
  }
};

Interface.prototype.requestFullScreen = function () {
  /*
   * Function Interface.requestFullScreen
   * Requests the game to go fullscreen in the browser
   */

  // The body must go fullscreen
  let element = document.body;

  // Supports most browsers and their versions.
  let requestMethod =
    element.requestFullScreen ||
    element.webkitRequestFullScreen ||
    element.mozRequestFullScreen ||
    element.msRequestFullScreen;

  if (requestMethod) {
    return requestMethod.call(element);
  }
};

Interface.prototype.isRaining = function () {
  /*
   * Function Interface.isRaining
   * Returns true if the game is raining
   */

  return gameClient.renderer.weatherCanvas.isRaining();
};
Interface.prototype.getSpriteScaling = function () {
  /*
   * Function Canvas.getSpriteScaling
   * Returns the sprite scaling: if the gamewindow is larger than default (480x352)
   * Mobile uses actual displayed canvas size, desktop uses resolution scale
   */

  // Check if we're in mobile mode
  let isMobile = gameClient.touch && gameClient.touch.isMobileMode;

  if (isMobile) {
    // Return cached value if available
    if (this.__cachedMobileScale !== null) {
      return this.__cachedMobileScale;
    }

    // Mobile: use actual displayed canvas size vs internal size
    let canvas = gameClient.renderer.screen.canvas;
    let displayedWidth = canvas.getBoundingClientRect().width;
    let internalWidth = canvas.width;
    let scale = displayedWidth / internalWidth;

    // Cache the result (32 * scale)
    this.__cachedMobileScale = 32 * scale;
    return this.__cachedMobileScale;
  }

  // Desktop: use the original resolution scale calculation
  return 32 * this.getResolutionScale();
};

Interface.prototype.getSpriteScalingVector = function () {
  /*
   * Function Interface.getSpriteScalingVector
   * Returns the sprite scaling in X and Y directions
   * Needed for mobile where the canvas might be stretched non-uniformly
   */

  // Check if we're in mobile mode
  let isMobile = gameClient.touch && gameClient.touch.isMobileMode;

  if (isMobile) {
    let canvas = gameClient.renderer.screen.canvas;
    let rect = canvas.getBoundingClientRect();

    // Calculate separate scales for Width and Height
    // Mobile CSS stretches to 100% width/height, potentially changing aspect ratio
    let scaleX = rect.width / canvas.width;
    let scaleY = rect.height / canvas.height;

    // Cache the result for stability if needed, but for now return raw
    // Note: If we need caching, we should cache both values
    // For now reusing the existing cache variable for the scalar (width) scale

    return {
      x: 32 * scaleX,
      y: 32 * scaleY
    };
  }

  // Desktop: uniform scaling
  let scale = 32 * this.getResolutionScale();
  return { x: scale, y: scale };
};

Interface.prototype.addAvailableResolutions = function () {
  /*
   * Function Interface.addAvailableResolutions
   * Adds the available resolutions to the option list
   */

  let selectElement = document.getElementById("resolution");

  // List of available resolutions (only added when available)
  let resolutions = new Array(
    { width: 800, height: 600 },
    { width: 960, height: 720 },
    { width: 1024, height: 768 },
    { width: 1152, height: 864 }
  );

  // Always add the default resolution
  let nodes = new Array(
    this.__createResolutionNode({ width: 480, height: 352 })
  );

  for (let resolution of resolutions) {
    let { width, height } = resolution;

    // The static resolution should fit within the available screen
    if (
      window.visualViewport.width - 360 < width ||
      window.visualViewport.height - 188 < height
    ) {
      break;
    }

    nodes.push(this.__createResolutionNode(resolution));
  }

  // Set to the maximum available resolution
  selectElement.replaceChildren(...nodes);
  selectElement.selectedIndex = selectElement.options.length - 1;
};

Interface.prototype.getResolutionScale = function () {
  /*
   * Function Interface.getResolutionScale
   * Returns the required scale of the game screen canvas
   *
   * Cache is invalidated by an integer version counter that bumps only
   * on events that actually change the scale: window/visualViewport
   * resize (handleResize) and the resolution dropdown / enable-resolution
   * checkbox (listeners attached in load(), which mirror handleResize).
   * The previous frame-keyed cache still incurred one visualViewport.width
   * read per frame (= ~6 ms/sec of forced-layout); a version counter
   * holds the cache for the entire session of stable viewport.
   */

  if (this.__cachedScaleVersion === this.__scaleInvalidationVersion) {
    return this.__cachedScale;
  }

  // Mobile mode: handle phone vs tablet differently
  let isMobile = gameClient.touch && gameClient.touch.isMobileMode;

  let result;
  if (isMobile) {

    let vw = window.visualViewport ? window.visualViewport.width : window.innerWidth;
    let vh = window.visualViewport ? window.visualViewport.height : window.innerHeight;

    // Tablet (large screen touch device): scale canvas uniformly to fit viewport
    // CSS removes width/height:100% stretch so transform is the only scaling
    if (vw > 600 && vh > 500) {

      // Stretch mode: CSS width/height 100% handles sizing, no transform needed
      if (document.body.classList.contains("canvas-stretch")) {
        result = 1;
      } else {
        let scaleX = vw / this.SCREEN_WIDTH_MIN;
        let scaleY = vh / this.SCREEN_HEIGHT_MIN;
        result = Math.max(1, Math.min(scaleX, scaleY));
      }
    } else {
      // Phone: return 1 — CSS width:100%/height:100% handles the stretching
      result = 1;
    }

  } else if (document.getElementById("enable-resolution").checked) {
    // Fixed resolution is requested
    result = Number(document.getElementById("resolution").value) / this.SCREEN_WIDTH_MIN;

  } else {
    // Dynamic resolution is requested (subtract interface elements)
    let scaleX = (window.visualViewport.width - 360) / this.SCREEN_WIDTH_MIN;
    let scaleY = (window.visualViewport.height - 188) / this.SCREEN_HEIGHT_MIN;
    result = Math.max(1, Math.min(scaleX, scaleY));
  }

  this.__cachedScaleVersion = this.__scaleInvalidationVersion || 0;
  this.__cachedScale = result;
  return result;
};

Interface.prototype.__handleStackResize = function () {
  // Previously this auto-closed the bottom container window in each column
  // whenever it overflowed the viewport. That was user-hostile: a tall
  // depot or backpack would vanish on any incidental resize (browser
  // chrome reflow, tooltip-driven layout pass, etc.), and the close
  // surprise made users think hovering itself was killing the window.
  //
  // The flex layout already handles overflow gracefully — `.column` uses
  // `flex-direction: column` with `overflow: hidden`, each `.window` is
  // `flex: 0 1 auto; min-height: 0`, and `.window > .body` has
  // `overflow-y: scroll`. When sibling windows compete for column space,
  // the bottom one shrinks and its body scrolls internally, so items
  // stay reachable. The server-side 5-container ceiling still trims the
  // oldest non-locked container on monster loot churn — that's the
  // legitimate auto-close path. The lock button remains useful for
  // surviving THAT, not for surviving viewport overflow.
};

Interface.prototype.handleResize = function (event) {
  /*
   * Function Interface.handleResize
   * Closes windows in the column if the window is resized
   */

  // Invalidate mobile + desktop scale caches
  this.__cachedMobileScale = null;
  this.__scaleInvalidationVersion = (this.__scaleInvalidationVersion || 0) + 1;

  // Guard against resize before renderer is initialized (e.g. during login screen)
  if (!gameClient.renderer || !gameClient.renderer.screen) {
    return;
  }

  // Get and set the resolution scale
  gameClient.renderer.screen.setScale(this.getResolutionScale());

  // We should update the wrapper size explicitly too
  let { width, height } =
    gameClient.renderer.screen.canvas.getBoundingClientRect();

  this.setElementDimensions(
    document.getElementById("canvas-id"),
    width,
    height
  );
  this.__handleStackResize();
};

Interface.prototype.setElementDimensions = function (elem, width, height) {
  /*
   * function Interface.setElementDimensions
   * Callback fired when the browser window is resized: make sure to keep the aspect ratio
   */

  // Update the dimensions in pixels
  elem.style.width = "%spx".format(Math.round(width));
  elem.style.height = "%spx".format(Math.round(height));
};

Interface.prototype.closeClient = function (event) {
  /*
   * Function GameClient.closeClient
   * Callback fired when the client is closed.
   */

  // Make sure to save the minimap
  gameClient.renderer.minimap.save();

  // Save the state of the settings to localstorage
  this.settings.saveState();
};

Interface.prototype.sendLogout = function () {
  /*
   * Function Interface.sendLogout
   * Writes a logout request to the server
   */

  // Confirm and write logout packet when confirming
  this.modalManager.open("confirm-modal", function () {
    // Block no logout zones (client-side check)
    if (gameClient.player.getTile().isNoLogoutZone()) {
      return gameClient.interface.setCancelMessage("You may not logout here.");
    }

    // Send logout request — the server will check combat state and either
    // close the socket (allowed) or send a cancel message (rejected)
    gameClient.networkManager.__intentionalClose = true;
    gameClient.send(new LogoutPacket());
  });
};

Interface.prototype.__createResolutionNode = function ({ width, height }) {
  /*
   * Function Interface.__createResolutionNode
   * Creates a select option for a particular game screen resolution (width, height)
   */

  // Only save the width as a value: we can calcualte the scale from it anyway
  let optionElement = document.createElement("option");
  optionElement.text = "%s × %s".format(width, height);
  optionElement.value = width;

  return optionElement;
};

Interface.prototype.__handleVisibiliyChange = function (event) {
  /*
   * Function Interface.handleVisibiliyChange
   * Callback fired when the window visibility changes
   */

  // Page became visible again — auto-reconnect if disconnected (mobile only)
  if (!document.hidden && gameClient.touch && gameClient.touch.isMobileMode && gameClient.networkManager.__wasConnected && !gameClient.networkManager.isConnected()) {
    gameClient.networkManager.reconnectNow();
    return;
  }

  // Must be connected to the gameserver
  if (!gameClient.networkManager.isConnected()) {
    return;
  }

  // Disable the keyboard when tabbing out: reset all active keys to prevent "hanging"
  gameClient.keyboard.setInactive();

  if (gameClient.renderer) {
    return gameClient.renderer.__handleVisibiliyChange(event);
  }
};

Interface.prototype.__handleResizeWindow = function () {
  /*
   * Function Interface.__handleResizeWindow
   * Called when the browser window is resized
   */

  // When resizing we have to re-calculate the available gamescreen resolutions that fit within the window
  this.addAvailableResolutions();

  // Handle resizing of the gamescreen
  this.handleResize();
};

Interface.prototype.__closeClientConfirm = function (event) {
  /*
   * Function Interface.__closeClientConfirm
   * Asks the client to confirm the browser close when connected
   */

  // Request confirmation from the client
  if (gameClient.isConnected()) {
    return true;
  }

  return;
};

Interface.prototype.__enableListeners = function () {
  /*
   * Function Interface.__enableListeners
   * All configured event listeners for the DOM
   */

  // These are buttons that open windows
  document
    .getElementById("openSkills")
    .addEventListener("click", this.toggleWindow.bind(this, "skill-window"));
  document
    .getElementById("openBattle")
    .addEventListener("click", this.toggleWindow.bind(this, "battle-window"));
  document
    .getElementById("openQuests")
    .addEventListener("click", this.modalManager.open.bind(this.modalManager, "quest-log-modal"));
  document
    .getElementById("openFriends")
    .addEventListener("click", this.toggleWindow.bind(this, "friend-window"));

  // The logout buttons (equipment panel + settings modal)
  document
    .getElementById("logout-button")
    .addEventListener("click", this.sendLogout.bind(this));
  document
    .getElementById("settings-logout-button")
    .addEventListener("click", this.sendLogout.bind(this));

  // The load asset button & delegator
  document
    .getElementById("load-assets")
    .addEventListener("click", this.loadAssetsDelegator);
  document
    .getElementById("asset-selector")
    .addEventListener("change", this.loadGameFiles.bind(this));

  // Resolution settings invalidate the getResolutionScale cache. Without
  // these the cache lives until window resize, so flipping the dropdown
  // wouldn't take effect on the running session.
  let invalidateScale = function () {
    this.__scaleInvalidationVersion = (this.__scaleInvalidationVersion || 0) + 1;
  }.bind(this);
  document.getElementById("resolution").addEventListener("change", invalidateScale);
  document.getElementById("enable-resolution").addEventListener("change", invalidateScale);
  document
    .getElementById("enter-game")
    .addEventListener("click", this.enterGame.bind(this));

  // Allow Enter key to trigger login from the login form
  let enterGameBound = this.enterGame.bind(this);
  document.getElementById("user-username").addEventListener("keydown", function(event) {
    if (event.key === "Enter") {
      event.preventDefault();
      enterGameBound();
    }
  });
  document.getElementById("user-password").addEventListener("keydown", function(event) {
    if (event.key === "Enter") {
      event.preventDefault();
      enterGameBound();
    }
  });

  // Allow Enter key to submit create account form
  ["create-username", "create-password", "create-name"].forEach(function(fieldId) {
    document.getElementById(fieldId).addEventListener("keydown", function(event) {
      if (event.key === "Enter") {
        event.preventDefault();
        gameClient.interface.modalManager.handleConfirm();
      }
    });
  });

  // Restore saved credentials if "Remember me" was checked
  if (localStorage.getItem("remember-me") === "true") {
    document.getElementById("remember-me").checked = true;
    document.getElementById("user-username").value = localStorage.getItem("saved-account") || "";
    document.getElementById("user-password").value = localStorage.getItem("saved-password") || "";
  }

  // Visibility change
  addEventListener("visibilitychange", this.__handleVisibiliyChange.bind(this));

  // Callback before the window is unloaded to close the client and terminate the client gracefully
  window.onbeforeunload = this.__closeClientConfirm.bind(this);
  window.onunload = this.closeClient.bind(this);
  window.onresize = this.__handleResizeWindow.bind(this);

  // iPad/iPhone: the OS screenshot thumbnail + Stage Manager / Split View can
  // change the visual viewport without firing window.resize. That leaves the
  // canvas drawing buffer sized for the old viewport → a strip of the screen
  // renders black until a rotation or scroll forces a full reflow. Listening
  // to visualViewport.resize closes that gap.
  // Gate: skip when the user is typing in an input — otherwise the iOS
  // soft-keyboard show/hide would re-size the canvas on every chat keystroke.
  if (window.visualViewport) {
    let self = this;
    window.visualViewport.addEventListener("resize", function () {
      let active = document.activeElement;
      if (active && (active.tagName === "INPUT" || active.tagName === "TEXTAREA" || active.isContentEditable)) return;
      self.__handleResizeWindow();
    });
  }
};


/* ===== FILE: https://minibia.com/src/ui/layout-editor.js?v=1778114738363 ===== */

const LayoutEditor = function () {

  /*
   * Class LayoutEditor
   * Manages mobile UI layout customization.
   * Allows users to drag and resize the joystick, hotbar, and chat button.
   */

  this.__active = false;
  this.__dragState = null;
  this.__currentOrientation = this.__getOrientation();
  this.__handles = [];
  this.__preEditState = null;
  this.__modifiedElements = new Set();

  // Element config: id used in storage, DOM element ID, display label
  this.__elementConfig = [
    { id: "joystick", domId: "mobile-joystick-zone", label: "Joystick" },
    { id: "hotbar", domId: "mobile-hotbar", label: "Hotbar" },
    { id: "chatBtn", domId: "mobile-chat-btn", label: "Chat" },
    { id: "pkLock", domId: "mobile-pk-lock-btn", label: "PvP" },
    { id: "hotbarPreset", domId: "mobile-hotbar-preset-btn", label: "Preset" },
    { id: "equipment", domId: "mobile-equipment-panel", label: "Equipment" },
    { id: "container", domId: "mobile-container-panel", label: "Container" },
    { id: "container2", domId: "mobile-container-panel-2", label: "Container 2" },
    { id: "extraHotbar", domId: "mobile-extra-hotbar", label: "Extra Hotbar" },
    { id: "skillWindow", domId: "skill-window", label: "Skills" },
    { id: "friendWindow", domId: "friend-window", label: "Friends" },
    { id: "minimap", domId: "minimap-container", label: "Minimap" }
  ];

  // Load saved layout
  this.__layout = this.__loadLayout();

  // Bind customize button
  let customizeBtn = document.getElementById("customize-layout-btn");
  if (customizeBtn) {
    customizeBtn.addEventListener("click", this.enter.bind(this));
  }

  // Bind toolbar buttons
  let saveBtn = document.getElementById("layout-save-btn");
  let resetBtn = document.getElementById("layout-reset-btn");
  let centerBtn = document.getElementById("layout-center-btn");
  let cancelBtn = document.getElementById("layout-cancel-btn");

  if (saveBtn) {
    saveBtn.addEventListener("click", this.exit.bind(this, true));
    saveBtn.addEventListener("touchend", function (e) { e.preventDefault(); this.exit(true); }.bind(this), { passive: false });
  }
  if (resetBtn) {
    resetBtn.addEventListener("click", this.reset.bind(this));
    resetBtn.addEventListener("touchend", function (e) { e.preventDefault(); this.reset(); }.bind(this), { passive: false });
  }
  if (centerBtn) {
    centerBtn.addEventListener("click", this.__toggleCenterMenu.bind(this));
    centerBtn.addEventListener("touchend", function (e) { e.preventDefault(); this.__toggleCenterMenu(); }.bind(this), { passive: false });
  }
  if (cancelBtn) {
    cancelBtn.addEventListener("click", this.exit.bind(this, false));
    cancelBtn.addEventListener("touchend", function (e) { e.preventDefault(); this.exit(false); }.bind(this), { passive: false });
  }

  // Listen for orientation changes and fullscreen toggle. Both `resize`
  // and `orientationchange` are registered because iOS Safari fires
  // them with different timings — `orientationchange` lands first with
  // stale innerWidth/innerHeight, then `resize` fires after the
  // viewport actually updates. Re-evaluating in both gives us one that
  // catches the new dimensions.
  let boundOrientationHandler = this.__handleOrientationChange.bind(this);
  window.addEventListener("resize", boundOrientationHandler);
  window.addEventListener("orientationchange", boundOrientationHandler);
  document.addEventListener("fullscreenchange", this.__handleFullscreenChange.bind(this));
  document.addEventListener("webkitfullscreenchange", this.__handleFullscreenChange.bind(this));

}

LayoutEditor.prototype.__isFullscreen = function () {

  /*
   * Function LayoutEditor.__isFullscreen
   * Returns true if the browser is in fullscreen mode
   */

  // Standard Fullscreen API
  if (document.fullscreenElement || document.webkitFullscreenElement || document.mozFullScreenElement || document.msFullscreenElement) {
    return true;
  }

  // iOS PWA: runs fullscreen via manifest but doesn't set fullscreenElement
  if (navigator.standalone || window.matchMedia("(display-mode: fullscreen)").matches || window.matchMedia("(display-mode: standalone)").matches) {
    return true;
  }

  return false;

}

LayoutEditor.prototype.enter = function () {

  /*
   * Function LayoutEditor.enter
   * Enter layout edit mode (only allowed in fullscreen)
   */

  if (this.__active) return;

  if (!this.__isFullscreen()) {
    let btn = document.getElementById("customize-layout-btn");
    if (btn) {
      let original = btn.textContent;
      btn.textContent = "Fullscreen required!";
      btn.style.color = "#ff4444";
      btn.style.animation = "none";
      btn.offsetHeight;
      btn.style.animation = "shake 0.4s ease";
      setTimeout(function () {
        btn.textContent = original;
        btn.style.color = "";
        btn.style.animation = "";
      }, 2000);
    }
    return;
  }
  this.__active = true;
  this.__modifiedElements = new Set();

  // Close settings modal
  if (gameClient && gameClient.interface && gameClient.interface.modalManager) {
    gameClient.interface.modalManager.close();
  }

  // Disable game touch input
  if (gameClient && gameClient.touch) {
    gameClient.touch.__layoutEditActive = true;
  }

  // Force-show equipment and container panels so they can be positioned
  this.__forcePanelsVisible(true);

  // Briefly reveal the tab-switched panels (skill/friend/minimap) so
  // __captureCurrentPositions() can measure their CSS-default rect. Without
  // this their fallback positions are empty, and under body.layout-custom
  // they'd collapse to the top-left corner (0,0) until the player drags.
  let tabPanels = [
    document.getElementById("skill-window"),
    document.getElementById("friend-window"),
    document.getElementById("minimap-container")
  ];
  let tabSnapshot = tabPanels.map(function (el) {
    if (!el) return null;
    return {
      hadClass: el.classList.contains("mobile-tab-panel"),
      display: el.style.display
    };
  });
  tabPanels.forEach(function (el) {
    if (!el) return;
    el.classList.add("mobile-tab-panel");
    el.style.display = "flex";
  });

  // Force reflow so newly-shown elements have valid geometry
  document.body.offsetHeight;

  // Capture current positions BEFORE changing layout mode
  // This captures either the CSS defaults or previously saved positions
  let currentPositions = this.__captureCurrentPositions();
  this.__preEditState = currentPositions;

  // Restore the tab panels to their prior hidden state now that we have
  // their default positions. The inline left/bottom applied by
  // __applyPositions below keeps them anchored when tabs bring them back.
  tabPanels.forEach(function (el, i) {
    if (!el || !tabSnapshot[i]) return;
    if (!tabSnapshot[i].hadClass) el.classList.remove("mobile-tab-panel");
    el.style.display = tabSnapshot[i].display || "";
  });

  let orientation = this.__currentOrientation;
  if (!this.__layout[orientation]) {
    this.__layout[orientation] = currentPositions;
  }

  // Now switch to independent positioning and apply inline styles
  document.body.classList.add("layout-edit-mode");
  document.body.classList.add("layout-custom");
  this.__applyPositions(this.__layout[orientation], currentPositions);

  // Show toolbar
  let toolbar = document.getElementById("layout-editor-toolbar");
  if (toolbar) toolbar.style.display = "flex";

  // Create drag handles on each element
  this.__createHandles();

}

LayoutEditor.prototype.exit = function (save) {

  /*
   * Function LayoutEditor.exit
   * Exit layout edit mode. If save is true, persist positions.
   */

  if (!this.__active) return;
  this.__active = false;

  // Tear down the Center menu if still open
  this.__closeCenterMenu();

  // Re-enable game touch input
  if (gameClient && gameClient.touch) {
    gameClient.touch.__layoutEditActive = false;
  }

  // Remove handles
  this.__removeHandles();

  // Hide toolbar
  let toolbar = document.getElementById("layout-editor-toolbar");
  if (toolbar) toolbar.style.display = "none";

  document.body.classList.remove("layout-edit-mode");

  let orientation = this.__currentOrientation;

  if (save) {
    // Only update positions for elements that were actually dragged or scaled
    // during this session. This prevents force-shown empty panels (like the
    // container panel) from having their position overwritten.
    let currentPositions = this.__captureCurrentPositions();
    if (!this.__layout[orientation]) {
      this.__layout[orientation] = {};
    }
    let self = this;
    this.__modifiedElements.forEach(function (id) {
      if (currentPositions[id]) {
        self.__layout[orientation][id] = currentPositions[id];
      }
    });
    this.__saveLayout();
  } else {
    // Cancel: check if there was a saved layout before we entered
    let hadSavedLayout = this.__loadLayout()[orientation];

    if (hadSavedLayout) {
      // Restore the previously saved layout
      this.__layout[orientation] = hadSavedLayout;
      this.__applyPositions(hadSavedLayout);
    } else {
      // No layout was saved before — go back to CSS defaults
      delete this.__layout[orientation];
      this.__clearPositions();
      document.body.classList.remove("layout-custom");
    }
  }

  // Reposition extra hotbar to its default (no CSS fallback)
  if (gameClient && gameClient.touch) {
    gameClient.touch.__positionExtraHotbar();
  }

  // Restore panel visibility
  this.__forcePanelsVisible(false);

  this.__preEditState = null;

}

LayoutEditor.prototype.reset = function () {

  /*
   * Function LayoutEditor.reset
   * Reset layout to CSS defaults for current orientation
   */

  let orientation = this.__currentOrientation;
  delete this.__layout[orientation];
  this.__saveLayout();

  // Remove inline styles and custom positioning class
  this.__clearPositions();
  document.body.classList.remove("layout-custom");

  // Reposition extra hotbar to its default (no CSS fallback)
  if (gameClient && gameClient.touch) {
    gameClient.touch.__positionExtraHotbar();
  }

  // Exit edit mode
  this.__active = false;

  if (gameClient && gameClient.touch) {
    gameClient.touch.__layoutEditActive = false;
  }

  this.__removeHandles();

  let toolbar = document.getElementById("layout-editor-toolbar");
  if (toolbar) toolbar.style.display = "none";

  document.body.classList.remove("layout-edit-mode");

  // Restore panel visibility
  this.__forcePanelsVisible(false);

  this.__preEditState = null;

}

LayoutEditor.prototype.centerAll = function () {

  /*
   * Function LayoutEditor.centerAll
   * Centers every configurable panel — the "All" menu entry.
   */

  this.__centerPanels(null);

}

LayoutEditor.prototype.__centerPanels = function (configIds) {

  /*
   * Function LayoutEditor.__centerPanels
   * Snaps the given panels to the viewport centre. Passing null centers every
   * entry in __elementConfig (the existing "center all" behaviour). Passing an
   * array of config ids centers only those — used by the Opened-Window option
   * so a single off-screen tab panel can be recovered without stacking the
   * whole UI on top of itself.
   */

  if (!this.__active) return;

  let vp = window.visualViewport;
  let viewW = vp ? vp.width : window.innerWidth;
  let viewH = vp ? vp.height : window.innerHeight;

  let filter = configIds ? new Set(configIds) : null;

  for (let i = 0; i < this.__elementConfig.length; i++) {
    let config = this.__elementConfig[i];
    if (filter && !filter.has(config.id)) continue;

    let el = document.getElementById(config.domId);
    if (!el) continue;

    let rect = el.getBoundingClientRect();
    if (rect.width === 0 && rect.height === 0) continue;

    let centerLeft = Math.round((viewW - rect.width) / 2);
    let centerBottom = Math.round((viewH - rect.height) / 2);

    el.style.setProperty("left", centerLeft + "px", "important");
    el.style.setProperty("top", "auto", "important");
    el.style.setProperty("right", "auto", "important");
    el.style.setProperty("bottom", centerBottom + "px", "important");

    this.__modifiedElements.add(config.id);

    let orientation = this.__currentOrientation;
    if (!this.__layout[orientation]) this.__layout[orientation] = {};
    let existing = this.__layout[orientation][config.id] || {};
    this.__layout[orientation][config.id] = {
      x: centerLeft,
      bottom: centerBottom,
      scale: existing.scale || 1.0
    };
  }

  if (navigator.vibrate) navigator.vibrate(30);

}

LayoutEditor.prototype.__getOpenedTabTarget = function () {

  /*
   * Function LayoutEditor.__getOpenedTabTarget
   * Returns { id, label } for the currently-visible mobile tab panel, or null
   * if no tab panel is open. Consults gameClient.touch.__visiblePanels — the
   * source of truth maintained by Touch.__switchTab.
   */

  if (typeof gameClient === "undefined" || !gameClient || !gameClient.touch) {
    return null;
  }
  let visible = gameClient.touch.__visiblePanels;
  if (!visible || visible.size === 0) return null;

  let tabKeyToConfigId = {
    equipment: "equipment",
    minimap:   "minimap",
    stats:     "skillWindow",
    friends:   "friendWindow"
  };

  let target = null;
  visible.forEach(function (key) {
    if (target) return;
    let configId = tabKeyToConfigId[key];
    if (configId) target = configId;
  });

  if (!target) return null;

  for (let i = 0; i < this.__elementConfig.length; i++) {
    if (this.__elementConfig[i].id === target) {
      return { id: target, label: this.__elementConfig[i].label };
    }
  }

  return null;

}

LayoutEditor.prototype.__toggleCenterMenu = function () {

  /*
   * Function LayoutEditor.__toggleCenterMenu
   * Opens or closes the Center popup — All / Opened Window picker.
   */

  if (!this.__active) return;

  if (this.__centerMenu) {
    this.__closeCenterMenu();
  } else {
    this.__openCenterMenu();
  }

}

LayoutEditor.prototype.__openCenterMenu = function () {

  /*
   * Function LayoutEditor.__openCenterMenu
   * Builds the popup anchored below the Center toolbar button. Contains
   * "All" (existing center-everything behaviour) and, if a tab panel is
   * currently open, a second entry named after that panel.
   */

  let centerBtn = document.getElementById("layout-center-btn");
  if (!centerBtn) return;

  let menu = document.createElement("div");
  menu.id = "layout-center-menu";

  let self = this;
  let makeRow = function (label, handler) {
    let btn = document.createElement("button");
    btn.textContent = label;
    let onTap = function (e) {
      if (e) e.preventDefault();
      self.__closeCenterMenu();
      handler();
    };
    btn.addEventListener("click", onTap);
    btn.addEventListener("touchend", onTap, { passive: false });
    return btn;
  };

  menu.appendChild(makeRow("All", function () {
    self.__centerPanels(null);
  }));

  let opened = this.__getOpenedTabTarget();
  if (opened) {
    menu.appendChild(makeRow(opened.label, function () {
      self.__centerPanels([opened.id]);
    }));
  }

  // Anchor above the Center button (toolbar is centered on screen; popup
  // above keeps it out from under the user's finger).
  let rect = centerBtn.getBoundingClientRect();
  menu.style.position = "fixed";
  menu.style.left = Math.round(rect.left + rect.width / 2) + "px";
  menu.style.bottom = Math.round(window.innerHeight - rect.top + 6) + "px";
  menu.style.transform = "translateX(-50%)";

  document.body.appendChild(menu);
  this.__centerMenu = menu;

  // Dismiss on tap outside. Deferred so the tap that opened the menu doesn't
  // immediately close it.
  let dismissHandler = function (e) {
    if (!self.__centerMenu) return;
    if (self.__centerMenu.contains(e.target)) return;
    if (centerBtn.contains(e.target)) return;
    self.__closeCenterMenu();
  };
  this.__centerMenuDismiss = dismissHandler;
  setTimeout(function () {
    document.addEventListener("touchstart", dismissHandler, { passive: true });
    document.addEventListener("mousedown", dismissHandler);
  }, 0);

}

LayoutEditor.prototype.__closeCenterMenu = function () {

  /*
   * Function LayoutEditor.__closeCenterMenu
   * Tears down the popup and unbinds the outside-tap dismiss listener.
   */

  if (this.__centerMenu && this.__centerMenu.parentNode) {
    this.__centerMenu.parentNode.removeChild(this.__centerMenu);
  }
  this.__centerMenu = null;

  if (this.__centerMenuDismiss) {
    document.removeEventListener("touchstart", this.__centerMenuDismiss);
    document.removeEventListener("mousedown", this.__centerMenuDismiss);
    this.__centerMenuDismiss = null;
  }

}

LayoutEditor.prototype.applyLayout = function () {

  /*
   * Function LayoutEditor.applyLayout
   * Apply saved layout for current orientation. Called on startup.
   */

  let orientation = this.__getOrientation();
  let data = this.__layout[orientation];

  // Only apply custom layout in fullscreen — use CSS defaults otherwise
  if (!data || !this.__isFullscreen()) {
    document.body.classList.remove("layout-custom");
    this.__clearPositions();
    return;
  }

  // Capture current positions BEFORE layout-custom forces position:fixed,
  // so unsaved elements can be pinned at their CSS-defined locations
  let fallbackPositions = this.__captureCurrentPositions();

  document.body.classList.add("layout-custom");
  this.__applyPositions(data, fallbackPositions);

}

LayoutEditor.prototype.__applyPositions = function (data, fallbackPositions) {

  /*
   * Function LayoutEditor.__applyPositions
   * Apply position data to elements via inline styles.
   * Uses bottom/left anchoring so positions stay stable when address bar hides/shows.
   * fallbackPositions: pre-captured positions for elements without saved data,
   * taken BEFORE layout-custom forces position:fixed on all elements.
   */

  for (let i = 0; i < this.__elementConfig.length; i++) {
    let config = this.__elementConfig[i];
    let el = document.getElementById(config.domId);

    if (!el) continue;

    let elData = data[config.id];

    if (!elData) {
      // No saved position — pin at pre-captured CSS position so layout-custom
      // doesn't displace it when it forces position:fixed on all elements
      let fb = fallbackPositions && fallbackPositions[config.id];
      if (!fb) continue;
      el.style.setProperty("left", fb.x + "px", "important");
      el.style.setProperty("top", "auto", "important");
      el.style.setProperty("right", "auto", "important");
      el.style.setProperty("bottom", fb.bottom + "px", "important");
      continue;
    }

    // Use setProperty with "important" to override !important rules in mobile CSS
    el.style.setProperty("left", elData.x + "px", "important");
    el.style.setProperty("top", "auto", "important");
    el.style.setProperty("right", "auto", "important");
    el.style.setProperty("bottom", elData.bottom + "px", "important");
    el.style.setProperty("transform", "scale(" + (elData.scale || 1.0) + ")", "important");
    el.style.setProperty("transform-origin", "bottom left", "important");
  }

}

LayoutEditor.prototype.reapplyElement = function (elementId) {

  /*
   * Function LayoutEditor.reapplyElement
   * Re-apply saved position for a single element without re-capturing all positions.
   * Used when a panel becomes visible and needs its custom position restored.
   *
   * The fullscreen gate lives in applyLayout (which also manages the
   * body.layout-custom class). reapplyElement READS the saved position for a
   * panel that just became visible and must not gate on fullscreen — iOS
   * Safari (non-PWA) can't enter true fullscreen, so the gate would short-
   * circuit here and leave the panel relying on iOS-unreliable CSS defaults
   * (stale safe-area vars + position:fixed recomputation quirks → panel
   * renders off-screen). Applying the saved inline position works in any mode.
   */

  let orientation = this.__getOrientation();
  let data = this.__layout[orientation];

  if (!data) return;

  let elData = data[elementId];
  if (!elData) return;

  // Find the DOM element for this config id
  for (let i = 0; i < this.__elementConfig.length; i++) {
    if (this.__elementConfig[i].id !== elementId) continue;
    let el = document.getElementById(this.__elementConfig[i].domId);
    if (!el) return;

    el.style.setProperty("left", elData.x + "px", "important");
    el.style.setProperty("top", "auto", "important");
    el.style.setProperty("right", "auto", "important");
    el.style.setProperty("bottom", elData.bottom + "px", "important");
    el.style.setProperty("transform", "scale(" + (elData.scale || 1.0) + ")", "important");
    el.style.setProperty("transform-origin", "bottom left", "important");
    return;
  }

}

LayoutEditor.prototype.__clearPositions = function () {

  /*
   * Function LayoutEditor.__clearPositions
   * Remove inline position styles from all configurable elements
   */

  for (let i = 0; i < this.__elementConfig.length; i++) {
    let config = this.__elementConfig[i];
    let el = document.getElementById(config.domId);

    if (!el) continue;

    // Skip extra hotbar — it has no CSS fallback position, always JS-managed
    if (config.id === "extraHotbar") continue;

    el.style.removeProperty("left");
    el.style.removeProperty("top");
    el.style.removeProperty("right");
    el.style.removeProperty("bottom");
    el.style.removeProperty("position");
    el.style.removeProperty("transform");
    el.style.removeProperty("transform-origin");
  }

}

LayoutEditor.prototype.__captureCurrentPositions = function () {

  /*
   * Function LayoutEditor.__captureCurrentPositions
   * Capture current positions using bottom/left offsets.
   * Bottom offset is stable across address bar changes.
   */

  let positions = {};
  let vh = window.innerHeight;

  for (let i = 0; i < this.__elementConfig.length; i++) {
    let config = this.__elementConfig[i];
    let el = document.getElementById(config.domId);

    if (!el) continue;

    let rect = el.getBoundingClientRect();

    // Skip elements with zero size (hidden/not laid out yet)
    if (rect.width === 0 && rect.height === 0) continue;

    // Get current scale from transform (check inline first, then computed)
    let scale = 1.0;
    let transform = el.style.transform || window.getComputedStyle(el).transform;
    if (transform && transform !== "none") {
      let scaleMatch = transform.match(/scale\(([^)]+)\)/);
      if (scaleMatch) {
        scale = parseFloat(scaleMatch[1]);
      } else {
        // Computed style returns matrix(a, b, c, d, tx, ty) — a is scaleX
        let matrixMatch = transform.match(/matrix\(([^,]+)/);
        if (matrixMatch) scale = parseFloat(matrixMatch[1]);
      }
    }

    let x = rect.left;
    let bottom = vh - rect.bottom;

    positions[config.id] = {
      x: Math.round(x),
      bottom: Math.round(bottom),
      scale: scale
    };
  }

  return positions;

}

LayoutEditor.prototype.__createHandles = function () {

  /*
   * Function LayoutEditor.__createHandles
   * Create drag handle overlays on each configurable element
   */

  this.__removeHandles();

  for (let i = 0; i < this.__elementConfig.length; i++) {
    let config = this.__elementConfig[i];
    let el = document.getElementById(config.domId);

    if (!el) continue;

    let handle = this.__createHandle(config.id, config.label, el);
    this.__handles.push(handle);
  }

}

LayoutEditor.prototype.__createHandle = function (id, label, targetEl) {

  /*
   * Function LayoutEditor.__createHandle
   * Create a single drag handle overlay for an element
   */

  let handle = document.createElement("div");
  handle.className = "layout-editor-handle";

  // Label
  let labelEl = document.createElement("span");
  labelEl.className = "handle-label";
  labelEl.textContent = label;
  handle.appendChild(labelEl);

  // Scale controls
  let controls = document.createElement("div");
  controls.className = "handle-scale-controls";

  let minusBtn = document.createElement("button");
  minusBtn.className = "handle-scale-btn";
  minusBtn.textContent = "-";
  minusBtn.addEventListener("touchstart", function (e) {
    e.preventDefault();
    e.stopPropagation();
  }, { passive: false });
  minusBtn.addEventListener("touchend", function (e) {
    e.preventDefault();
    e.stopPropagation();
    this.__handleScale(id, -0.1);
  }.bind(this), { passive: false });
  controls.appendChild(minusBtn);

  let plusBtn = document.createElement("button");
  plusBtn.className = "handle-scale-btn";
  plusBtn.textContent = "+";
  plusBtn.addEventListener("touchstart", function (e) {
    e.preventDefault();
    e.stopPropagation();
  }, { passive: false });
  plusBtn.addEventListener("touchend", function (e) {
    e.preventDefault();
    e.stopPropagation();
    this.__handleScale(id, 0.1);
  }.bind(this), { passive: false });
  controls.appendChild(plusBtn);

  handle.appendChild(controls);

  // Drag events on the handle
  handle.addEventListener("touchstart", this.__handleDragStart.bind(this, id, targetEl), { passive: false });
  handle.addEventListener("touchmove", this.__handleDragMove.bind(this, targetEl), { passive: false });
  handle.addEventListener("touchend", this.__handleDragEnd.bind(this), { passive: false });

  targetEl.appendChild(handle);

  return handle;

}

LayoutEditor.prototype.__removeHandles = function () {

  /*
   * Function LayoutEditor.__removeHandles
   * Remove all drag handle overlays
   */

  for (let i = 0; i < this.__handles.length; i++) {
    if (this.__handles[i].parentNode) {
      this.__handles[i].parentNode.removeChild(this.__handles[i]);
    }
  }

  this.__handles = [];

}

LayoutEditor.prototype.__handleDragStart = function (id, targetEl, event) {

  /*
   * Function LayoutEditor.__handleDragStart
   * Start dragging an element
   */

  event.preventDefault();

  let touch = event.touches[0];
  let rect = targetEl.getBoundingClientRect();

  this.__dragState = {
    id: id,
    startTouchX: touch.clientX,
    startTouchY: touch.clientY,
    startElX: rect.left,
    startElBottom: window.innerHeight - rect.bottom
  };

  this.__modifiedElements.add(id);

}

LayoutEditor.prototype.__handleDragMove = function (targetEl, event) {

  /*
   * Function LayoutEditor.__handleDragMove
   * Move an element while dragging (uses bottom/left positioning)
   */

  event.preventDefault();

  if (!this.__dragState) return;

  let touch = event.touches[0];
  let dx = touch.clientX - this.__dragState.startTouchX;
  let dy = touch.clientY - this.__dragState.startTouchY;

  let newX = this.__dragState.startElX + dx;
  let newBottom = this.__dragState.startElBottom - dy;

  // Clamp to viewport
  let maxX = window.innerWidth - 20;
  let maxBottom = window.innerHeight - 20;
  newX = Math.max(-20, Math.min(maxX, newX));
  newBottom = Math.max(-20, Math.min(maxBottom, newBottom));

  targetEl.style.setProperty("left", Math.round(newX) + "px", "important");
  targetEl.style.setProperty("bottom", Math.round(newBottom) + "px", "important");

}

LayoutEditor.prototype.__handleDragEnd = function (event) {

  /*
   * Function LayoutEditor.__handleDragEnd
   * End dragging. Immediately records the final position into the in-memory
   * layout so hidden (tab-switched-away) panels don't lose their drag when
   * save-time capture misses them.
   */

  event.preventDefault();

  if (this.__dragState && this.__dragState.id) {
    let id = this.__dragState.id;
    let config = null;
    for (let i = 0; i < this.__elementConfig.length; i++) {
      if (this.__elementConfig[i].id === id) { config = this.__elementConfig[i]; break; }
    }
    if (config) {
      let el = document.getElementById(config.domId);
      if (el) {
        let rect = el.getBoundingClientRect();
        if (rect.width > 0 || rect.height > 0) {
          let scale = 1.0;
          let transform = el.style.transform;
          if (transform) {
            let m = transform.match(/scale\(([^)]+)\)/);
            if (m) scale = parseFloat(m[1]);
          }
          let orientation = this.__currentOrientation;
          if (!this.__layout[orientation]) this.__layout[orientation] = {};
          this.__layout[orientation][id] = {
            x: Math.round(rect.left),
            bottom: Math.round(window.innerHeight - rect.bottom),
            scale: scale
          };
        }
      }
    }
  }

  this.__dragState = null;

}

LayoutEditor.prototype.__handleScale = function (id, delta) {

  /*
   * Function LayoutEditor.__handleScale
   * Adjust the scale of an element
   */

  let config = null;
  for (let i = 0; i < this.__elementConfig.length; i++) {
    if (this.__elementConfig[i].id === id) {
      config = this.__elementConfig[i];
      break;
    }
  }

  if (!config) return;

  let el = document.getElementById(config.domId);
  if (!el) return;

  // Get current scale (check inline first, then computed)
  let scale = 1.0;
  let transform = el.style.transform || window.getComputedStyle(el).transform;
  if (transform && transform !== "none") {
    let scaleMatch = transform.match(/scale\(([^)]+)\)/);
    if (scaleMatch) {
      scale = parseFloat(scaleMatch[1]);
    } else {
      let matrixMatch = transform.match(/matrix\(([^,]+)/);
      if (matrixMatch) scale = parseFloat(matrixMatch[1]);
    }
  }

  // Adjust and clamp
  scale = Math.round((scale + delta) * 10) / 10;
  scale = Math.max(0.5, Math.min(1.5, scale));

  el.style.setProperty("transform", "scale(" + scale + ")", "important");
  el.style.setProperty("transform-origin", "bottom left", "important");

  this.__modifiedElements.add(id);

  // Persist the change into the in-memory layout immediately — save-time
  // re-capture misses hidden (tab-switched) panels and would otherwise drop
  // the scale when the player moves on to edit another panel.
  let orientation = this.__currentOrientation;
  if (!this.__layout[orientation]) this.__layout[orientation] = {};
  let rect = el.getBoundingClientRect();
  let existing = this.__layout[orientation][id] || {};
  this.__layout[orientation][id] = {
    x: (rect.width > 0 || rect.height > 0) ? Math.round(rect.left) : (existing.x || 0),
    bottom: (rect.width > 0 || rect.height > 0) ? Math.round(window.innerHeight - rect.bottom) : (existing.bottom || 0),
    scale: scale
  };

  if (navigator.vibrate) navigator.vibrate(20);

}

LayoutEditor.prototype.__getOrientation = function () {

  /*
   * Function LayoutEditor.__getOrientation
   * Returns current orientation string ("portrait" | "landscape").
   *
   * Detection chain:
   *   1. screen.orientation.type — Android + iOS 16.4+, desktop
   *   2. matchMedia("(orientation: portrait)") — reliable fallback on
   *      every modern mobile browser including older iOS Safari
   *   3. window.innerWidth / innerHeight — final fallback (these DO
   *      swap on iOS; screen.width/height stay fixed to the device's
   *      physical orientation and were the cause of layout positions
   *      not re-applying after rotating on pre-iOS-16.4 iPhones)
   */

  if (screen.orientation && screen.orientation.type) {
    return screen.orientation.type.startsWith("portrait") ? "portrait" : "landscape";
  }

  if (typeof window.matchMedia === "function") {
    try {
      if (window.matchMedia("(orientation: portrait)").matches) return "portrait";
      if (window.matchMedia("(orientation: landscape)").matches) return "landscape";
    } catch (e) { /* fall through */ }
  }

  return window.innerHeight > window.innerWidth ? "portrait" : "landscape";

}

LayoutEditor.prototype.__handleFullscreenChange = function () {

  /*
   * Function LayoutEditor.__handleFullscreenChange
   * Exit customize mode when fullscreen is toggled, then reapply layout
   */

  if (this.__active) {
    this.exit(false);
  }

  // Reapply layout — custom positions only active in fullscreen.
  // Defer by TWO animation frames so innerWidth/innerHeight have
  // finished settling on iOS Safari (the first paint after entering
  // fullscreen still reports the pre-fullscreen dimensions on some
  // iPhones). One RAF wasn't enough; see the rotation and touch-init
  // paths which use the same two-RAF pattern.
  let self = this;
  requestAnimationFrame(function () {
    requestAnimationFrame(function () {
      self.applyLayout();
      // Reposition extra hotbar to its default after positions are cleared/applied
      if (gameClient && gameClient.touch) {
        gameClient.touch.__positionExtraHotbar();
      }
    });
  });

}

LayoutEditor.prototype.__handleOrientationChange = function () {

  /*
   * Function LayoutEditor.__handleOrientationChange
   * Handle orientation change — apply the correct layout.
   *
   * Deferred to the next frame because on iOS Safari the orientation
   * event lands before the viewport has finished resizing —
   * __captureCurrentPositions reads stale getBoundingClientRects and
   * produces fallback positions that are mid-rotation, which left the
   * equipment window taller than it should be on the rotate-back case.
   * Waiting one RAF lets the viewport finalise before we measure.
   */

  let newOrientation = this.__getOrientation();

  if (newOrientation === this.__currentOrientation) return;

  this.__currentOrientation = newOrientation;

  // Exit customize mode without saving on rotation
  if (this.__active) {
    this.exit(false);
  }

  // Drop any lingering inline styles from the previous orientation
  // (transform, left/bottom, width, height). __applyPositions only
  // overrides the top/left/bottom/right/transform fields — if a panel
  // had picked up, say, a cached height from mid-rotation CSS, that
  // would persist past applyLayout. Clearing first + deferring apply
  // past the viewport settle guarantees a fresh measurement.
  this.__clearPositions();
  document.body.classList.remove("layout-custom");

  let self = this;
  requestAnimationFrame(function () {
    requestAnimationFrame(function () {
      self.applyLayout();
    });
  });

}

LayoutEditor.prototype.__loadLayout = function () {

  /*
   * Function LayoutEditor.__loadLayout
   * Load saved layout from localStorage. Clears old format that used top (y) positioning.
   */

  try {
    let data = localStorage.getItem("mobile-layout");
    if (data) {
      let layout = JSON.parse(data);

      // Detect old format (used y/top instead of bottom) and discard it
      for (let orientation in layout) {
        let positions = layout[orientation];
        for (let id in positions) {
          if (positions[id].y !== undefined && positions[id].bottom === undefined) {
            // Old format — clear all saved layouts
            localStorage.removeItem("mobile-layout");
            return {};
          }
        }
      }

      return layout;
    }
  } catch (e) {}

  return {};

}

LayoutEditor.prototype.__saveLayout = function () {

  /*
   * Function LayoutEditor.__saveLayout
   * Save layout to localStorage
   */

  localStorage.setItem("mobile-layout", JSON.stringify(this.__layout));

}

LayoutEditor.prototype.__forcePanelsVisible = function (show) {

  /*
   * Function LayoutEditor.__forcePanelsVisible
   * Force the container panel + extra hotbar visible during edit (they don't
   * participate in the tab bar). Equipment, Skills, Friends, Minimap are all
   * tab-switched — users pick which one to edit via the normal tab bar instead
   * of seeing them all stacked on top of each other.
   */

  let containerEl = document.getElementById("mobile-container-panel");
  let container2El = document.getElementById("mobile-container-panel-2");
  let extraHotbarEl = document.getElementById("mobile-extra-hotbar");

  let isTablet = document.body.classList.contains("force-tablet");

  if (show) {
    this.__savedContainerDisplay = containerEl ? containerEl.style.display : "";
    this.__savedContainer2Display = container2El ? container2El.style.display : "";
    this.__savedExtraHotbarVisible = extraHotbarEl ? extraHotbarEl.classList.contains("visible") : false;

    if (containerEl) containerEl.style.display = "flex";
    if (container2El && isTablet) container2El.style.display = "flex";
    if (extraHotbarEl) { extraHotbarEl.style.display = ""; extraHotbarEl.classList.add("visible"); }
  } else {
    if (containerEl) containerEl.style.display = this.__savedContainerDisplay || "";
    if (container2El) container2El.style.display = this.__savedContainer2Display || "";
    if (extraHotbarEl) {
      if (!this.__savedExtraHotbarVisible) {
        extraHotbarEl.classList.remove("visible");
      }
    }
  }

}


