const ContainerMenu = function (id) {

    /*
     * Class ContainerMenu
     * Wrapper for the menu that displays on container slots
     */

    // Inherits from menu
    Menu.call(this, id);

    // Store reference to the slot object
    this.slotObject = null;

}

ContainerMenu.prototype = Object.create(Menu.prototype);
ContainerMenu.prototype.constructor = ContainerMenu;

ContainerMenu.prototype.open = function (event, slotObject) {

    /*
     * Function ContainerMenu.open
     * Opens the container menu with the slot object reference
     */

    this.slotObject = slotObject;

    // Call parent open
    return Menu.prototype.open.call(this, event);

}

ContainerMenu.prototype.click = function (event) {

    /*
     * Function ContainerMenu.click
     * Callback fired specially for the ContainerMenu after a button is clicked
     */

    if (this.slotObject === null) {
        return true;
    }

    // The "open-here" button is always the *override* — it flips whatever
    // the current right-click default is. With setting OFF (default right-
    // click = new window), it opens in same window. With setting ON
    // (default right-click = same window), it opens in new window and the
    // button label is "Open in new window" instead of "Open Here".
    let settings = gameClient.interface && gameClient.interface.settings;
    let sameWindow = settings && settings.__state && settings.__state["open-containers-same-window"];

    // Take action depending on the button
    switch (this.__getAction(event)) {
        case "look":
            gameClient.mouse.look(this.slotObject);
            break;
        case "use":
            // When the setting is ON, "Open" should match the new default
            // (same window for nested containers), not silently diverge
            // from what a direct right-click does.
            {
                let useItem = this.slotObject.which && this.slotObject.which.peekItem
                  ? this.slotObject.which.peekItem(this.slotObject.index)
                  : null;
                let isContainerItem = useItem !== null && useItem.isContainer && useItem.isContainer();
                if (sameWindow && isContainerItem && this.slotObject.which.constructor.name === "Container") {
                    gameClient.__ctrlContainerOpen = this.slotObject.which.__containerId;
                    clearTimeout(gameClient.__ctrlContainerOpenTimeout);
                    gameClient.__ctrlContainerOpenTimeout = setTimeout(function() {
                      gameClient.__ctrlContainerOpen = null;
                    }, 2000);
                }
                // Auto-retry on toggle-close — same as the open-here case
                // and the direct right-click in mouse.js. If the bag is
                // already open elsewhere, server's first toggle closes it
                // and the user has to click again. The 300ms re-send
                // handles it transparently.
                if (isContainerItem) {
                    gameClient.__forceOpenAfterClose = this.slotObject;
                    clearTimeout(gameClient.__forceOpenAfterCloseTimeout);
                    gameClient.__forceOpenAfterCloseTimeout = setTimeout(function() {
                      gameClient.__forceOpenAfterClose = null;
                    }, 300);
                }
            }
            gameClient.mouse.use(this.slotObject);
            break;
        case "open-here":
            if (!sameWindow) {
                // Setting OFF: this button is "Open Here" → open in same window.
                gameClient.__ctrlContainerOpen = this.slotObject.which.__containerId;
                clearTimeout(gameClient.__ctrlContainerOpenTimeout);
                gameClient.__ctrlContainerOpenTimeout = setTimeout(function() {
                  gameClient.__ctrlContainerOpen = null;
                }, 2000);
            } else {
                // Setting ON: this button is "Open in new window". Server's
                // toggleContainer CLOSES a bag that is already open (authentic
                // Tibia toggle). If the bag the user targets happens to be
                // open elsewhere, the first click closes it and the user has
                // to click again to actually open. Arm an auto-retry: if a
                // close packet arrives within 300ms of this use, re-send.
                gameClient.__forceOpenAfterClose = this.slotObject;
                clearTimeout(gameClient.__forceOpenAfterCloseTimeout);
                gameClient.__forceOpenAfterCloseTimeout = setTimeout(function() {
                  gameClient.__forceOpenAfterClose = null;
                }, 300);
            }
            gameClient.mouse.use(this.slotObject);
            break;
        case "cook":
            gameClient.mouse.__setMultiUseItem(this.slotObject);
            break;
        case "trade":
            gameClient.mouse.startTradeTargetSelect(this.slotObject);
            break;
    }

    // Reset slot object reference
    this.slotObject = null;

    // Return true to close the menu after clicking
    return true;

}


