/* ===== FILE: https://minibia.com/src/ui/modals/modal-create-account.js?v=1778114744231 ===== */

const CreateAccountModal = function(element) {

  /*
   * Class CreateAccountModal
   * Modal for creating a new account with validation and auto-login on success
   */

  // Inherit from modal
  Modal.call(this, element);

  // Debounce timers for availability checks
  this.__nameCheckTimer = null;
  this.__accountCheckTimer = null;

  // Attach real-time validation listeners
  let self = this;

  document.getElementById("create-name").addEventListener("input", function() {
    self.__validateNameField(this);
  });

  document.getElementById("create-username").addEventListener("input", function() {
    self.__validateAccountField(this);
  });

  document.getElementById("create-password").addEventListener("input", function() {
    self.__validatePasswordField(this);
  });

}

CreateAccountModal.prototype = Object.create(Modal.prototype);
CreateAccountModal.constructor = CreateAccountModal;

CreateAccountModal.prototype.__setHint = function(id, text, type) {

  /*
   * Function CreateAccountModal.__setHint
   * Sets the hint text and style for a field
   */

  let hint = document.getElementById(id);
  if (!hint) return;
  hint.textContent = text;
  hint.className = "field-hint" + (type ? " " + type : "");

}

CreateAccountModal.prototype.__setFieldState = function(field, valid) {

  /*
   * Function CreateAccountModal.__setFieldState
   * Adds valid/invalid CSS class to an input field
   */

  field.classList.remove("field-valid", "field-invalid");
  if (valid === true) field.classList.add("field-valid");
  else if (valid === false) field.classList.add("field-invalid");

}

CreateAccountModal.prototype.__validateNameField = function(field) {

  /*
   * Function CreateAccountModal.__validateNameField
   * Real-time validation for the character name field with availability check
   */

  let val = field.value.toLowerCase().trim();

  if (val.length === 0) {
    this.__setFieldState(field, null);
    this.__setHint("create-name-hint", "", "");
    return;
  }

  if (val.length < 3) {
    this.__setFieldState(field, false);
    this.__setHint("create-name-hint", "Too short (min 3 characters)", "error");
    return;
  }

  if (!/^[a-z]+(?: [a-z]+)*$/.test(val)) {
    this.__setFieldState(field, false);
    this.__setHint("create-name-hint", "Only letters with single spaces", "error");
    return;
  }

  // Debounce the server check
  let self = this;
  clearTimeout(this.__nameCheckTimer);
  this.__setHint("create-name-hint", "Checking...", "");
  this.__setFieldState(field, null);

  this.__nameCheckTimer = setTimeout(function() {
    fetch("/api/login/check-name", {
      "method": "POST",
      "headers": { "Content-Type": "application/json" },
      "body": JSON.stringify({ "name": val })
    }).then(function(response) {
      return response.json();
    }).then(function(data) {
      // Only update if value hasn't changed
      if (field.value.toLowerCase().trim() !== val) return;
      if (data.available) {
        self.__setFieldState(field, true);
        self.__setHint("create-name-hint", "Name available", "success");
      } else {
        self.__setFieldState(field, false);
        self.__setHint("create-name-hint", "Name already taken", "error");
      }
    }).catch(function() {
      self.__setHint("create-name-hint", "", "");
      self.__setFieldState(field, null);
    });
  }, 400);

}

CreateAccountModal.prototype.__validateAccountField = function(field) {

  /*
   * Function CreateAccountModal.__validateAccountField
   * Real-time validation for the account name field with availability check
   */

  let val = field.value.trim();

  if (val.length === 0) {
    this.__setFieldState(field, null);
    this.__setHint("create-username-hint", "", "");
    return;
  }

  if (val.length < 3) {
    this.__setFieldState(field, false);
    this.__setHint("create-username-hint", "Too short (min 3 characters)", "error");
    return;
  }

  if (val.length > 20) {
    this.__setFieldState(field, false);
    this.__setHint("create-username-hint", "Too long (max 20 characters)", "error");
    return;
  }

  // Debounce the server check
  let self = this;
  clearTimeout(this.__accountCheckTimer);
  this.__setHint("create-username-hint", "Checking...", "");
  this.__setFieldState(field, null);

  this.__accountCheckTimer = setTimeout(function() {
    fetch("/api/login/check-account", {
      "method": "POST",
      "headers": { "Content-Type": "application/json" },
      "body": JSON.stringify({ "account": val })
    }).then(function(response) {
      return response.json();
    }).then(function(data) {
      if (field.value.trim() !== val) return;
      if (data.available) {
        self.__setFieldState(field, true);
        self.__setHint("create-username-hint", "Account name available", "success");
      } else {
        self.__setFieldState(field, false);
        self.__setHint("create-username-hint", "Account name already taken", "error");
      }
    }).catch(function() {
      self.__setHint("create-username-hint", "", "");
      self.__setFieldState(field, null);
    });
  }, 400);

}

CreateAccountModal.prototype.__validatePasswordField = function(field) {

  /*
   * Function CreateAccountModal.__validatePasswordField
   * Real-time validation for the password field
   */

  let val = field.value;

  if (val.length === 0) {
    this.__setFieldState(field, null);
    this.__setHint("create-password-hint", "", "");
    return;
  }

  if (val.length < 6) {
    this.__setFieldState(field, false);
    this.__setHint("create-password-hint", "Too short (min 6 characters)", "error");
  } else {
    this.__setFieldState(field, true);
    this.__setHint("create-password-hint", "", "");
  }

}

CreateAccountModal.prototype.__isValidSubmission = function(options) {

  /*
   * Function CreateAccountModal.__isValidSubmission
   * Returns true if the submission is valid
   */

  document.getElementById("create-username").style.border = null;
  document.getElementById("create-password").style.border = null;
  document.getElementById("create-name").style.border = null;
  document.getElementById("create-sex").style.border = null;

  let errorEl = document.getElementById("create-error");
  if (errorEl) { errorEl.style.display = "none"; errorEl.textContent = ""; }

  function showError(fieldId, msg) {
    document.getElementById(fieldId).style.border = "1px solid red";
    if (errorEl) { errorEl.textContent = msg; errorEl.style.display = "block"; }
  }

  if(options.name === "") {
    showError("create-name", "Please enter a character name.");
    return false;
  }

  if(options.sex !== "male" && options.sex !== "female") {
    showError("create-sex", "Please choose a sex.");
    return false;
  }

  if(options.account === "") {
    showError("create-username", "Please enter an account name.");
    return false;
  }

  if(options.password === "") {
    showError("create-password", "Please enter a password.");
    return false;
  }

  if(options.name.length < 3 || options.name.length > 20) {
    showError("create-name", "Character name must be 3-20 characters.");
    return false;
  }

  if(!/^[a-z]+(?: [a-z]+)*$/.test(options.name)) {
    showError("create-name", "Only lowercase letters with single spaces.");
    return false;
  }

  if(options.account.length < 3 || options.account.length > 20) {
    showError("create-username", "Account name must be 3-20 characters.");
    return false;
  }

  if(options.password.length < 6 || options.password.length > 32) {
    showError("create-password", "Password must be 6-32 characters.");
    return false;
  }

  return true;

}

CreateAccountModal.prototype.handleOpen = function() {

  /*
   * Function CreateAccountModal.handleOpen
   * Resets the confirm button state when the modal is opened
   */

  let confirmBtn = this.element.querySelector("button[action='confirm']");
  if (confirmBtn) {
    confirmBtn.disabled = false;
    confirmBtn.textContent = "Create Account";
  }

}

CreateAccountModal.prototype.handleCancel = function() {

  /*
   * Function CreateAccountModal.handleCancel
   * Handles the Cancel button click — closes modal and returns to login form
   */

  gameClient.interface.modalManager.close();
  gameClient.interface.modalManager.open("floater-enter");

  return false;

}

CreateAccountModal.prototype.handleConfirm = function() {

  /*
   * Function CreateAccountModal.handleConfirm
   * Validates and submits account creation, then auto-logs in on success
   */

  let referralVal = document.getElementById("create-referral");
  let options = new Object({
    "account": document.getElementById("create-username").value.trim(),
    "password": document.getElementById("create-password").value,
    "name": document.getElementById("create-name").value.toLowerCase().trim(),
    "sex": document.getElementById("create-sex").value,
    "referral": referralVal ? referralVal.value.trim().toUpperCase() : ""
  });

  if(!this.__isValidSubmission(options)) {
    return false;
  }

  // Show loading state on the confirm button
  let confirmBtn = this.element.querySelector("button[action='confirm']");
  if (confirmBtn) {
    confirmBtn.disabled = true;
    confirmBtn.textContent = "Creating Account...";
  }

  // Store credentials for auto-login
  this.__pendingAccount = options.account;
  this.__pendingPassword = options.password;

  gameClient.networkManager.createAccount(options);
  return false;

}


