const ScreenElement = function (id) {

  /*
   * Class ScreenElement
   * Base class for DOM elements on the game screen
   *
   * API:
   *
   * ScreenElement.remove() - removes the screen element DOM
   * ScreenElement.hide() - hides the screen element DOM
   * ScreenElement.show() - shows the screen element DOM
   *
   */

  // Specific classes implement and create the element
  this.element = document.getElementById(id).cloneNode(true);

  // Show the element when it is spawned
  this.show();

}

ScreenElement.prototype.remove = function () {

  /*
   * Function ScreenElement.remove
   * Removes the element from the DOM
   */

  // Force hidden before removal to invalidate iOS WebKit compositor cache
  this.element.style.display = "none";
  this.element.remove();

}

ScreenElement.prototype.hide = function () {

  /*
   * Function ScreenElement.hide
   * Hides the element from the game screen
   */

  this.element.style.display = "none";

}

ScreenElement.prototype.show = function () {

  /*
   * Function ScreenElement.show
   * Shows the element on the game screen
   */

  this.element.style.display = "block";

}

ScreenElement.prototype.__getElementWidth = function () {

  /*
   * Function ScreenElement.__getElementWidth
   * Cached offsetWidth read. Each forced layout costs ~50-150 µs;
   * with 30 visible nameplates, the per-frame cost was ~228 ms total
   * over an 18 s trace. Element width only changes when the rendered
   * content does (name, skull/shield/NPC icon flips), so we cache
   * after first read and let mutators call __invalidateDimensions.
   *
   * A zero result means the element isn't fully laid out yet (parent
   * still hidden during login transition, font not loaded, etc.) —
   * never cache that, or the nameplate stays mis-centered forever
   * (player report 2026-05-05: HP/mana/name floating off the player).
   */

  if (!this.__cachedOffsetWidth) {
    let w = this.element.offsetWidth;
    if (w > 0) {
      this.__cachedOffsetWidth = w;
    }
    return w;
  }
  return this.__cachedOffsetWidth;

}

ScreenElement.prototype.__getElementHeight = function () {

  if (!this.__cachedOffsetHeight) {
    let h = this.element.offsetHeight;
    if (h > 0) {
      this.__cachedOffsetHeight = h;
    }
    return h;
  }
  return this.__cachedOffsetHeight;

}

ScreenElement.prototype.__invalidateDimensions = function () {

  /*
   * Function ScreenElement.__invalidateDimensions
   * Drops cached width/height — call from any setter that mutates the
   * rendered element content (setName, setSkull, setShield, etc.).
   */

  this.__cachedOffsetWidth = undefined;
  this.__cachedOffsetHeight = undefined;

}

ScreenElement.prototype.__updateTextPosition = function (offset) {

  /*
   * Function ScreenElement.__updateTextPosition
   * Actually applies the transform.
   *
   * Per-nameplate hot path. Without caching, this calls
   * canvas.getBoundingClientRect() + parentElement.getBoundingClientRect()
   * — two synchronous layout-forcing reads per element. With 30 visible
   * creatures that's 60 forced layouts per frame from this function alone.
   * Both rects are identical across every call in the same frame (the
   * canvas and the wrapper parent don't move), so we cache them on the
   * renderer keyed by the GameLoop frame counter.
   */

  let frame = (gameClient.gameLoop && gameClient.gameLoop.__frame) || 0;
  let cache = gameClient.renderer.__rectCache;
  if (!cache || cache.frame !== frame) {
    cache = {
      frame: frame,
      canvasRect: gameClient.renderer.screen.canvas.getBoundingClientRect(),
      parentRect: this.element.parentElement
        ? this.element.parentElement.getBoundingClientRect()
        : null
    };
    gameClient.renderer.__rectCache = cache;
  }
  let rect = cache.canvasRect;

  // Account for canvas offset within the text-wrapper parent.
  // On desktop/phone the canvas fills the wrapper so offset is (0,0).
  // On tablet the canvas is centered via flexbox, creating an offset.
  let canvasLeft = 0;
  let canvasTop = 0;

  if (cache.parentRect) {
    canvasLeft = rect.left - cache.parentRect.left;
    canvasTop = rect.top - cache.parentRect.top;
  }

  // Clamp the position of the text box to within the game screen
  let left = (canvasLeft + offset.left).clamp(canvasLeft, canvasLeft + rect.width - this.__getElementWidth());
  let top = (canvasTop + offset.top).clamp(canvasTop, canvasTop + rect.height - this.__getElementHeight());

  // Position using left/top for reliable absolute positioning
  this.element.style.left = left + "px";
  this.element.style.top = top + "px";

  // Show the element immediately (no setTimeout — element must already be visible
  // before __getAbsoluteOffset reads offsetWidth/offsetHeight for correct centering)
  this.show();

}

ScreenElement.prototype.__getAbsoluteOffset = function (position) {

  /*
   * Function ScreenElement.__getAbsoluteOffset
   * Returns the offset of the screen element based on its properties and the screen size
   */

  // Determine the fraction based on the size of the screen
  let scale = gameClient.interface.getSpriteScalingVector();

  // Calculate the text position in canvas coordinates and center them
  // Use separate X and Y scales to handle non-uniform stretching on mobile
  let left = (scale.x * position.x) - (0.5 * this.__getElementWidth());
  let top = (scale.y * position.y) - (0.5 * this.__getElementHeight());

  // Return the new offsets
  return { left, top }

}

/* ===== FILE: https://minibia.com/src/ui/settings.js?v=1778114715327 ===== */

const Settings = function (element) {

  /*
   * Class Settings
   * Container for all the settings
   *
   * API:
   *
   * @Settings.isFilterEnabled() - returns true if the filter setting is enabled
   * @Settings.getFilter() - returns the selected filter
   * @Settings.isWeatherEnabled() - returns true when the weather is enabled
   * @Settings.isLightingEnabled() - returns true when the lighting is enabled
   * @Settings.isSoundEnabled() - returns true when sound is enabled
   * @Settings.saveState() - Saves state to local storage
   * @Settings.clear() - Clears state from local storage
   * @Settings.showScreenText() - Enables whether to show text on the screen
   *
   */

  // Set the volume slider callback functions
  document.getElementById("music-slider").oninput = this.setMusicVolume;
  document.getElementById("music-slider-value").innerHTML = document.getElementById("music-slider").value + "%";
  document.getElementById("effects-slider").oninput = this.setEffectsVolume;
  document.getElementById("effects-slider-value").innerHTML = document.getElementById("effects-slider").value + "%";

  document.getElementById("anti-aliasing").addEventListener("change", this.__setAA);
  document.getElementById("show-performance").addEventListener("change", this.__togglePerformance);
  document.getElementById("display-mode").addEventListener("change", this.__setDisplayMode);
  document.getElementById("aspect-ratio-mode").addEventListener("change", this.__setAspectRatioMode);
  document.getElementById("movement-style").addEventListener("change", this.__setMovementStyle);
  document.getElementById("fps-limit").addEventListener("change", this.__setFPSLimit);

  // Clear the learned-word map used by the mobile word-suggestions strip.
  let clearWordsBtn = document.getElementById("clear-learned-words-btn");
  if (clearWordsBtn) {
    clearWordsBtn.addEventListener("click", this.__clearLearnedWords.bind(this));
  }

  // Open the /lootlist modal directly from settings (replaces the old
  // "Loot Rares" toggle — the explicit lootlist supersedes the catch-all).
  let lootlistBtn = document.getElementById("open-lootlist-btn");
  if (lootlistBtn) {
    lootlistBtn.addEventListener("click", function () {
      if (gameClient && gameClient.isConnected()) {
        gameClient.send(new ChannelMessagePacket(0x00, 0, "/lootlist"));
        // Close the settings modal so the lootlist modal can take focus
        gameClient.interface.modalManager.close();
      }
    });
  }

  // Open language-picker dialog for word suggestions (primary + secondary).
  let langBtn = document.getElementById("word-suggestions-languages-btn");
  if (langBtn) {
    langBtn.addEventListener("click", this.__openLanguageDialog.bind(this));
  }
  let langClose = document.getElementById("wsl-close");
  if (langClose) {
    langClose.addEventListener("click", this.__closeLanguageDialog.bind(this));
  }
  let langReset = document.getElementById("wsl-reset");
  if (langReset) {
    langReset.addEventListener("click", this.__resetLanguageDialog.bind(this));
  }
  let langPrimary = document.getElementById("wsl-primary");
  if (langPrimary) {
    langPrimary.addEventListener("change", this.__applyLanguageDialog.bind(this));
  }
  let langSecondary = document.getElementById("wsl-secondary");
  if (langSecondary) {
    langSecondary.addEventListener("change", this.__applyLanguageDialog.bind(this));
  }

  // Wire settings-modal tab strip. Mirrors the skill-window tab pattern:
  // click a tab → remove .active from all tabs+contents, add it to the
  // clicked tab and its matching [data-tab=...] content div.
  let settingsTabs = document.querySelectorAll("#settings-modal .settings-tab");
  let settingsTabContents = document.querySelectorAll("#settings-modal .settings-tab-content");
  settingsTabs.forEach(function (tab) {
    tab.addEventListener("click", function () {
      let target = tab.getAttribute("data-tab");
      settingsTabs.forEach(function (t) { t.classList.remove("active"); });
      settingsTabContents.forEach(function (c) { c.classList.remove("active"); });
      tab.classList.add("active");
      let content = document.querySelector("#settings-modal .settings-tab-content[data-tab=\"" + target + "\"]");
      if (content) content.classList.add("active");
    });
  });

  // Direct close handler on the settings-modal ✕ button. Belt-and-suspenders
  // backup to the generic Modal `button[action]` handler — added after
  // reports the ✕ wasn't closing the modal once the flex-column layout and
  // tab strip were introduced above the body.
  let settingsClose = document.querySelector("#settings-modal > .close-button-transparent");
  if (settingsClose) {
    settingsClose.addEventListener("click", function (event) {
      event.stopPropagation();
      if (window.gameClient && gameClient.interface && gameClient.interface.modalManager) {
        gameClient.interface.modalManager.close();
      }
    });
  }

  this.__init();

  // Apply state to the DOM to keep it in sync
  Object.keys(this.__state).forEach(this.__applyState.bind(this));

  // Reflect anti-DC override on the Sounds label after initial apply
  this.__updateSoundsAntiDcNote();

}

Settings.prototype.__updateSoundsAntiDcNote = function () {

  /*
   * Function Settings.__updateSoundsAntiDcNote
   * Shows a small italic note next to the "Sounds" toggle when the
   * Anti Connection Loss setting is enabled — clarifies that a faint
   * keep-alive loop will play even when the player has Sounds turned
   * off (the keep-alive bypasses master volume to keep the mobile
   * tab alive).
   */

  let note = document.getElementById("sounds-anti-dc-note");
  if (!note) return;
  let on = this.__state["anti-connection-loss"] === true;
  note.style.display = on ? "" : "none";

}

Settings.prototype.__setAA = function () {

  if (this.checked) {
    gameClient.renderer.screen.canvas.style.imageRendering = "auto";
  } else {
    gameClient.renderer.screen.canvas.style.imageRendering = "pixelated";
  }

}

Settings.prototype.__togglePerformance = function () {

  /*
   * Function Settings.__togglePerformance
   * Toggles the performance statistics display
   */

  gameClient.renderer.debugger.toggleStatistics();

}

Settings.prototype.__setFPSLimit = function () {

  /*
   * Function Settings.__setFPSLimit
   * Sets the FPS limit from the dropdown and persists to localStorage
   */

  let limit = parseInt(this.value);
  gameClient.gameLoop.setFPSLimit(limit);
  gameClient.interface.settings.__state["fps-limit"] = this.value;
  gameClient.interface.settings.saveState();

}

Settings.prototype.__setDisplayMode = function () {

  /*
   * Function Settings.__setDisplayMode
   * Applies the display mode override (auto, desktop, mobile)
   * Reloads the page because __initialize() binds many event listeners
   * and DOM state that cannot be cleanly reversed by __cleanup()
   */

  var newValue = this.value;
  var oldValue = gameClient.interface.settings.__state["display-mode"];

  if (newValue === oldValue) return;

  if (!confirm("Reload required. You will be disconnected briefly. Continue?")) {
    this.value = oldValue;
    return;
  }

  gameClient.interface.settings.__state["display-mode"] = newValue;
  gameClient.interface.settings.saveState();
  location.reload();

}

Settings.prototype.__setAspectRatioMode = function () {

  /*
   * Function Settings.__setAspectRatioMode
   * Toggles between original aspect ratio and stretch-to-fill canvas modes
   */

  if (this.value === "stretch") {
    document.body.classList.add("canvas-stretch");
  } else {
    document.body.classList.remove("canvas-stretch");
  }

  // Recalculate canvas scale and wrapper dimensions for the new mode
  if (gameClient.renderer) {
    gameClient.interface.handleResize();
  }

}

Settings.prototype.__setMovementStyle = function () {

  /*
   * Function Settings.__setMovementStyle
   * Toggles between analog stick and d-pad movement on mobile
   */

  if (gameClient.touch) {
    gameClient.touch.setMovementStyle(this.value);
  }

}

Settings.prototype.getDisplayMode = function () {

  /*
   * Function Settings.getDisplayMode
   * Returns the current display mode setting
   */

  return this.__state["display-mode"] || "auto";

}

Settings.prototype.setMusicVolume = function () {

  /*
   * Function Settings.setMusicVolume
   * Sets the music (ambient) volume
   */

  gameClient.interface.soundManager.setMusicVolume(Number(this.value) / 100);
  document.getElementById("music-slider-value").innerHTML = Number(this.value) + "%";

}

Settings.prototype.setEffectsVolume = function () {

  /*
   * Function Settings.setEffectsVolume
   * Sets the effects (weather/thunder) volume
   */

  gameClient.interface.soundManager.setEffectsVolume(Number(this.value) / 100);
  document.getElementById("effects-slider-value").innerHTML = Number(this.value) + "%";

}

Settings.prototype.clear = function () {

  /*
   * Class Settings.clear
   * Clears local storage from the settings
   */

  localStorage.removeItem("settings");

}

Settings.prototype.isSoundEnabled = function () {

  /*
   * Class Settings.isSoundEnabled
   * Returns true if sound is enabled
   */

  return this.__state["enable-sound"];

}

Settings.prototype.isClassicControlEnabled = function () {

  /*
   * Function Settings.isClassicControlEnabled
   * Returns true if classic mouse control mode is enabled
   * Classic: right-click directly opens/uses containers
   * Regular: right-click opens context menu
   */

  return this.__state["mouse-control-mode"] === "classic";

}

Settings.prototype.is12HourClock = function () {

  /*
   * Function Settings.is12HourClock
   * Returns true if the clock should display in 12-hour AM/PM format
   */

  return this.__state["clock-format"] === "12h";

}

Settings.prototype.isTapToWalkEnabled = function () {

  /*
   * Function Settings.isTapToWalkEnabled
   * Returns true if tap-to-walk is enabled on mobile
   */

  return this.__state["tap-to-walk"];

}

Settings.prototype.isExtraHotbarEnabled = function () {

  /*
   * Function Settings.isExtraHotbarEnabled
   * Returns true if the extra mobile hotbar is enabled
   */

  return this.__state["extra-hotbar"];

}

Settings.prototype.isAntiConnectionLossEnabled = function () {

  /*
   * Function Settings.isAntiConnectionLossEnabled
   * Returns true if the anti connection loss setting is enabled
   */

  return this.__state["anti-connection-loss"];

}

Settings.prototype.isChatAlwaysUnlocked = function () {

  /*
   * Function Settings.isChatAlwaysUnlocked
   * Returns true if chat should stay permanently unlocked (WASD types in chat)
   */

  return this.__state["chat-always-unlocked"];

}

Settings.prototype.isSmartWalkingEnabled = function () {

  /*
   * Function Settings.isSmartWalkingEnabled
   * Returns true if smart walking is enabled (two arrow keys = diagonal)
   */

  return this.__state["smart-walking"];

}

