  let primary = document.getElementById("wsl-primary");
  let secondary = document.getElementById("wsl-secondary");
  if (!primary || !secondary) return;

  let p = primary.value;
  let s = secondary.value;
  if (s === p) s = "none"; // primary and secondary cannot match

  this.__state["word-suggestions-primary"] = p;
  this.__state["word-suggestions-secondary"] = s;

  // Mirror into the hidden selects so __getCleanState / __applyState stay in sync
  let hiddenP = document.getElementById("word-suggestions-primary");
  let hiddenS = document.getElementById("word-suggestions-secondary");
  if (hiddenP) hiddenP.value = p;
  if (hiddenS) hiddenS.value = s;

  this.saveState();

  let kb = gameClient && gameClient.touch && gameClient.touch.mobileChat
    ? gameClient.touch.mobileChat.__keyboard : null;
