const WindowQuestLog = function (id) {

  /*
   * Class WindowQuestLog
   * Container for the Quest Log window with Achievements and Quests tabs
   */

  Modal.call(this, id);

  this.body = this.element.querySelector(".modal-body");

  this.body.innerHTML = `
    <div class="quest-log-window">
      <div class="quest-log-tabs">
        <div class="quest-log-tab active" data-tab="achievements">Achievements</div>
        <div class="quest-log-tab" data-tab="quests">Quests</div>
      </div>
      <div style="display: flex; flex-direction: column; flex: 1; overflow: hidden;">
        <div class="quest-list-container" style="flex: 1;">
          <div class="quest-list" id="quest-log-list">
            <div class="empty-state">Loading...</div>
          </div>
        </div>
      </div>
      <div class="footer-panel">
        <div class="footer-left">
          <div class="tibia-checkbox-group">
            <label class="tibia-checkbox">
              <input type="checkbox" checked id="ach-show-completed"> Show completed
            </label>
          </div>
        </div>
        <div class="footer-right">
          <div class="tibia-btn-group">
            <button class="tibia-button" action="close">Close</button>
          </div>
        </div>
      </div>
    </div>
  `;

  this.listContainer = this.body.querySelector("#quest-log-list");
  this.activeTab = "achievements";

  // Tab switching
  let tabs = this.body.querySelectorAll(".quest-log-tab");
  for (let i = 0; i < tabs.length; i++) {
    tabs[i].onclick = this.__switchTab.bind(this, tabs[i]);
  }

  let closeBtn = this.body.querySelector('button[action="close"]');
  if (closeBtn) {
    closeBtn.onclick = function () { gameClient.interface.modalManager.close(); };
  }

  let showCompleted = this.body.querySelector("#ach-show-completed");
  if (showCompleted) {
    showCompleted.onchange = this.__renderActiveTab.bind(this);
  }

  this.currentAchievements = [];
  this.currentQuestChests = [];

}

WindowQuestLog.prototype = Object.create(Modal.prototype);
WindowQuestLog.prototype.constructor = WindowQuestLog;

WindowQuestLog.prototype.handleOpen = function () {

  /*
   * Function WindowQuestLog.handleOpen
   * Requests achievement + quest data from server when opened
   */

  if (gameClient && gameClient.isConnected()) {
    gameClient.send(new QuestLogPacket(0));
  }

}

WindowQuestLog.prototype.__switchTab = function (tabElement) {

  /*
   * Function WindowQuestLog.__switchTab
   * Switches between Achievements and Quests tabs
   */

  let tabs = this.body.querySelectorAll(".quest-log-tab");
  for (let i = 0; i < tabs.length; i++) {
    tabs[i].classList.remove("active");
  }
  tabElement.classList.add("active");
  this.activeTab = tabElement.getAttribute("data-tab");
  this.__renderActiveTab();

}

WindowQuestLog.prototype.setQuests = function (achievements) {

  /*
   * Function WindowQuestLog.setQuests
   * Receives achievement data from server
   */

  this.currentAchievements = achievements;
  if (this.activeTab === "achievements") {
    this.__renderActiveTab();
  }

}

WindowQuestLog.prototype.setQuestChests = function (questChests) {

  /*
   * Function WindowQuestLog.setQuestChests
   * Receives quest chest data from server
   */

  this.currentQuestChests = questChests;
  if (this.activeTab === "quests") {
    this.__renderActiveTab();
  }

}

WindowQuestLog.prototype.__renderActiveTab = function () {

  /*
   * Function WindowQuestLog.__renderActiveTab
   * Renders the currently active tab content
   */

  if (this.activeTab === "achievements") {
    this.__renderAchievements();
  } else {
    this.__renderQuestChests();
  }

}

WindowQuestLog.prototype.__renderAchievements = function () {

  /*
   * Function WindowQuestLog.__renderAchievements
   * Renders the achievement list with optional completed filter
   */

  let achievements = this.currentAchievements;
  let showCompleted = this.body.querySelector("#ach-show-completed");
  let hideCompleted = showCompleted && !showCompleted.checked;

  this.listContainer.innerHTML = "";

  if (achievements.length === 0) {
    this.listContainer.innerHTML = '<div class="empty-state">No achievements yet.</div>';
    return;
  }

  let count = 0;

  achievements.forEach(function (a) {
    if (hideCompleted && a.completed) return;
    count++;

    let div = document.createElement("div");
    div.className = "quest-entry";
    if (a.completed) div.classList.add("completed");

    let checkSpan = document.createElement("span");
    checkSpan.className = "quest-check";
    div.appendChild(checkSpan);

    let nameSpan = document.createElement("span");
    nameSpan.className = "quest-name";
    nameSpan.innerText = a.name;
    div.appendChild(nameSpan);

    let progress = document.createElement("span");
    progress.style.cssText = "margin-left:auto;font-size:10px;opacity:0.7;white-space:nowrap;";
    progress.innerText = a.current + "/" + a.required;
    div.appendChild(progress);

    this.listContainer.appendChild(div);
  }.bind(this));

  if (count === 0) {
    this.listContainer.innerHTML = '<div class="empty-state">All achievements completed!</div>';
  }

}

WindowQuestLog.prototype.__renderQuestChests = function () {

  /*
   * Function WindowQuestLog.__renderQuestChests
   * Renders the quest chest completion list
   */

  let quests = this.currentQuestChests;
  let showCompleted = this.body.querySelector("#ach-show-completed");
  let hideCompleted = showCompleted && !showCompleted.checked;

  this.listContainer.innerHTML = "";

  if (quests.length === 0) {
    this.listContainer.innerHTML = '<div class="empty-state">No quests available.</div>';
    return;
  }

  let count = 0;
  let completed = 0;

  quests.forEach(function (q) {
    if (q.completed) completed++;
    if (hideCompleted && q.completed) return;
    count++;

    let div = document.createElement("div");
    div.className = "quest-entry";
    if (q.completed) div.classList.add("completed");

    let checkSpan = document.createElement("span");
    checkSpan.className = "quest-check";
    div.appendChild(checkSpan);

    let nameSpan = document.createElement("span");
    nameSpan.className = "quest-name";
    nameSpan.innerText = q.name;
    div.appendChild(nameSpan);

    let rewardSpan = document.createElement("span");
    rewardSpan.style.cssText = "margin-left:auto;font-size:10px;opacity:0.7;white-space:nowrap;max-width:200px;overflow:hidden;text-overflow:ellipsis;";
    rewardSpan.innerText = q.reward;
    rewardSpan.title = q.reward;
    div.appendChild(rewardSpan);

    this.listContainer.appendChild(div);
  }.bind(this));

  if (count === 0) {
    this.listContainer.innerHTML = '<div class="empty-state">All quests completed!</div>';
  }

}

