const CharacterMessage = function(message, type, name, color, loudness) {

  /*
   * Class CharacterMessage
   * Container for a message that belongs to a character
   */

  // Inherit from message
  Message.call(this, message);

  // Has a name and color
  this.name = name;
  this.type = type;
  this.color = gameClient.interface.getHexColor(color);
  // Loudness: 0=whisper, 1=say, 2=yell
  this.loudness = loudness !== undefined ? loudness : 1;

}

CharacterMessage.prototype = Object.create(Message.prototype);
CharacterMessage.prototype.constructor = CharacterMessage;

CharacterMessage.prototype.format = function() {

  /*
   * Function CharacterMessage.format
   * Implements the format API to format a message in a particular way
   */

  let verb = " says:";
  if (this.loudness === 0) verb = " whispers:";
  else if (this.loudness === 2) verb = " YELLS:";

  // Build the full line first (prefix + message), then wrap so every
  // visual row stays under ~80 chars regardless of how long the prefix
  // (timestamp + name + verb) eats. Two passes:
  //   1. Insert a space after every 70 unbroken non-space chars to
  //      defuse pathological tokens (URLs, glyph runs, malformed text).
  //   2. Insert a newline at the next space past every 80 chars so
  //      long NPC greets split across multiple rows instead of pushing
  //      the chat box past its container width.
  // CSS already has white-space: pre-wrap so the inserted \n renders.
  let line = "%s %s%s %s".format(this.__formatTime(), this.name, verb, this.message);
  return line
    .replace(/(\S{70})(?=\S)/g, "$1 ")
    .replace(/(.{80,}?)\s/g, "$1\n");

}

CharacterMessage.prototype.createNode = function() {

  /*
   * Function Message.createNode
   * Formats the internal messages to the DOM
   */

  // Format the time the message was sent
  let span = document.createElement("span");
  span.className = "chat-message";
  span.style.color = this.color;

  // Call to format the message string
  span.innerHTML = this.format();

  // Always set the speaker name on the span so right-click → context
  // menu works for any character message (player AND NPC). The
  // `type === 0` gate previously restricted this to private channels
  // and silently broke "copy message" on regular say/whisper/yell.
  // MessageMenu.open hides irrelevant buttons (Message/Whisper/Add
  // Friend) when the right-clicked entry isn't a real player.
  span.setAttribute("name", this.name);

  return span;

}


